-- Poems batch 101
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('664e798b-aa53-48d2-9119-c8454fbed840','昌齡和詩以不得志於賢關有欲退隠之語復用前韻勉其涵養俟時未可真作休休計也','王十朋','宋','宋诗','song-poetry','','[]','出門休歎知己稀，開卷攬取前人奇。',64,'全唐诗/poet.song.118000.json','["出門休歎知己稀，開卷攬取前人奇。", "西園松菊聊笑傲，未可遽賦休休詩。", "涵養胸襟容萬斛，仰視青天紙盈幅。", "行看富貴來逼人，江左家聲子當續。"]'),
('6123b839-def6-4095-9f41-f8c03d940048','昌齡頻開尊再用前韻','王十朋','宋','宋诗','song-poetry','','[]','人生常患如意稀，利名擾擾何足奇。',64,'全唐诗/poet.song.118000.json','["人生常患如意稀，利名擾擾何足奇。", "誰能如我惠連弟，有園有酒兼能詩。", "種秫西疇都幾斛，時見小童馳片幅。", "風軒洒掃又相呼，適有嘉魚饋羊續。"]'),
('7d9bcf4f-b1dd-43a9-beb7-201d49520fcb','用前韻題東園','王十朋','宋','宋诗','song-poetry','','[]','吾園小小遊人稀，吾腹便便空自奇。',64,'全唐诗/poet.song.118000.json','["吾園小小遊人稀，吾腹便便空自奇。", "徑草青青可煎飲，雨竹涓涓堪賦詩。", "鮮鮮菊滿東籬斛，揚揚蘭入騷人幅。", "牡丹芍藥紫薇梅，四時花卉開相續。"]'),
('c1d8544b-3e2c-4773-b775-0cbaceeed666','賈元識和詩酬以前韻','王十朋','宋','宋诗','song-poetry','','[]','河東丈人年及稀，精神矍鑠心瑰奇。',64,'全唐诗/poet.song.118000.json','["河東丈人年及稀，精神矍鑠心瑰奇。", "新來移居向山谷，一尊時得同論詩。", "酒量汪汪可勝斛，醉後揮毫動盈幅。", "新詩疏越似朱弦，不才何用煎膠續。"]'),
('c439cd9d-19a9-44a1-aade-5ec6d2227059','次韻昌齡西園即事','王十朋','宋','宋诗','song-poetry','','[]','世態蠅營已厭驅，小園初闢稱幽居。',64,'全唐诗/poet.song.118000.json','["世態蠅營已厭驅，小園初闢稱幽居。", "杯深轉覺利名薄，心靜更宜花木踈。", "窗几吟餘山色好，軒齋夢覺日華舒。", "尤憐不棄東園老，時復相從辨魯魚。"]'),
('4d31f4d8-b714-45a0-ac2f-4d5ff7025933','東園小閤丹粉一新昌齡有詩次韻','王十朋','宋','宋诗','song-poetry','','[]','小園小閤無奇新，但喜有酒堪娛賓。',128,'全唐诗/poet.song.118000.json','["小園小閤無奇新，但喜有酒堪娛賓。", "西疇種秫可自釀，不用勤買拋青春。", "月明星稀烏擇木，吾愛吾廬堪寓目。", "須知主父五鼎珍，不似王猷數竿竹。", "丈夫未遇當安貧，带經且作鋤園人。", "詩酒過從老兄弟，一笑可破雙眉顰。", "見說西園相繼闢，好將因果同栽植。", "子孫清白世相傳，莫同阮氏分南北。"]'),
('ae8e6a75-780f-4457-b6c4-cd750c411de0','夢齡得男老者喜甚湯餠會中出詩以賀','王十朋','宋','宋诗','song-poetry','','[]','梅溪佳氣夜葱葱，果得奇兒應夢熊。',64,'全唐诗/poet.song.118000.json','["梅溪佳氣夜葱葱，果得奇兒應夢熊。", "湯餠笑歡良不淺，桑弧時節稍相同。", "喜將老眼看猶子，首出新詩賀乃翁。", "從此吾門如謝傅，芝蘭玉樹滿庭中。"]'),
('a3b643fe-b674-4660-8aee-6dd7c1d2c1b7','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 小小園','王十朋','宋','宋诗','song-poetry','','[]','預作休休計，先開小小園。',24,'全唐诗/poet.song.118000.json','["預作休休計，先開小小園。", "杖藜成日涉，得趣與心論。"]'),
('0ef4c2bf-ae54-4982-b085-5f8f1f043007','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 便便閤','王十朋','宋','宋诗','song-poetry','','[]','一閤僅容膝，閉門塵慮捐。',24,'全唐诗/poet.song.118000.json','["一閤僅容膝，閉門塵慮捐。", "讀書心已懶，高卧腹便便。"]'),
('ff694f57-dc61-46fa-975e-c6896e70e79e','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 青青徑','王十朋','宋','宋诗','song-poetry','','[]','小徑循園闢，青青草色都。',24,'全唐诗/poet.song.118000.json','["小徑循園闢，青青草色都。", "主人猶未仕，時得理荒蕪。"]'),
('1bdef0c7-10c8-44cf-83c8-1ea979f42a10','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 娟娟林','王十朋','宋','宋诗','song-poetry','','[]','遶舍種脩竹，清風長滿筵。',24,'全唐诗/poet.song.118000.json','["遶舍種脩竹，清風長滿筵。", "天姿本來凈，不雨亦娟娟。"]'),
('bb3c5c9a-6631-425c-84b3-21111ae2690c','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 揚揚畹','王十朋','宋','宋诗','song-poetry','','[]','九畹何人種，光風泛國香。',24,'全唐诗/poet.song.118000.json','["九畹何人種，光風泛國香。", "林間今幾許，鼻觀日揚揚。"]'),
('54052bf0-d679-412a-a555-aa0229af50a1','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 鮮鮮砌','王十朋','宋','宋诗','song-poetry','','[]','吾圃豈不富，黄金無數錢。',24,'全唐诗/poet.song.118000.json','["吾圃豈不富，黄金無數錢。", "誰云何用好，霜裏白鮮鮮。"]'),
('6773f1e3-54e1-475f-b032-da11ae860567','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 牡丹','王十朋','宋','宋诗','song-poetry','','[]','人道此花貴，豈宜顔巷栽。',24,'全唐诗/poet.song.118000.json','["人道此花貴，豈宜顔巷栽。", "春風情不世，紅紫一般開。"]'),
('59cfbbf5-1310-41a0-aadd-715d419c0cc6','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 芍藥','王十朋','宋','宋诗','song-poetry','','[]','十花稱近客，千葉重維揚。',24,'全唐诗/poet.song.118000.json','["十花稱近客，千葉重維揚。", "世上無姚魏，還他霸衆芳。"]'),
('9dc1cae0-6f5b-425f-bbbe-52367dc98b61','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 早梅','王十朋','宋','宋诗','song-poetry','','[]','北陸寒未半，南枝春已回。',24,'全唐诗/poet.song.118000.json','["北陸寒未半，南枝春已回。", "方於雪中種，便向雪中開。"]'),
('9d380be8-b9b4-4cfa-8f01-837b2092c54e','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 雙竹','王十朋','宋','宋诗','song-poetry','','[]','本是一根出，相期同化龍。',24,'全唐诗/poet.song.118000.json','["本是一根出，相期同化龍。", "慎毋輕剪伐，雲路定相從。"]'),
('5fb7e9e5-0697-4c06-aa48-278b2aaf913c','予有書閤僅容膝東有隙地初甚荒蕪偶於暇日理成小園徑以通之杖藜日涉於其間幾欲成趣然花木蕭疏不足播之吟詠謾賦十一小詩以記園中之僅有者時甲戌仲冬也 紫微花','王十朋','宋','宋诗','song-poetry','','[]','盛夏綠遮眼，茲花紅滿堂。',24,'全唐诗/poet.song.118000.json','["盛夏綠遮眼，茲花紅滿堂。", "自慚終日對，豈是紫微郎。"]'),
('de0ca7bb-0cf1-44a0-939e-99bdb75b9da2','梅花次賈元識韻','王十朋','宋','宋诗','song-poetry','','[]','南枝昨夜暖先回，壓盡群芳獨自開。',64,'全唐诗/poet.song.118000.json','["南枝昨夜暖先回，壓盡群芳獨自開。", "仙客風中飄素袂，玉妃月下試新裁。", "未憑驛使殷勤寄，首辱新詩特地來。", "明日雪晴須共賞，爲花拚却飲千杯。"]'),
('566dcd9f-b60f-44a3-9a9b-3d182c80af32','歲暮雨雪連作稍阻會集賈元識有詩次韻','王十朋','宋','宋诗','song-poetry','','[]','自從春色上孤根，淫雨經時步不前。',64,'全唐诗/poet.song.118000.json','["自從春色上孤根，淫雨經時步不前。", "愛日未能供宿潤，愁雲依舊蔽青天。", "溪山咫尺成千里，棋酒因循又一年。", "今夕籃輿定相過，尊前行樂興無邊。"]'),
('e23b5bc9-5e7e-4d69-9e55-c2b2239b7ff7','萬府君挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','東平隠君子，當以古人看。',48,'全唐诗/poet.song.118000.json','["東平隠君子，當以古人看。", "孝却豺群易，恩全雁序難。", "人如心畫正，度勝酒腸寬。", "粲粲三株樹，門闌已壯觀。"]'),
('72dd2a04-f4ad-4cf0-b136-5b9800164ecc','萬府君挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','老成嗟不見，里巷尚能談。',48,'全唐诗/poet.song.118000.json','["老成嗟不見，里巷尚能談。", "衣解因周急，簪還務激貪。", "蹶蹄心不慍，折翼淚常含。", "瞑目應無恨，聲名與佛參。"]'),
('c07b7091-28e3-4c23-94b7-2ead0ab8fcf3','萬府君挽詞  其三','王十朋','宋','宋诗','song-poetry','','[]','吾母昔逃難，携孥依舅船。',48,'全唐诗/poet.song.118000.json','["吾母昔逃難，携孥依舅船。", "態多朝暮警，恩獨始終全。", "濫與高門出，尤蒙長者憐。", "未能成宅相，徒有淚如泉。"]'),
('9505b1d8-9f42-4810-85f5-0f74a99b8ca7','林府君挽詞','王十朋','宋','宋诗','song-poetry','','[]','我昔遊庠序，夤緣識令孫。',48,'全唐诗/poet.song.118000.json','["我昔遊庠序，夤緣識令孫。", "雅知苗裔遠，更喜典刑存。", "俗子猶遷善，偷兒最感恩。", "佳城明日閉，墮淚滿江村。"]'),
('237200bd-b56d-4e4b-ae1c-c262dc81ad3a','表兄璐挺二道人以山茶一根見贈植于便便閤前每黑甜餘開窗寓目茗碗不捧精神自清因成小詩','王十朋','宋','宋诗','song-poetry','','[]','一枕春眠到日斜，夢回喜對小山茶。',32,'全唐诗/poet.song.118000.json','["一枕春眠到日斜，夢回喜對小山茶。", "道人贈我歲寒種，不是尋常兒女花。"]'),
('29651ca5-c1b2-41a4-b478-a1c94583fcdb','又覓沒利花','王十朋','宋','宋诗','song-poetry','','[]','沒利名嘉花亦嘉，遠從佛國到中華。',32,'全唐诗/poet.song.118000.json','["沒利名嘉花亦嘉，遠從佛國到中華。", "老來耻逐蠅頭利，故向樿房覓此花。"]'),
('ccb19838-4e1b-4174-b063-821428eee6bf','二道人以抹利及東山蘭爲贈再成一章','王十朋','宋','宋诗','song-poetry','','[]','西域名花最孤潔，東山芳友更清幽。',64,'全唐诗/poet.song.118000.json','["西域名花最孤潔，東山芳友更清幽。", "遠煩丈室維摩詰，分韻小園王子猷。", "入鼻頓除浮利盡，同心端與國香侔。", "從今日講通家好，詩往花來卒未休。"]'),
('2b13af7e-0894-4c11-80b3-159dfe79d02b','覓海棠','王十朋','宋','宋诗','song-poetry','','[]','好事高人重海棠，兩株分植舫齋旁。',64,'全唐诗/poet.song.118000.json','["好事高人重海棠，兩株分植舫齋旁。", "恰當燕子來時放，更向禪房深處芳。", "道眼想應憐不俗，癡人何苦恨無香。", "梅溪野叟曾經眼，欲覓一根栽草堂。"]'),
('8793a3c5-b9f2-4b56-982a-daee618f29c4','郁師贈海棠酬以前韻','王十朋','宋','宋诗','song-poetry','','[]','珍重高人贈海棠，殷勤封植弊廬旁。',64,'全唐诗/poet.song.118000.json','["珍重高人贈海棠，殷勤封植弊廬旁。", "固宜花裏稱名友，已向園中壓衆芳。", "萬樹總含兒女態，一根獨带佛爐香。", "杜陵應恨未曾識，空向成都結草堂。"]'),
('bc75ed97-9ddc-446e-9a3f-6a7a5499eadb','札上人許贈山丹花且云此花三月盡開俟蕊成移去至上巳日以詩索之','王十朋','宋','宋诗','song-poetry','','[]','人間花木眼曾經，未識茲花狀與名。',64,'全唐诗/poet.song.118000.json','["人間花木眼曾經，未識茲花狀與名。", "丹却青山暮春色，續他紅樹墮時英。", "梅溪野老栽成癖，蓮社高人諾不輕。", "小小園林綠將暗，早移芳蘂看敷榮。"]'),
('64bae6eb-9cf3-454e-899c-c8466a7e1c58','表弟津上人有瑞香抹利戲覓之','王十朋','宋','宋诗','song-poetry','','[]','瑞香早入江南夢，抹利來從毘舍園。',32,'全唐诗/poet.song.118000.json','["瑞香早入江南夢，抹利來從毘舍園。", "久與道人同寂寞，不如來薦孔融尊。"]'),
('33e2de27-fff6-47af-a284-50b3befc3455','覓季仲權碧桃','王十朋','宋','宋诗','song-poetry','','[]','紅雨紛紛空自繁，碧雲一朵勝桃源。',32,'全唐诗/poet.song.118000.json','["紅雨紛紛空自繁，碧雲一朵勝桃源。", "君家獨有神仙種，分我閙花深處根。"]'),
('34fb73bb-e4bb-43ca-9fbe-1dc1168d7e24','覓季仲達酴醾','王十朋','宋','宋诗','song-poetry','','[]','名園羽蓋謾童童，不似青虬出甕中。',32,'全唐诗/poet.song.118000.json','["名園羽蓋謾童童，不似青虬出甕中。", "好事主人仍好施，定移韻友乞山翁。"]'),
('1748f05f-6c1e-4044-ab5a-cb22242d0d9e','和寶印叔送春二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','潛澗園林幽更奇，送春歸去有新詩。',32,'全唐诗/poet.song.118000.json','["潛澗園林幽更奇，送春歸去有新詩。", "風光流轉身長健，又見明年花滿枝。"]'),
('e377f236-711d-4f7a-b08f-51df12c3ef3e','和寶印叔送春二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','青春不覺去堂堂，把酒誰分此日光。',32,'全唐诗/poet.song.118000.json','["青春不覺去堂堂，把酒誰分此日光。", "偶讀高人送春句，味回齒頰有餘香。"]'),
('18433e4e-99bc-47d9-ab7e-0d72239c3a50','族兄文通贈山茶','王十朋','宋','宋诗','song-poetry','','[]','野性無端喜種花，吾兄得得贈山茶。',64,'全唐诗/poet.song.118000.json','["野性無端喜種花，吾兄得得贈山茶。", "鶑聲老後移雖晚，鶴頂丹時看始嘉。", "雨葉鱗鱗成小蓋，春枝艷艷首羣葩。", "自慚欲報無瓊玖，來徃同看本一家。"]'),
('1e747fcb-1498-4194-bb7f-06c0b36ffc93','兄弟鄰里日講率會因書一絕且戒其早納租稅也','王十朋','宋','宋诗','song-poetry','','[]','屏跡山林頗自安，里閭率會有餘歡。',32,'全唐诗/poet.song.118000.json','["屏跡山林頗自安，里閭率會有餘歡。", "但須及早輸租稅，不用低顔見長官。"]'),
('597cd810-21a6-4585-9cf6-05083317e0af','萬府君挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','前輩風流久，之人尚典刑。',48,'全唐诗/poet.song.118000.json','["前輩風流久，之人尚典刑。", "抱才雖汩沒，種德自芬馨。", "養浩眠龍穴，流光屬鯉庭。", "鄉評推燕竇，所欠獨年齡。"]'),
('b5166032-ed1d-410e-ac6f-74ca895ab29c','萬府君挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','太學稱多士，奇兒占上游。',48,'全唐诗/poet.song.118000.json','["太學稱多士，奇兒占上游。", "賢書連得雋，舍選復居優。", "善教由狐突，興家出萬脩。", "板輿游未遂，風樹已蕭颼。"]'),
('38fcde97-4736-48d4-8b7e-7c5fa0657fe4','萬府君挽詞  其三','王十朋','宋','宋诗','song-poetry','','[]','屈指吾鄉黨，如公今幾何。',48,'全唐诗/poet.song.118000.json','["屈指吾鄉黨，如公今幾何。", "門猶畢萬大，男類陸終多。", "壯志埋蒿里，幽光發薤歌。", "河梁嗟未就，遺恨滿滄波。"]'),
('c0165992-a46d-451a-a06c-4bb0d1f600da','張廷直挽詞','王十朋','宋','宋诗','song-poetry','','[]','意氣軒軒蓋一時，林頭周易造深幾。',64,'全唐诗/poet.song.118000.json','["意氣軒軒蓋一時，林頭周易造深幾。", "芹芳泮水聲蜚早，花滿河陽迹到稀。", "方外客携因果去，道旁人汲義泉歸。", "柳川池館規模壯，一夕花妖世已非。"]'),
('dddb49f5-1f38-400d-ae97-47f8a0c7a35b','左原紀異','王十朋','宋','宋诗','song-poetry','','[]','君不見溫公年方髫齔時，奮然擊甕活小兒。',378,'全唐诗/poet.song.118000.json','["君不見溫公年方髫齔時，奮然擊甕活小兒。", "至今遺事在圖畫，活人手段良可奇。", "又不見耿恭昔年困疏勒，孤城鑿井踰千尺。", "整衣一拜精誠通，俄頃枯泉飛爲液。", "樂清有地名左原，地幽井古知幾年。", "一朝陷溺誰氏子，萬石壓腦沉黄泉。", "路隔幽冥生望絕，三宿沉魂豈能活。", "鬼神莫救功莫施，天遣仁人爲之出。", "彩棒來臨驅五丁，抉石求屍俄有聲。", "頭顱半露語未辯，人疑鬼物相視驚。", "拯溺辛勤功未果，土圮石欹紛欲墮。", "爭言陷者不復生，救者徒遭頹壓禍。", "梅仙惻然臨井旁，焚香再拜祈彼蒼。", "散金募衆蹈死救，手植板幹加隄防。", "土石相銜危不倒，韲粉餘生僅能保。", "須臾奪命鬼窟中，萬口讙呼喜填道。", "翕然輿論咸奇公，異事行將達帝聰。", "感物誠居耿恭上，活人手與溫公同。", "况公才學俱超絕，吏隠那能久淹屈。", "使君前日飛鶚章，蒞事詳明己廉潔。", "鯫生桑梓居此間，具書目見非妄傳。", "太史採詩儻見取，願付銀筆書青編。", "將見大書特書屢書不止此，史筆芬香此其始。"]'),
('b44c05a4-7f86-41b2-921f-e959575563de','法燈俊上人惠杜鵑花','王十朋','宋','宋诗','song-poetry','','[]','杜鵑嘉樹狀非常，久向緇林壓衆芳。',64,'全唐诗/poet.song.118000.json','["杜鵑嘉樹狀非常，久向緇林壓衆芳。", "春去尚疑啼蜀魄，客來還錯認丁香。", "高人好事栽蓮社，野叟移根植草堂。", "習氣未除端自笑，賞花銜惠意難忘。"]'),
('ae3aa220-6d23-40a4-b90b-1ea8b67de81c','法燈聞上人和杜鵑詩酬以前韻','王十朋','宋','宋诗','song-poetry','','[]','道眼相看頗異常，遥遥蓮社有遺芳。',64,'全唐诗/poet.song.118000.json','["道眼相看頗異常，遥遥蓮社有遺芳。", "兩篇詩好無蔬氣，四季花然带佛香。", "杖錫何時離竹徑，尋山莫惜訪槐堂。", "小園花疏煩題注，詩徃花來未可忘。"]'),
('40255855-6936-44b3-8333-bcb1673e27c3','孫先覺毋夫人正月四日生時年八十','王十朋','宋','宋诗','song-poetry','','[]','蓂開四莢瑞新春，瓦弄幽閨應此辰。',64,'全唐诗/poet.song.118000.json','["蓂開四莢瑞新春，瓦弄幽閨應此辰。", "蛇虺夢中祥女子，鳳凰占裏吉佳人。", "平生不負三從義，老去兼全五福身。", "他日奇兒亦黄髮，捧觴猶得壽慈親。"]'),
('7e9d2486-51d4-49fd-ae54-14bc57b3cb3c','明慶懺院上方地爽而幽蓋精藍之勝也予因會友託迹於其間一日探囊中得石刻詩一本乃王瞻叔國博先生題台人秀野堂也摹寫景物頗類於此因置之壁間意有感觸遂借其韻','王十朋','宋','宋诗','song-poetry','','[]','下帷精舍遠塵繁，境靜心清事不關。',64,'全唐诗/poet.song.118000.json','["下帷精舍遠塵繁，境靜心清事不關。", "案上忘機有黄卷，眼中得趣是青山。", "林泉欲共高僧老，事業未容吾輩閑。", "準擬他年掛冠後，飄然杖履白雲間。"]'),
('28bdc37b-4895-487c-be5d-fcc08137d01a','懺院種蘭次寶印叔韻  其一','王十朋','宋','宋诗','song-poetry','','[]','偶向緇林植子芳，光風入院泛幽香。',32,'全唐诗/poet.song.118000.json','["偶向緇林植子芳，光風入院泛幽香。", "他時倘免芟鋤患，餘馥猶堪供道場。"]'),
('a1b58894-870b-4f82-961d-3e2cf881ae59','懺院種蘭次寶印叔韻  其二','王十朋','宋','宋诗','song-poetry','','[]','不放凡花染道場，故栽芳友伴友郎。',32,'全唐诗/poet.song.118000.json','["不放凡花染道場，故栽芳友伴友郎。", "一盤喜遇高人賞，却勝家園十八香。"]'),
('08a48fd5-f2dd-4526-b7ed-9f6debd36204','次濟上人韻','王十朋','宋','宋诗','song-poetry','','[]','老來未厭短檠光，又集青衿就故鄉。',64,'全唐诗/poet.song.118000.json','["老來未厭短檠光，又集青衿就故鄉。", "却荷道人能具眼，不同時輩有他腸。", "心傳潛澗源流別，首出新詩意味長。", "我亦筆頭爲佛事，未應中國異西方。"]'),
('4275eef5-334e-4e7b-8794-a998be88f672','玄鳥至','王十朋','宋','宋诗','song-poetry','','[]','昆蟲方啟戶，玄鳥亦知辰。',72,'全唐诗/poet.song.118000.json','["昆蟲方啟戶，玄鳥亦知辰。", "去自盲風候，來逢化日春。", "深條烟雨濕，廣厦羽毛新。", "故壘尋遺迹，雕梁拂舊塵。", "早鶑宜結友，秋雁不同賓。", "嘉爾能知義，無忘舊主人。"]'),
('78053e47-b63d-4242-b1ba-f355c5ce93f7','陳希仲贈山茶','王十朋','宋','宋诗','song-poetry','','[]','都勝名花入小園，群芳無復敢爭妍。',64,'全唐诗/poet.song.118000.json','["都勝名花入小園，群芳無復敢爭妍。", "童童翠蓋藏春色，艷艷繁燈照雪天。", "青蘂似開吾輩眼，高標不染俗流錢。", "此花端有歲寒意，好賦甘棠蔽芾篇。"]'),
('d805e7e8-8a8c-4dc6-8bf4-1b3891d9d32c','酴醾次賈元節韻','王十朋','宋','宋诗','song-poetry','','[]','春山杜宇喚人歸，歸見酴醾滿架垂。',64,'全唐诗/poet.song.118000.json','["春山杜宇喚人歸，歸見酴醾滿架垂。", "葉底半開千顆白，鬢邊斜插一枝奇。", "園林綠樹成陰後，亭院青春欲老時。", "把酒對花歌數闋，濡毫更和鹿巖詩。"]'),
('f8e755e5-a4d8-4989-8257-7bf55cf463a7','覓海松贈僧希月','王十朋','宋','宋诗','song-poetry','','[]','海石真宜植海松，青青不改四時容。',32,'全唐诗/poet.song.118000.json','["海石真宜植海松，青青不改四時容。", "道人妙得栽培力，乞與書齋待化龍。"]'),
('3de7bd06-528c-4c7e-88a7-116aa099f4c5','浴佛無雨','王十朋','宋','宋诗','song-poetry','','[]','俗言浴佛天必雨，今年浴佛天愈晴。',112,'全唐诗/poet.song.118000.json','["俗言浴佛天必雨，今年浴佛天愈晴。", "招提鍾磬集梵侶，世尊塵埃思一清。", "紛然膜拜口誦偈，舉頭看天紅日明。", "或云天意與佛拗，不放雨師龍伯行。", "天雖不雨佛亦浴，誤此億萬蒼生情。", "廟堂何人職調燮，勸天與佛無使爭。", "沛然一雨四方足，億萬蒼生俱沐浴。"]'),
('8c641972-42eb-4acb-830c-7bfdd9fd24cb','喜雨用前韻','王十朋','宋','宋诗','song-poetry','','[]','去年春夏人苦雨，今年春夏人厭晴。',112,'全唐诗/poet.song.118000.json','["去年春夏人苦雨，今年春夏人厭晴。", "水枯秧老農務急，霈然膏澤來太清。", "小民易怨亦易喜，不知天意常分明。", "何須頻禱應上公，但起夏禹陳五行。", "五風十雨堯舜世，自古天意緣人情。", "今茲一雨荷帝力，龍神社鬼無妄爭。", "南畝有餘人意足，蠶已三眠更三浴。"]'),
('048e0605-e164-499b-ad1f-bf815d8612c9','雨止復用前韻','王十朋','宋','宋诗','song-poetry','','[]','水枯秧老農欲雨，麥黄桑綠蠶欲晴。',112,'全唐诗/poet.song.118000.json','["水枯秧老農欲雨，麥黄桑綠蠶欲晴。", "一朝大霈滿四澤，雲收霧掃天還清。", "曰暘曰雨豈人力，聖德仰荷吾君明。", "廟堂况無癡宰相，不怕泥濘妨牛行。", "布穀催耕最知務，鳴鳩呼婦殊有情。", "平原出水雲吐日，陰陽得所無戰爭。", "明日陽光照臨足，今日陽烏已先浴。"]'),
('2e783cbe-ce21-488e-b7ed-08ded47e9147','孟夏十有一日時雨初霽晨登高閣極目四望烟鎖日出氣象一新復用前韻','王十朋','宋','宋诗','song-poetry','','[]','蝶夢驚回聽殘雨，鳥聲喚起欣初晴。',112,'全唐诗/poet.song.118000.json','["蝶夢驚回聽殘雨，鳥聲喚起欣初晴。", "梵宮烟火带餘濕，黌舍几席生微清。", "披衣登閣忽四顧，頓覺遠目增雙明。", "樵漁欵乃霧中出，舟楫蕩漾田間行。", "清和節物滿眼界，柳垂暗綠花含情。", "窗明几凈日漸永，天開地廓陰不爭。", "俯視滄浪堪濯足，遥看扶桑觀日浴。"]'),
('456bbc8d-446f-4dc0-b5cd-c2a40b9ce1e0','再用前韻勉諸友','王十朋','宋','宋诗','song-poetry','','[]','蠶婦欲晴農欲雨，書生事業無雨晴。',112,'全唐诗/poet.song.118000.json','["蠶婦欲晴農欲雨，書生事業無雨晴。", "况茲長日足可惜，薰風入戶精神清。", "虛窗文字遮眼暗，短檠燈火通宵明。", "紙爲良田力耕穫，一廛稼穡嗤許行。", "太山北斗仰韓子，千態萬狀窮周情。", "群居涵養務渾厚，藩籬剖破銷紛爭。", "拭目天衢驤驥足，下視汙池雀兒浴。"]'),
('6bedd46e-d8a6-4443-8a63-95bc8851cfe7','穎師贈榧栽','王十朋','宋','宋诗','song-poetry','','[]','自從兒時食火榧，思欲移根向鄉里。',96,'全唐诗/poet.song.118000.json','["自從兒時食火榧，思欲移根向鄉里。", "年來花木浪經心，品色徒多真戯耳。", "道人贈我方外根，不比尋常桃與李。", "枝柯宛類秦大夫，功效端如使君子。", "殷勤栽植同因果，衆目紛紛等奴婢。", "他年摘實薦新時，杖屨相從蓮社裏。"]'),
('d54c46b5-6079-49ae-b51c-7641d8cb4c1b','月上人以拳石植海松蒔菖陽於四際蒼姿秀色鍾清氣于几案間以爲梅溪之野人贈兼惠詩章因與酬唱凡四首  其一','王十朋','宋','宋诗','song-poetry','','[]','蒼蒼千尺大夫松，不似湖嵌植小蘢。',64,'全唐诗/poet.song.118000.json','["蒼蒼千尺大夫松，不似湖嵌植小蘢。", "枕水一拳形崒嵂，凌雲三幹色尨茸。", "王衡星化姿兼茂，蓮社詩高席可重。", "乞與書窗端不惡，蕭然如對德人容。"]'),
('c47b7980-b7b9-479a-9227-27702b75c4c9','月上人以拳石植海松蒔菖陽於四際蒼姿秀色鍾清氣于几案間以爲梅溪之野人贈兼惠詩章因與酬唱凡四首  其二','王十朋','宋','宋诗','song-poetry','','[]','處士何須種七松，賸栽海上綠髯龍。',64,'全唐诗/poet.song.118000.json','["處士何須種七松，賸栽海上綠髯龍。", "靈根頻灌蒼如玉，黛色初抽軟似茸。", "蘸水小山形鑿鑿，引年昌歜節重重。", "道人分得歲寒種，一洗梅溪憔悴容。"]'),
('67c4cb37-7e9c-4bd6-9356-d73d6bdca952','月上人以拳石植海松蒔菖陽於四際蒼姿秀色鍾清氣于几案間以爲梅溪之野人贈兼惠詩章因與酬唱凡四首  其三','王十朋','宋','宋诗','song-poetry','','[]','禪杖西游覩萬松，歸栽九節伴蒼龍。',64,'全唐诗/poet.song.118000.json','["禪杖西游覩萬松，歸栽九節伴蒼龍。", "何須偃蓋藏龜甲，自可延年勝鹿茸。", "贊老房幽看更好，晝公詩險和難重。", "爲師旦旦加澆濯，不遣塵埃上綠容。"]'),
('3898ae08-8d3c-4110-9075-fd50d6d75397','月上人以拳石植海松蒔菖陽於四際蒼姿秀色鍾清氣于几案間以爲梅溪之野人贈兼惠詩章因與酬唱凡四首  其四','王十朋','宋','宋诗','song-poetry','','[]','澗毛纖細蔭青松，會見成仙與化龍。',64,'全唐诗/poet.song.118000.json','["澗毛纖細蔭青松，會見成仙與化龍。", "孤嶼兩峯多臭味，一莖九節異香茸。", "羨師得句侵澄觀，顧我談經媿叔重。", "明日還家带滄海，園林小小可能容。"]'),
('908718b9-ec6a-45bd-960c-420dd8c7f256','懺院種紅蕉用寶印叔韻','王十朋','宋','宋诗','song-poetry','','[]','新植靈根續蕙蘭，緇林佳處占清閑。',64,'全唐诗/poet.song.118000.json','["新植靈根續蕙蘭，緇林佳處占清閑。", "深紅應費化工染，濃綠疑從帝所頒。", "正色可曾娛俗眼，晚英猶足慰衰顔。", "它年解組歸三徑，多種青青滿故山。"]'),
('255d7e1e-390a-4c74-a158-ee50a71b7b65','題佛閣三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','佛閣閲人久，儒官涉世踈。',24,'全唐诗/poet.song.118000.json','["佛閣閲人久，儒官涉世踈。", "伽藍真長者，容我半年居。"]'),
('a6fcfea9-ced4-421e-912a-3f0492744abc','題佛閣三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','桑下不三宿，閣中經半年。',24,'全唐诗/poet.song.118000.json','["桑下不三宿，閣中經半年。", "青山滿庭戶，雖好莫留連。"]'),
('e81c9b0b-91ec-40df-9df7-fa1f9ad13674','題佛閣三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','靈運本狂客，偶來蓮社遊。',24,'全唐诗/poet.song.118000.json','["靈運本狂客，偶來蓮社遊。", "鍾魚聽已厭，歸去故園休。"]'),
('eea9a4ee-5fe0-4553-a16c-deabcf8caa4b','題郭莊路','王十朋','宋','宋诗','song-poetry','','[]','南山有井名黄花，我卜別業臨其涯。',160,'全唐诗/poet.song.118000.json','["南山有井名黄花，我卜別業臨其涯。", "酌泉潄石思徃事，天遺景與名俱嘉。", "東籬採菊隠君子，悠然凝望南山賒。", "茲人高躅已千古，三徑蕪沒堪咨嗟。", "我生本抱丘壑尚，誤涉塵世爭浮蝸。", "十年太學志未遂，歸來隴畝躬桑麻。", "草莊新築亦不惡，青山遠近光交加。", "會須移住效杜老，終賦歸去師陶家。", "新凉入郊九日近，西風漸欲吹烏紗。", "龍山風俗有故事，撩我清興凌烟霞。"]'),
('5cfeaf07-7fe6-4e22-b28e-77b076fe8640','率飲亭二十絕  其一','王十朋','宋','宋诗','song-poetry','','[]','吾門非北海，安得客滿坐。',24,'全唐诗/poet.song.118000.json','["吾門非北海，安得客滿坐。", "有亭名率飲，鄰里日相過。"]'),
('7956d167-37bb-44ef-acc1-e356e2494fcc','率飲亭二十絕  其二','王十朋','宋','宋诗','song-poetry','','[]','蒼頭稍知耕，赤脚頗能釀。',24,'全唐诗/poet.song.118000.json','["蒼頭稍知耕，赤脚頗能釀。", "有田俱種秫，我日坐亭上。"]'),
('a73ae727-4337-4b7a-b048-b92276206d06','率飲亭二十絕  其三','王十朋','宋','宋诗','song-poetry','','[]','幽亭闊方丈，脩竹種千百。',24,'全唐诗/poet.song.118000.json','["幽亭闊方丈，脩竹種千百。", "有時人不來，影月爲吾客。"]'),
('4a003aec-7d6b-4195-b099-9cb7e7fc44a8','率飲亭二十絕  其四','王十朋','宋','宋诗','song-poetry','','[]','富貴有天命，安貧士之常。',24,'全唐诗/poet.song.118000.json','["富貴有天命，安貧士之常。", "聊爲真率飲，未用利名忙。"]'),
('187b0165-b2e3-47b0-b279-3401bd750354','率飲亭二十絕  其五','王十朋','宋','宋诗','song-poetry','','[]','老去識交情，興來懷酒伴。',24,'全唐诗/poet.song.118000.json','["老去識交情，興來懷酒伴。", "山林車馬稀，風月壺觴滿。"]'),
('e01b7603-f55c-4f90-8e90-1514c8f1e7c8','率飲亭二十絕  其六','王十朋','宋','宋诗','song-poetry','','[]','文舉客滿坐，淵明酒盈尊。',24,'全唐诗/poet.song.118000.json','["文舉客滿坐，淵明酒盈尊。", "雖無古高躅，妙意亦常存。"]'),
('7637eb3c-c74e-4198-8349-1414790cd81d','率飲亭二十絕  其七','王十朋','宋','宋诗','song-poetry','','[]','文字粗能飲，聖賢時復中。',24,'全唐诗/poet.song.118000.json','["文字粗能飲，聖賢時復中。", "林間十二子，賓主自清風。"]'),
('bc4b7c30-e7b3-4471-af2b-9a32634fb855','率飲亭二十絕  其八','王十朋','宋','宋诗','song-poetry','','[]','富飲不解文，翁意非在酒。',24,'全唐诗/poet.song.118000.json','["富飲不解文，翁意非在酒。", "三盃聊遣興，一醉豈緣口。"]'),
('0b230150-1bba-4935-a65f-3237cdca8186','率飲亭二十絕  其九','王十朋','宋','宋诗','song-poetry','','[]','我游醉鄉中，常在軟飽後。',24,'全唐诗/poet.song.118000.json','["我游醉鄉中，常在軟飽後。", "誰脩醉鄉記，添我姓名不。"]'),
('caf6db40-c289-4b93-a216-cc8623d85639','率飲亭二十絕  其一○','王十朋','宋','宋诗','song-poetry','','[]','吾家數兄弟，薄有古人風。',24,'全唐诗/poet.song.118000.json','["吾家數兄弟，薄有古人風。", "生計何曾足，酒盃無日空。"]'),
('8bd377fc-2a83-4a4e-ad4b-c93478a5acfd','率飲亭二十絕  其一一','王十朋','宋','宋诗','song-poetry','','[]','我性野而率，山林謾求安。',24,'全唐诗/poet.song.118000.json','["我性野而率，山林謾求安。", "有酒固可樂，無酒亦自寬。"]'),
('5db9d04a-ad4b-43c0-bd07-5b01e7a1436e','率飲亭二十絕  其一二','王十朋','宋','宋诗','song-poetry','','[]','亭上可率飲，林間宜率吟。',24,'全唐诗/poet.song.118000.json','["亭上可率飲，林間宜率吟。", "每於詩酒裏，寓我率然心。"]'),
('6684f5d2-a8ab-41e3-987d-4ff085dbf7cb','率飲亭二十絕  其一三','王十朋','宋','宋诗','song-poetry','','[]','結交雖不泛，絕物亦何曾。',24,'全唐诗/poet.song.118000.json','["結交雖不泛，絕物亦何曾。", "莫問親踈客，過門無不應。"]'),
('d2c6f923-19a2-4c30-87d6-4cdab468e3d6','率飲亭二十絕  其一四','王十朋','宋','宋诗','song-poetry','','[]','交游聚散中，身世浮沉裏。',24,'全唐诗/poet.song.118000.json','["交游聚散中，身世浮沉裏。", "觀書悟昨非，把酒知今是。"]'),
('89f245c4-ed2b-405a-88cf-b589aead28f4','率飲亭二十絕  其一五','王十朋','宋','宋诗','song-poetry','','[]','有酒或無客，有客或無酒。',24,'全唐诗/poet.song.118000.json','["有酒或無客，有客或無酒。", "何時此亭中，客酒兩常有。"]'),
('a3999b5f-846d-436b-ad66-20c7f8014f5c','率飲亭二十絕  其一六','王十朋','宋','宋诗','song-poetry','','[]','是非何足論，時酒謾消遣。',24,'全唐诗/poet.song.118000.json','["是非何足論，時酒謾消遣。", "但把無它腸，聊爲在家善。"]'),
('9b9d095c-4f87-49a3-8d68-9618a1e35d13','率飲亭二十絕  其一七','王十朋','宋','宋诗','song-poetry','','[]','燈火散交游，園林寄幽興。',24,'全唐诗/poet.song.118000.json','["燈火散交游，園林寄幽興。", "萬事付無心，隨緣不求勝。"]'),
('aeaf246e-1f11-435a-a6e3-9ac2af44f363','率飲亭二十絕  其一八','王十朋','宋','宋诗','song-poetry','','[]','心向靜中求，身宜閑處著。',24,'全唐诗/poet.song.118000.json','["心向靜中求，身宜閑處著。", "閤已號便便，亭宜名莫莫。"]'),
('2baa903c-9aeb-4b44-9e43-19b39ec72a31','率飲亭二十絕  其一九','王十朋','宋','宋诗','song-poetry','','[]','吾家老兄弟，杖屨日相過。',24,'全唐诗/poet.song.118000.json','["吾家老兄弟，杖屨日相過。", "對酒歡無限，論詩味更多。"]'),
('1a04d683-7685-4b60-8125-e01f9b7199eb','率飲亭二十絕  其二○','王十朋','宋','宋诗','song-poetry','','[]','有口但飲酒，無悰亦作詩。',24,'全唐诗/poet.song.118000.json','["有口但飲酒，無悰亦作詩。", "它年宦南北，還憶在家時。"]'),
('d35a3f4d-dab7-4f6b-8a20-a0e4f6808232','橫山連氏妻方奉姑甚謹姑死刻木像事之越十年不怠郡守張公子韶下車命諸邑訪孝義予披牒至其家獲觀木像感嘆不已因書四十字時紹興丙子七月十四日也','王十朋','宋','宋诗','song-poetry','','[]','純孝世稀有，事亡人所難。',48,'全唐诗/poet.song.118000.json','["純孝世稀有，事亡人所難。", "堪嘉里曾子，况有婦丁蘭。", "守令方尊禮，鄉閭競聳觀。", "名將聞帝闕，旌表及門闌。"]'),
('453100aa-8549-459e-8575-9d0a9b0ec797','登姚奧嶺望家山有感','王十朋','宋','宋诗','song-poetry','','[]','昔年度茲嶺，回首念慈親。',24,'全唐诗/poet.song.118000.json','["昔年度茲嶺，回首念慈親。", "如今望雲處，惟有淚沾巾。"]'),
('4c2dd5c0-12c0-4c5b-8d68-ff627bcaa33a','題驛奧張店思周光宗','王十朋','宋','宋诗','song-poetry','','[]','憶昔同行宿此村，重來堪嘆止吾存。',32,'全唐诗/poet.song.118000.json','["憶昔同行宿此村，重來堪嘆止吾存。", "芙蓉雁蕩重經眼，舊事無人與共論。"]'),
('553d14e9-0a85-4e3e-9e4b-89809ec44797','度雁山','王十朋','宋','宋诗','song-poetry','','[]','雁山五經眼，茲行尤可觀。',120,'全唐诗/poet.song.118000.json','["雁山五經眼，茲行尤可觀。", "初冬天氣佳，雁歸山未寒。", "有日照幽谷，無雲翳層巒。", "入境見祥雲，振衣登馬鞍。", "瀑水飛玉龍，羽旗導翔鸞。", "石柱屹天外，卓筆書雲端。", "靈峯觀石室，杖屨穿巑岏。", "山禽知我來，好音若相歡。", "群峯列春笋，丹青狀尤難。", "行色媿匆匆，更約它時看。"]'),
('f54d201e-2c44-4071-9b5a-f7d525ce4848','度謝公嶺','王十朋','宋','宋诗','song-poetry','','[]','十年九行役，屢經此山中。',48,'全唐诗/poet.song.118000.json','["十年九行役，屢經此山中。", "愛山不厭觀，每媿行匆匆。", "大士瞻矩羅，騷人思謝公。", "一生看不足，語如白頭翁。"]'),
('af3a5b6b-40c9-4e09-8e76-efd269a0039a','臘日與守約同舍賞梅西湖','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖處士安在哉，湖山如舊梅花開。',128,'全唐诗/poet.song.118000.json','["西湖處士安在哉，湖山如舊梅花開。", "見花如見處士面，神清骨冷無纖埃。", "不將時節較早晚，風味自是花中魁。", "暗香和月入佳句，壓盡今古無詩才。", "武林深處景益勝，十里眼界多瓊瑰。", "北枝貪睡南枝醒，枝屨得得攙出來。", "旅中茲游殊不惡，况有佳友銜清杯。", "手折林間一枝雪，頭上带得新春回。"]'),
('501bc847-1296-4092-b347-6905efe87725','同舍再約賞梅用前韻','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅溪野人真野哉，老眼長爲寒梅開。',128,'全唐诗/poet.song.118000.json','["梅溪野人真野哉，老眼長爲寒梅開。", "朅來西湖探春色，濡毫一洗匈襟埃。", "却將梅花比和靖，花與人物俱奇魁。", "同行二十五佳客，一一盡是離騷才。", "新詩一出花價長，穅秕桃李奴玫瑰。", "湖山已槁處士骨，風月未厭吾儕來。", "欣聞好事約重賞，準擬餐玉嘗春盃。", "預辦長牋收白雪，載取十里清香回。"]'),
('cee70471-2cf6-4f5c-b0aa-c0e18a73d1a9','前日探梅李元翁以疾不往和詩有玉華野人多病惱獨守寒爐煨芋魁句復用前韻約同賞','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖十里真佳哉，百花未放梅先開。',128,'全唐诗/poet.song.118000.json','["西湖十里真佳哉，百花未放梅先開。", "吾儕好事頗成癖，探春不憚衝風埃。", "李生不出苦病惱，書閲肘後占河魁。", "膽瓶相對數點雪，錦腸寫出飄然才。", "人如西湖有涵養，句與和靖爭奇瑰。", "重尋勝游有新約，湖山準擬詩仙來。", "寒爐蹲鴟不必煨，爲花痛飲拚千盃。", "願君及早理杖屨，莫令立馬頭頻回。"]'),
('8673424c-1aa6-4b53-a38d-cd7bde2676b8','送王司業守永嘉','王十朋','宋','宋诗','song-poetry','','[]','中興天子初龍翔，臨軒策士當維揚。',320,'全唐诗/poet.song.118000.json','["中興天子初龍翔，臨軒策士當維揚。", "艱難果見異人出，龍虎甲乙俱非常。", "先生大對過晁董，指切時務言激昂。", "麟經絕筆二千載，收拾紙上生光芒。", "自從曲江到今日，勁氣獨得南方强。", "權門用事手可炙，申棖亦減平生剛。", "先生閉門玩爻象，簸弄日月潮之陽。", "帝憂南國命共理，袁連二政俱循良。", "公道方行正人用，詔起韓愈師虞庠。", "先生不作進學解，直言慷慨投封章。", "一麾出守山水郡，十行詔墨加恩光。", "東嘉得賢類京兆，前政有張今有王。", "張公到官席未煖，猶有遺愛如甘棠。", "先生况是儒宗師，斂此大惠施一方。", "入境願問民疾苦，下車宜誅吏奸贓。", "首延璆孺坐賢榻，無使楊墨登門牆。", "河內借恂豈容久，宸衷念賈殊未忘。", "鯫生摳衣恨太晚，執經未獲時登堂。", "私心竊喜父母國，聖恩特許來龔黄。", "願同何堅首率化，歸見潁川鳴鳳凰。"]'),
('30ffe78d-30e2-4578-92a8-1495942ff2a1','春日游西湖','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山色綠如染，湖光青似磨。',48,'全唐诗/poet.song.118000.json','["山色綠如染，湖光青似磨。", "峯高捧日久，波闊浸天多。", "瑞氣浮城闕，春光醉綺羅。", "能將比西子，妙句有東坡。"]'),
('4668a8be-cfa4-4dda-8771-300457b557c0','和韓秋懷十一首  其一','王十朋','宋','宋诗','song-poetry','','[]','孟夏游會稽，禾稼方薿薿。',96,'全唐诗/poet.song.118000.json','["孟夏游會稽，禾稼方薿薿。", "南風翼新苗，生意殊未已。", "重來覺非久，相去百日耳。", "黄雲萬頃空，蘋末凉風起。", "園林亦摇落，觸目成疑似。", "人生過隙駒，朱顔何足恃。", "胡爲向迷塗，奔走不停軌。", "得失無榮辱，歸來實堪喜。"]'),
('e26b1307-5745-42bb-9468-f425018b41aa','和韓秋懷十一首  其二','王十朋','宋','宋诗','song-poetry','','[]','草木無利名，時來自榮悴。',60,'全唐诗/poet.song.118000.json','["草木無利名，時來自榮悴。", "人生異草木，百念起心地。", "困窮斯感傷，利達或驕恣。", "一朝同物化，榮辱兩何異。", "有酒且行樂，不必富與貴。"]'),
('af26feeb-3c9d-436a-99c9-0a2c8129c7d7','和韓秋懷十一首  其三','王十朋','宋','宋诗','song-poetry','','[]','直道疾伊優，壯懷增靡曼。',84,'全唐诗/poet.song.118000.json','["直道疾伊優，壯懷增靡曼。", "海上豕方牧，夜中牛屢飯。", "半生營一名，偃蹇未如願。", "青銅忽自照，白髮已堪歎。", "斥鷃適蓬蒿，大鵬摶九萬。", "物情貴得所，奚用求自獻。", "富貴似可喜，貧賤亦何怨。"]'),
('f4e2befc-f33a-4e0b-bc34-88bd898d674b','和韓秋懷十一首  其四','王十朋','宋','宋诗','song-poetry','','[]','秋雨浸成潦，秋霜漸爲凌。',72,'全唐诗/poet.song.118000.json','["秋雨浸成潦，秋霜漸爲凌。", "老樹喑寒蟬，腥盤集癡蠅。", "天涯有歸客，面目吁可憎。", "吟餘自捫腹，肝膽空稜稜。", "臨淵不善漁，籬頭掛寒罾。", "數椽茅屋下，養此百不能。"]'),
('47c1c176-04fc-4af0-b717-f1787c118850','和韓秋懷十一首  其五','王十朋','宋','宋诗','song-poetry','','[]','秋懷蟲共悲，秋夜鶴同警。',72,'全唐诗/poet.song.118000.json','["秋懷蟲共悲，秋夜鶴同警。", "輝輝玉繩低，耿耿銀漢永。", "靜思鳬舄喬，遐慕螭蟠猛。", "途遠慵著鞭，井深艱下綆。", "鳥倦當知還，馬失亦云幸。", "窮通委天命，塵慮可深屏。"]'),
('d55edf66-a7ad-4e82-a5ae-58ef81d90dea','和韓秋懷十一首  其六','王十朋','宋','宋诗','song-poetry','','[]','客路厭繁暑，歸懷愜新景。',60,'全唐诗/poet.song.118000.json','["客路厭繁暑，歸懷愜新景。", "枕冷夢自清，夜明窗更炯。", "聊棲明月枝，勝逐西風梗。", "支床甘自息，伏櫪倦思騁。", "惟有問目心，拳拳慕回請。"]'),
('f08fea06-f04e-418b-b6e9-f3332131aa7b','和韓秋懷十一首  其七','王十朋','宋','宋诗','song-poetry','','[]','窗几生新凉，燈火照初暗。',108,'全唐诗/poet.song.118000.json','["窗几生新凉，燈火照初暗。", "省己有昨非，探懷無宿憾。", "古書恣掀翻，古意薄窺瞰。", "心將遊寂寞，語復攻苦淡。", "實歉名忌浮，才踈得懲濫。", "守志懼不堅，入道恐成暫。", "性抑戒戕賊，心猿思繫纜。", "有友頻琢磨，無官自校勘。", "澹然學楊雄，不恨儲無甔。"]'),
('d33201f3-7687-46e8-baf7-9ad7f02f6939','和韓秋懷十一首  其八','王十朋','宋','宋诗','song-poetry','','[]','賢關藹多士，頭角爭軒軒。',120,'全唐诗/poet.song.118000.json','["賢關藹多士，頭角爭軒軒。", "中有倦游客，虛名厭馳奔。", "學爲忠與孝，思踐陽城言。", "高秋賦歸去，戯舞庭闈前。", "東園柿栗熟，採摘供盤餐。", "兄弟各賦詩，集作棣蕚編。", "甲乙二孺子，日誦言半千。", "學語三歲時，笑味生甜酸。", "欣然動我懷，長夜不成眠。", "歸來有此樂，亦可終殘年。"]'),
('64b5f332-8ade-46dc-b74c-08c63ddb53d4','和韓秋懷十一首  其九','王十朋','宋','宋诗','song-poetry','','[]','吾廬有脩竹，滴翠凝不乾。',84,'全唐诗/poet.song.118000.json','["吾廬有脩竹，滴翠凝不乾。", "天風一吹拂，終夜鳴琅玕。", "黄楊亦嘉樹，一甕何團團。", "日暮飛禽歸，啾然欲求安。", "嗟予欲何爲，屢涉吳江瀾。", "一名竟未就，舉彈空飛丸。", "對竹賞佳樹，聊繫予征鞍。"]'),
('7c47f22d-d7b0-4c71-9c0d-6e265d7120d2','和韓秋懷十一首  其一○','王十朋','宋','宋诗','song-poetry','','[]','商飈起何處，古樹生秋聲。',84,'全唐诗/poet.song.118000.json','["商飈起何處，古樹生秋聲。", "肅肅夜氣寂，悠悠月華明。", "兀兀念前古，孜孜殫寸誠。", "默默守孤陋，兢兢防滿盈。", "興至役詩匠，愁來驅酒兵。", "自適布衣願，未覺青衫榮。", "長鬚與赤脚，亦足供使令。"]'),
('1d8b16c1-ad9a-40a2-a261-df012c7e46c7','和韓秋懷十一首  其一一','王十朋','宋','宋诗','song-poetry','','[]','鮮鮮霜中菊，誰云晚不好。',60,'全唐诗/poet.song.118000.json','["鮮鮮霜中菊，誰云晚不好。", "開日即重陽，雖晚亦同蚤。", "對景便須醉，浮生苦難保。", "胡爲楚大夫，不飲致枯槁。", "何如醉鄉人，雖醉亦有道。"]'),
('ab681370-f9b2-43da-8c6d-d364e6602141','和韓符讀書城南示孟甲孟乙','王十朋','宋','宋诗','song-poetry','','[]','性無有不善，茲言聞子輿。',288,'全唐诗/poet.song.118000.json','["性無有不善，茲言聞子輿。", "學所以脩性，楊雄著之書。", "欲知人之生，靈臺湛然虛。", "習善裕乃身，習惡喪厥初。", "下惠與盜跖，不生兩門閭。", "所趨一不同，相去霄壤如。", "是以吾夫子，詩禮教伯魚。", "當時非義方，聖門亦蕭疏。", "我似杜陵翁，有兒最憐渠。", "徒愛不知教，懼如馿與豬。", "詎望登丹霄，折桂騎蟾蜍。", "粗令有聞見，免爲甕中蛆。", "丱角入小學，首誦仲尼居。", "要知先孝弟，餘力哉乎歟。", "我家素孤寒，金玉苦無儲。", "舊業止青箱，辛勤二星餘。", "遺爾以清白，爾曹宜念且。", "性情乃良田，學問爲耘鋤。", "勿患遠難致，跬步馳蹇馿。", "勿憂年不逢，六經有新畬。", "勿隨奔競流，伺候人庭除。", "勿學田舍兒，黄金買冠裾。", "在我能自脩，不患無聲譽。", "我久困筆硯，退思老山墟。"]'),
('a8a44a8f-0a43-4882-9158-409e884f3d57','和韓醉贈張秘書寄萬大年先之申之','王十朋','宋','宋诗','song-poetry','','[]','良友不易得，清談苦難聞。',240,'全唐诗/poet.song.118000.json','["良友不易得，清談苦難聞。", "前夕知何夕，我來訪諸君。", "共對燈燭光，芳尊細論文。", "通家忝孔李，促席聯機雲。", "杯盤畧荷禮，氣味同清芬。", "一盞洗窮愁，三杯話離群。", "春舟會稽別，秋袂錢塘分。", "顧我與三友，新當敗孤軍。", "飄零各南北，對酒無復醺。", "客况飽牢落，時光負氤氳。", "聚散實堪恨，榮枯何足云。", "歸來已三月，俗狀日紛紛。", "幸此同一笑，盤餐飣腥葷。", "蠔山薦巨房，龜脚烹脩裙。", "良辰屬嚴冬，敗懽無蠅蚊。", "痛飲竟長夜，高歌和南薰。", "雖非韓孟張，所飲亦典墳。", "何時脫場屋，南畝同耕耘。", "晝爲雞豚社，夜策詩酒勳。", "此言宜早踐，勿待桑榆曛。"]'),
('4d7fb207-bd7e-4aef-a591-2e18e6c1b8b1','和韓縣齋有懷四十韻','王十朋','宋','宋诗','song-poetry','','[]','讀書窺古今，掩卷成叱咤。',288,'全唐诗/poet.song.118000.json','["讀書窺古今，掩卷成叱咤。", "唐虞昔垂衣，禹稷起躬稼。", "人材各超絕，王業迭興謝。", "典謨光日月，雅頌藹蘭麝。", "孟軻論易地，顔回堪並駕。", "窮達雖殊途，聖賢實同價。", "避就鄉隣鬭，泣笑疏戚謝。", "甘心惟飲瓢，沒齒不談霸。", "斯人嗟已亡，末俗遂多詐。", "祿從枉道求，氣爲權門下。", "爭爲邑犬吠，翻取獵師駡。", "幽人思隠盤，高士欲耕灞。", "予生苦多難，安跡殊未暇。", "冬行皸兩足，夜坐痹雙髂。", "黄卷徒自勞，青雲未能跨。", "借勢乏王公，成名無僕射。", "大學厭虀鹽，親闈疏膾炙。", "眷眷日懷歸，區區每求假。", "飛同鷁過宋，閑若馬歸華。", "陋巷懷哲人，短檠燒午夜。", "對床有兄弟，通家足姻婭。", "談笑開芳尊，塵勞釋征靶。", "篇章日盈囊，卷帙時抽架。", "詠歌同舞雩，歎息殊觀蠟。"]'),
('df0139c9-5324-4056-95b2-b73cb273e379','和韓桃源圖','王十朋','宋','宋诗','song-poetry','','[]','嬴秦斬新開混茫，傲睨前古無虞唐。',304,'全唐诗/poet.song.118000.json','["嬴秦斬新開混茫，傲睨前古無虞唐。", "詩書爲灰儒鬼哭，李斯秉筆中書堂。", "長城丁壯無還者，送徒更住驪山下。", "避世高人何所之，出門永與家鄉辭。", "入山惟恐不深遠，豈是得已巢於斯。", "來時六合爲秦室，未省今爲何歲日。", "吏不到門租不輸，子長丁添更何卹。", "春入山中桃自花，招邀隠侶傾流霞。", "男耕女織自婚嫁，派別支分都幾家。", "誰泛漁舟迷處所，山開洞闢聞人語。", "乍相驚問卒相歡，設酒烹鷄講賓主。", "可憐秦事已茫然，帝業初期萬萬年。", "猶道祖龍長在世，豈知異姓早三傳。", "鄰里殷勤爭餉饋，人情與世無相異。", "未信壺中別有天，却訝身游與夢寐。", "山花亂眼鳥哀鳴，數日留連喜復驚。", "更從洞口尋鄉路，逢人欲話疑非情。", "異日扁舟欲重顧，水眩山迷紅日暮。", "後來圖畫了非真，作誌淵明乃晉人。"]'),
('1c014c9b-b7f8-4163-a523-12b4e506c67c','和韓永貞行','王十朋','宋','宋诗','song-poetry','','[]','君不見天爲元和開號令，先遣憸人竊朝柄。',315,'全唐诗/poet.song.118000.json','["君不見天爲元和開號令，先遣憸人竊朝柄。", "奉天難平閑虎貔，弈客待詔來京師。", "口中班班談治道，貞觀開元何足爲。", "黨與紛紛自標置，遠借伊周供佞媚。", "望塵附火皆美官，怨脩睚眥曾不難。", "梯媒爵位由貨賂，斥遂朝士因杯盤。", "珣瑜卧第郢佑默，誰爲唐室回狂瀾。", "朝攘利權未爲怪，莫奪兵柄尤可歎。", "仙李蟠根未當艾，十葉神器那容干。", "禁中大義知誰主，東宮受禪同三祖。", "越兒涕泣吳兒悲，從此豺狼不生羽。", "剛明天子位初登，翦除元惡流凶朋。", "八州司馬才可稱，節已掃地誰復矜。", "子厚年少躁飛騰，身陷醜黨罹熏蒸。", "著文擬騷愁思凝，欲自辨白終莫曾。", "王孫尸蟲託駡憎，色豈不媿明窗燈。", "所記先友時良肱，忍使柳氏家聲崩。", "吁嗟匪人何足憑，士勿妄進當戰兢。", "退之鯁直憤不勝，詩篇史筆兩可徵，永貞覆轍宜痛懲。"]'),
('761f46d4-2168-4379-971e-3b8fe0ba6ebb','和韓短燈檠歌寄劉長方','王十朋','宋','宋诗','song-poetry','','[]','我與君游最久長，短檠夜夜分清光。',128,'全唐诗/poet.song.118000.json','["我與君游最久長，短檠夜夜分清光。", "初從鄉校共牢落，晚入太學同凄凉。", "眼看兒輩盡騰踏，尚磨鐵硯穿藜牀。", "君今已作青雲客，萬言曾射天庭策。", "藍袍歸拜七十翁，壽酒十分傾太白。", "嗟予偃蹇只如前，日高空作盧仝眠。", "樂事已輸君自恣，銀燭高燒環翡翠。", "直形空腹舊時燈，牆角未應容易棄。"]'),
('9bf97473-4e26-4b25-aaad-336da3efdda8','和韓苦寒','王十朋','宋','宋诗','song-poetry','','[]','羲和錯冬令，寒燠常相兼。',288,'全唐诗/poet.song.118000.json','["羲和錯冬令，寒燠常相兼。", "在人爲不常，時焉作貪廉。", "玄冥當用事，如忌還如謙。", "宜寒噤不噓，羣萌誤抽尖。", "既燠俄吹冷，夜寐黑不甜。", "水行失其理，厥疾不可砭。", "前日當孟冬，雷聲震銅蟾。", "三日輙大雪，飛花眩觀覘。", "逮此始踰月，屢變寒與炎。", "晨起坐東窗，陽光快恩霑。", "霜畦秀蔬苗，欣焉自腰鐮。", "頃刻變凜冽，枯藤怯提拈。", "齒牙戰霜風，縮舌疑銜箝。", "架抽紛掀翻，誰能正牙籤。", "酒杯覺無力，瓶罄勞頻添。", "貂裘尚不暖，况無或衣縑。", "兀坐擁黄紬，脰作寒龜潛。", "氣血粟肌體，涕涶冰鬚髯。", "紅爐熾薪炭，旋覺寒星殲。", "靜思天壤間，萬類何繁纖。", "路傍泣凍餒，海角愁廢淹。", "羽毛有不庇，腥血有不燖。", "豈堪當此時，可以吾身占。", "殷勤語妻子，汝勿多怨嫌。"]'),
('49d9a49e-9d0f-4560-b785-51ae5d14c45b','和韓南食','王十朋','宋','宋诗','song-poetry','','[]','海錯千萬族，惟蠔不能行。',168,'全唐诗/poet.song.118000.json','["海錯千萬族，惟蠔不能行。", "潮來腹自飽，亦足遂厥生。", "翻笑魚蟹蝦，晨夜何營營。", "風味與江瑶，可以次第名。", "薦身炮炙間，殻破材始呈。", "北客昔南食，一見生怪驚。", "故人居海濱，群鮮厭庖烹。", "酷愛此味真，不假薑桂橙。", "遥憐山間友，混迹黎與騂。", "蔬腸久不飽，肌骨尫且獰。", "巨房餉饞腹，一笑百念平。", "豈爲飲食欲，實見親舊情。", "誰知虀鹽餘，盤餐味常并。", "故鄉實堪戀，未用圖西行。"]'),
('a00f33eb-c5ef-4cdc-af83-f89247196f6e','和韓聽穎師琴','王十朋','宋','宋诗','song-poetry','','[]','七絃自相語，唱予仍和汝。',118,'全唐诗/poet.song.118000.json','["七絃自相語，唱予仍和汝。", "千指忽凄凉，騷人悲戰場。", "大絃溫和小消越，惠風夷韻參悠揚。", "琴瑟鳴寒泉，儀儀舞鸞凰。", "山高水遠聽愈淡，花奴羯鼓聲方彊。", "施生幽雅士，不好笙與篁。", "千金買焦尾，悠然坐藜牀。", "顧我非知音，感激涕自滂。", "三聽輒三嘆，羲皇在我虀鹽腸。"]'),
('997f0a71-b4cb-4874-a72f-2bbdfde4bf02','和韓憶昨行示夢齡','王十朋','宋','宋诗','song-poetry','','[]','憶昨少年氣銳心未灰，平明出門薄暮迴。',322,'全唐诗/poet.song.118000.json','["憶昨少年氣銳心未灰，平明出門薄暮迴。", "解衣換酒期必醉，亂花壓面欹條枚。", "年華荏苒今半世，觸事徃徃生悲哀。", "歡娛無復少年味，勉强談笑陪尊罍。", "飲纔過量輙成疾，秋霜入鬢剛腸摧。", "子年少我氣鼎盛，琅玕夜誦聲如雷。", "匈中平時足藴藉，頤神養素成嬰孩。", "松姿柏質異蒲柳，堅剛不怕霜霰漼。", "凌雲變化未可料，豈比嵲屼風中桅。", "胡爲鬰鬰乃如許，與我老者同虺隤。", "豈緣心事未如願，一念遂覺憂愁來。", "還驚世態多險阻，忤意未兌生嫌猜。", "壯懷千里力未致，齟齬翻類三足能。", "傷和伐性致坎軻，兩眉蹙恨憑誰開。", "吾聞君子貴知命，數者於我何有哉。", "又聞古人亦迍蹇，在易固有無妄災。", "閉門靜坐養時晦，拂拭心鏡捐塵埃。", "他年定作仁者壽，齒背會見同鯢鮐。", "聖賢遺訓載子腹，此事寧不知所裁。", "否徃泰來固有日，坦塗利轂寧須推。"]'),
('ee7b3bf5-a397-4ba7-8343-98231d73befd','和韓燕河南府秀才送周光宗','王十朋','宋','宋诗','song-poetry','','[]','吾皇尚柔理，北客來輸平。',240,'全唐诗/poet.song.118000.json','["吾皇尚柔理，北客來輸平。", "投戈講文藝，虞庠萃群英。", "藹藹六年間，人物如西京。", "菁莪各成材，龍虎巍標名。", "東嘉號多士，半作鴻都生。", "昭然藻鑑中，不負事業精。", "先進日通顯，天衢作雷轟。", "後生益可畏，行藝方蜚聲。", "賢哉汝南丈，頭角令人驚。", "撐腸飽文史，欲振三年鳴。", "偃蹇未如志，造物殊無情。", "歸來務遵養，絕意蝸角爭。", "高堂有慈親，祿養須大烹。", "壯懷不能已，千里提短檠。", "掉頭脫塵鞅，舉翼摩太清。", "賤子忝交末，平生荷推誠。", "緬懷去年春，駕言共西征。", "悠悠舊時路，君今獨先行。", "江梅弄春色，愛日烘新晴。", "勿憚行役苦，會見歸來榮。"]'),
('84b9cfc9-7d2f-4a2b-8290-e215d5ce2a6b','和韓答張轍寄曹夢良','王十朋','宋','宋诗','song-poetry','','[]','故舊別云久，話言猶未聆。',288,'全唐诗/poet.song.118000.json','["故舊別云久，話言猶未聆。", "歲暮念愈劇，宵長夢形頻。", "憶昔始傾蓋，相看俱妙齡。", "參乎方越席，鯉也纔趨庭。", "樂泮共采藻，泛江同食萍。", "玄深探羲畫，狂妄窺麟經。", "端能辨箕荄，未省分雷霆。", "卷帙發晨架，膏油燃夜櫺。", "君才富八斗，我字識一丁。", "輕願苦窘幅，高屋欽建瓴。", "低頭願爲愈，割席終慙寧。", "結游指寥廓，約泛航清泠。", "驥足騁天駿，鼇頭緡海腥。", "塗遠困塵鞅，棹迴閣寒汀。", "壯懷誓白水，憤氣干青冥。", "孤嶼散形影，雙溪隔滄溟。", "耿耿月遥共，悠悠門獨扃。", "論文憶李白，對酒懷劉伶。", "鄉校鼓沂瑟，頌章賡魯駉。", "濯暑振風袂，破寒操雪舲。", "勝游倣栗里，雅會脩蘭亭。", "瓶罄沽甕蟻，燭殘照囊螢。", "猖狂却大雅，酩酊還獨醒。", "槐市忽飛詔，英才先振翎。"]'),
('01987cc9-1a1c-46a1-9fe3-517b4dd0b18f','己巳元日讀韓送楊郎中賀正詩因和其韻','王十朋','宋','宋诗','song-poetry','','[]','曉日五更雞咿喔，銀缸明滅燒餘脂。',64,'全唐诗/poet.song.118000.json','["曉日五更雞咿喔，銀缸明滅燒餘脂。", "家家呼牛逐耗鬼，牛歸誰家鬼何之。", "皇都朝會我無與，西疇春事行及期。", "弟兄成行拜親老，猶勝去年身未歸。"]'),
('6add5d75-e076-43d0-bd2a-da3c3df7145b','人日過電山隨行有昌黎集因讀城南登高詩遂次韵留別孫先覺','王十朋','宋','宋诗','song-poetry','','[]','臘去梅已稀，陽浮柳初弄。',120,'全唐诗/poet.song.118000.json','["臘去梅已稀，陽浮柳初弄。", "北斗新轉梢，東風漸消凍。", "爲人節固佳，顧我身無用。", "命駕訪親交，肩輿勞僕從。", "門闌念久別，燈燭忻此共。", "興來酒自斟，歡至欹頻送。", "提壺勸銜盃，播穀催除葑。", "農耕方迫歸，行樂未能縱。", "人生苦離別，俗狀嗟倥傯。", "春風桃李花，把盞何時重。"]'),
('e2fb16a1-b07d-4b25-836d-2d728676fbc4','和韓李花  其一','王十朋','宋','宋诗','song-poetry','','[]','春風入園林，萬卉以艷爭相夸。',124,'全唐诗/poet.song.118000.json','["春風入園林，萬卉以艷爭相夸。", "胡爲此仙李，顔色憔悴堪咨嗟。", "稜稜瘦樹數點雪，半醒半睡風欹斜。", "枯枝膚剝少生意，况有疥癬相孽芽。", "不如免葵及燕麥，妍媚春色摇纖葩。", "下自成蹊直虛語，誰肯顧盼留香車。", "顧我逢春少行樂，老眼日有文書遮。", "自憐衰颯已如許，那更對此愁人花。"]'),
('3ad37489-922b-4acd-8d4a-da53568b9025','和韓李花  其二','王十朋','宋','宋诗','song-poetry','','[]','皇都二月桃李盛，朱輪翠蓋方紛拏。',112,'全唐诗/poet.song.118000.json','["皇都二月桃李盛，朱輪翠蓋方紛拏。", "東君世情亦太甚，十分春在侯門花。", "試吟怨句問蒼昊，一種春工何損加。", "白華秉燭光照夜，此樹不屬孤寒家。", "造化無言意潛告，我愛萬物初無差。", "物情稟受苦自異，奚有厚薄施萌芽。", "勸君勿爲花致怨，居易俟命思無邪。"]'),
('ee9023da-48b1-42ef-8f3a-6db6e5c98036','和韓答柳柳州食蝦蟆','王十朋','宋','宋诗','song-poetry','','[]','蟲魚千萬族，一一異狀貌。',204,'全唐诗/poet.song.118000.json','["蟲魚千萬族，一一異狀貌。", "飛潛同一性，巨細何必校。", "彼微水中鼃，四足傴而皰。", "自從科蚪初，生育在泥淖。", "好鳴乃其性，非故欲喧閙。", "蟈氏職洒灰，恐非聖人教。", "吾聞人間世，生死同夢覺。", "殺物傷吾仁，忍聽聲熚爆。", "况我儒衣冠，絃誦生鄉校。", "彼亦呼子曰，有意欲吾效。", "人蟲各好生，奚用苦相撓。", "退之憚食蛇，得得釋籠罩。", "子厚放鷓鴣，仁心亦稍稍。", "胡爲於此蟲，未盡忘嗜樂。", "薦祠用梟獍，穿穽誅虎豹。", "古人豈妄殺，去害除不孝。", "願留茲鼓吹，駐我寒溪櫂。"]'),
('1253c687-2012-4f45-9105-9ec27dd56727','伏犧  其一','王十朋','宋','宋诗','song-poetry','','[]','太古民淳事簡稀，聖人牛首號包羲。',32,'全唐诗/poet.song.118000.json','["太古民淳事簡稀，聖人牛首號包羲。", "如今四海皆人面，心似山川更嶮巇。"]'),
('32f70601-dd7f-49c4-af34-1ee03c32e2e5','伏犧  其二','王十朋','宋','宋诗','song-poetry','','[]','六畫中含萬象殊，洪荒一變遂歸儒。',32,'全唐诗/poet.song.118000.json','["六畫中含萬象殊，洪荒一變遂歸儒。", "河圖不授包犧氏，民到于今目尚塗。"]'),
('6a3b9df6-9f92-444b-bec0-808421d7696a','神農','王十朋','宋','宋诗','song-poetry','','[]','民食腥膻鳥獸同，那知土穀利無窮。',32,'全唐诗/poet.song.118000.json','["民食腥膻鳥獸同，那知土穀利無窮。", "後人只祀勾龍棄，誰念艱難起帝功。"]'),
('261eb56e-e7b4-4308-a80a-48aa73b2a230','黄帝','王十朋','宋','宋诗','song-poetry','','[]','百年功就蛻乾坤，鼎冷湖空跡尚存。',32,'全唐诗/poet.song.118000.json','["百年功就蛻乾坤，鼎冷湖空跡尚存。", "別有慶源流不盡，皇朝葉葉是神孫。"]'),
('fbe1aaba-b7b7-4450-913e-1e346d593747','唐堯','王十朋','宋','宋诗','song-poetry','','[]','仁德如天帝業隆，四凶不去付重瞳。',32,'全唐诗/poet.song.118000.json','["仁德如天帝業隆，四凶不去付重瞳。", "當時黄屋如傳子，千古那知楫遜風。"]'),
('9cadec60-190b-44bf-9637-9e39ab93a0df','夏禹','王十朋','宋','宋诗','song-poetry','','[]','洪流浩浩浸寰區，民雜蛇龍鳥獸居。',32,'全唐诗/poet.song.118000.json','["洪流浩浩浸寰區，民雜蛇龍鳥獸居。", "長歎當時微帝力，蒼生今日盡爲魚。"]'),
('df3f82c3-58fd-4dce-b13b-edd8138fc568','啟','王十朋','宋','宋诗','song-poetry','','[]','堯舜與賢真可法，夏王傳子若堪疑。',32,'全唐诗/poet.song.118000.json','["堯舜與賢真可法，夏王傳子若堪疑。", "謳欹自屬吾君子，不是當時禹德哀。"]'),
('18801906-3e87-4fc1-918f-f50e594fc511','少康','王十朋','宋','宋诗','song-poetry','','[]','虞仍靡艾共輸忠，一旅中興復禹功。',32,'全唐诗/poet.song.118000.json','["虞仍靡艾共輸忠，一旅中興復禹功。", "較德宜優漢高帝，知音惟有貴鄉公。"]'),
('47455434-b74e-40b6-a944-c4d541933b82','桀','王十朋','宋','宋诗','song-poetry','','[]','大禹辛勤造夏邦，子孫何苦事淫荒。',32,'全唐诗/poet.song.118000.json','["大禹辛勤造夏邦，子孫何苦事淫荒。", "國亡不悟生平罪，翻悔當時不殺湯。"]'),
('34915afd-c63f-4318-a737-bc584fa78aa8','成湯','王十朋','宋','宋诗','song-poetry','','[]','大乙興仁獸網中，鳴條一戰遂成功。',32,'全唐诗/poet.song.118000.json','["大乙興仁獸網中，鳴條一戰遂成功。", "歸來猶自懷慙德，事與唐虞已不同。"]'),
('af99b750-9577-4c85-a61e-1fa5247170da','高宗','王十朋','宋','宋诗','song-poetry','','[]','須信精誠可動天，高宗一夢得真賢。',32,'全唐诗/poet.song.118000.json','["須信精誠可動天，高宗一夢得真賢。", "濟川不頼良舟楫，安得中興五千年。"]'),
('ac034afc-5318-4853-babb-d6021e8bc7a4','紂','王十朋','宋','宋诗','song-poetry','','[]','釀酒爲池肉作林，深宮長夜恣荒淫。',32,'全唐诗/poet.song.118000.json','["釀酒爲池肉作林，深宮長夜恣荒淫。", "何如早散橋倉粟，結取臣民億萬心。"]'),
('7a784be1-e647-4c8e-bc60-75e63710a7fe','周文王','王十朋','宋','宋诗','song-poetry','','[]','民疾商辛若寇讎，三分天下二歸周。',32,'全唐诗/poet.song.118000.json','["民疾商辛若寇讎，三分天下二歸周。", "文王終世全臣節，不念前時羑里囚。"]'),
('369aea83-f6dd-43be-b45d-6a68e4b73109','武王','王十朋','宋','宋诗','song-poetry','','[]','八百諸侯會孟津，民心天意總歸仁。',32,'全唐诗/poet.song.118000.json','["八百諸侯會孟津，民心天意總歸仁。", "須知不食干戈粟，自有登山采蕨人。"]'),
('28540485-8099-4541-ab20-272a82cc7fb7','成王','王十朋','宋','宋诗','song-poetry','','[]','姬旦推誠相幼沖，流言交亂出居東。',32,'全唐诗/poet.song.118000.json','["姬旦推誠相幼沖，流言交亂出居東。", "誰云王是中才主，一啟金縢即悟公。"]'),
('37029a4f-69e7-4b6d-8499-4c94497e5980','宣王','王十朋','宋','宋诗','song-poetry','','[]','北伐南征萬國臣，中興周室頼賢人。',32,'全唐诗/poet.song.118000.json','["北伐南征萬國臣，中興周室頼賢人。", "崧高千古英靈在，何獨當時降甫申。"]'),
('e382c0d9-d97c-4154-9fea-8553b3ea8ec4','幽王','王十朋','宋','宋诗','song-poetry','','[]','文武基圖未易量，可憐中葉壞幽王。',32,'全唐诗/poet.song.118000.json','["文武基圖未易量，可憐中葉壞幽王。", "神龍流沫生尤物，赫赫宗周一笑亡。"]'),
('8688e124-6c3b-4c27-b0b9-4640ca82e408','秦始皇','王十朋','宋','宋诗','song-poetry','','[]','鯨吞六國帝人寰，遣使遥尋海上山。',32,'全唐诗/poet.song.118000.json','["鯨吞六國帝人寰，遣使遥尋海上山。", "仙藥未來身已死，鑾輿空載鮑魚還。"]'),
('ff7afc4b-6303-4237-8f69-6cf86cc7debc','二世','王十朋','宋','宋诗','song-poetry','','[]','始皇一怒逐扶蘇，天欲亡秦果在胡。',32,'全唐诗/poet.song.118000.json','["始皇一怒逐扶蘇，天欲亡秦果在胡。", "翻被四方黔首笑，不分鹿馬是誰愚。"]'),
('2561ad6f-5603-466c-90e1-53291c1287c0','漢高帝  其一','王十朋','宋','宋诗','song-poetry','','[]','百戰功成漢業新，咸陽置酒問群臣。',32,'全唐诗/poet.song.118000.json','["百戰功成漢業新，咸陽置酒問群臣。", "區區高起王陵輩，豈識龍顔善用人。"]'),
('0bb21fb7-8ab8-44e6-8aae-6d5fe0e84e0a','漢高帝  其二','王十朋','宋','宋诗','song-poetry','','[]','仗劍崎嶇起沛豐，祇將嫚駡馭英雄。',32,'全唐诗/poet.song.118000.json','["仗劍崎嶇起沛豐，祇將嫚駡馭英雄。", "雖然能用三人傑，已失商山四老翁。"]'),
('aa50c1eb-ddf2-4b3a-a9ea-8aca98658d7b','文帝','王十朋','宋','宋诗','song-poetry','','[]','文帝興王自代來，百金不費亦仁哉。',32,'全唐诗/poet.song.118000.json','["文帝興王自代來，百金不費亦仁哉。", "後人不務師恭儉，萬戶千門幾露臺。"]'),
