('2674b837-fc62-4306-ac07-90f4c49f6736','狄仁傑','王十朋','宋','宋诗','song-poetry','','[]','武火方炎李欲灰，忠良何力可能回。',32,'全唐诗/poet.song.118000.json','["武火方炎李欲灰，忠良何力可能回。", "斗南人有擎天手，爲向虞淵取日來。"]'),
('6856573a-1fc0-444a-989d-7ecac364483a','徐有功','王十朋','宋','宋诗','song-poetry','','[]','獄興羅織陷忠良，公亦幾遭虎口傷。',32,'全唐诗/poet.song.118000.json','["獄興羅織陷忠良，公亦幾遭虎口傷。", "蹈死救人人免死，論功何止漢于張。"]'),
('a9ae5c03-5545-4b79-b5cb-efbf231291f9','丁丑二月二十一日集英殿賜第','王十朋','宋','宋诗','song-poetry','','[]','太平天子崇儒術，寒賤書生荷作成。',64,'全唐诗/poet.song.118000.json','["太平天子崇儒術，寒賤書生荷作成。", "槐市育才叨舍選，楓宸唱第冠時英。", "聖恩寬大容愚直，御墨褒嘉佩寵榮。", "却笑劉蕡不遭際，徒令紙上有虛名。"]'),
('47e65b81-6a8e-4b30-a4b6-66c6ce6ab5ce','游天竺贈同年','王十朋','宋','宋诗','song-poetry','','[]','雅會清時不易逢，吾儕今日此游從。',64,'全唐诗/poet.song.118000.json','["雅會清時不易逢，吾儕今日此游從。", "逼人英氣湖光瑩，照眼恩袍草色濃。", "文盛一時俱俊傑，名先千佛媿疏庸。", "致身許國宜相勉，莫學平津但取容。"]'),
('56f05e8e-170b-42ff-b8cc-99f0c6df59f6','贈閻同年','王十朋','宋','宋诗','song-poetry','','[]','飄飄吳蜀兩衰翁，尊酒論文偶會同。',64,'全唐诗/poet.song.118000.json','["飄飄吳蜀兩衰翁，尊酒論文偶會同。", "名在儒科雖後我，言關國體豈如公。", "休嗟世路多巇嶮，共報君恩有樸忠。", "此日游從足可惜，行將渭北與江東。"]'),
('7e02bebb-05d4-449c-ada9-faad068fb67a','閻和詩敘別再用前韵','王十朋','宋','宋诗','song-poetry','','[]','我本東嘉田舍翁，登科偶與蜀龍同。',64,'全唐诗/poet.song.118000.json','["我本東嘉田舍翁，登科偶與蜀龍同。", "盍簪經月欽高誼，分袂令人念此公。", "幕府可能淹俊傑，宸襟應亦記精忠。", "他年攬轡游吳越，訪我茅廬浙水東。"]'),
('458a5b36-b8b2-4ffb-9a52-4c8186edfd1f','贈梁同年','王十朋','宋','宋诗','song-poetry','','[]','君家錦水邊，我居浙江東。',84,'全唐诗/poet.song.118000.json','["君家錦水邊，我居浙江東。", "各在天一涯，芳尊偶相同。", "君方富青春，勁氣吐長虹。", "我老志亦衰，倚麻媿蒿蓬。", "會合已踰月，周旋見高風。", "久客思故鄉，歸心各怱怱。", "贈君無別言，相期盡孤忠。"]'),
('8ff1819d-78ee-4f63-91df-1cd90bd5600c','次韻陳大監見贈','王十朋','宋','宋诗','song-poetry','','[]','中興天子尤崇儒，衆賢彙進如聯珠。',160,'全唐诗/poet.song.118000.json','["中興天子尤崇儒，衆賢彙進如聯珠。", "鄒枚待詔萃金馬，臯夔接武相俞都。", "策士初期異人出，不尚虛文與聲律。", "况當盛世多賈生，晁錯豈容爲第一。", "自慙俗學非名家，遺經獨抱居東嘉。", "齏鹽太學浪十載，豈有文許時人夸。", "芻言旅奏宸庭策，狂妄誤蒙明主擇。", "生天偶在千佛先，材劣名浮有餘責。", "潁川丈人詩絕奇，長篇勉我毋趨時。", "欲報君恩答知己，胸中耿耿何當施。"]'),
('186b8d5a-207e-469b-87eb-f7df1751558d','次韻劉長方司戶見贈','王十朋','宋','宋诗','song-poetry','','[]','楓宸昔羨君登第，蓮幕今慙我效官。',64,'全唐诗/poet.song.118000.json','["楓宸昔羨君登第，蓮幕今慙我效官。", "相見可嗟頭并白，老來自合量俱寬。", "不嫌此日成名晚，最喜平生取友端。", "待報君恩知死所，却同神武掛衣冠。"]'),
('294a9c23-a959-421f-875c-42b61ec09bc4','陳大監用賞梅韻以贈依韵酬之','王十朋','宋','宋诗','song-poetry','','[]','潁川丈人賢矣哉，青眼喜爲清流開。',128,'全唐诗/poet.song.118000.json','["潁川丈人賢矣哉，青眼喜爲清流開。", "詩章翰墨兩奇絕，筆下一字無塵埃。", "品題人物奬後進，搢紳樂善公爲魁。", "東嘉賤子生太晚，猶幸識此真人才。", "朅來西游也不惡，錦囊所得俱瓊瑰。", "區區科第何足道，此行似爲詩篇來。", "客中拜貺更重複，丙穴魚及郫筒杯。", "寒鄉故舊問歸橐，首言带得公詩回。"]'),
('df43edca-47b8-49a0-b7e4-52fc2e4732a3','大監復贈詩紙尾有留飯語再用韵以謝','王十朋','宋','宋诗','song-poetry','','[]','平生漫學乎歟哉，心茅胸棘鋤不開。',128,'全唐诗/poet.song.118000.json','["平生漫學乎歟哉，心茅胸棘鋤不開。", "得公新詩一再讀，便覺胸宇清無埃。", "銀鈎妙畫發光艷，照眼有如參與魁。", "鯫生肺腑非太白，公似工部尤憐才。", "旅中屢獲錦綉段，但媿欲報無瓊瑰。", "豫章一榻不妄下，賢非徐孺安敢來。", "荷公此意最敦篤，一笑當奉論文杯。", "鄉心如飛不可遏，更爲長者遲遲回。"]'),
('c2688741-4ef3-43ec-9309-0eb2a1975ab4','謝榮帥贈御書孝經用陳大監韵','王十朋','宋','宋诗','song-poetry','','[]','輦轂之下先彈壓，茲言雖佳未足法。',160,'全唐诗/poet.song.118000.json','["輦轂之下先彈壓，茲言雖佳未足法。", "丈人身居彈壓地，撫字心勞民自洽。", "神聖當天萬物春，王畿共理嘉得人。", "雲漢昭回賜優渥，不特爲公端爲民。", "聖經一章公獨得，黄堂葱鬰生春色。", "賢哉名卿才大夫，匪懈事君端可則。", "石刻分餘猶及我，榮耀驚聞浙江左。", "從今蔀屋光屬天，更有寵褒雲八朵。", "願公勉爲不朽傳，長如治吳與治川。", "要令列郡法青白，了無一吏橫索錢。"]'),
('2a0dec6c-e839-41bf-86c7-fab299c3b3f3','陳大監餞別用前詩珠字韵以謝','王十朋','宋','宋诗','song-poetry','','[]','宸廷僥冒先諸儒，寵褒况獲驪龍珠。',160,'全唐诗/poet.song.118000.json','["宸廷僥冒先諸儒，寵褒况獲驪龍珠。", "青衫黄牒拜君賜，紅蓮綠水官留都。", "明日扁舟欲東出，訪別長憂礙新律。", "丈人呼酒如韓公，賤子媿非張十一。", "酒闌未放客還家，活火煎泉烹葉嘉。", "西來頻下豫章榻，盛事當作還鄉夸。", "始終尚頼公鞭策，邪正途中知所擇。", "捐軀誓報明主恩，青史庶逃千古責。", "况公自是人中奇，境鄰呂望逢明時。", "行持從橐奉清問，美惡願分嫫與施。"]'),
('e70a7628-2cfe-41f5-aad2-0b790a0526fa','用陳大監韵謝王國錄季羔見贈','王十朋','宋','宋诗','song-poetry','','[]','吾宗神秀時名儒，贈我三百隋侯珠。',160,'全唐诗/poet.song.118000.json','["吾宗神秀時名儒，贈我三百隋侯珠。", "野人不識希世寶，但見照眼清而都。", "我昔遥從雁山出，旅食賢關淹歲律。", "雅欽陸子常患多，更歎張融可無一。", "長淮久絕誰起家，青箱有君殊可嘉。", "祠科得雋誚子厚，何止文許後生夸。", "我拙慚無濟時策，老境初官尚何擇。", "江南蓮幕君故鄉，竊芘聊逃簡書責。", "寒賤誤蒙君見奇，祖別贈言榮一時。", "明日東歸詫閭里，五絕首稱虞伯施。"]'),
('48b6823a-66e4-4d63-80a0-915a3ece4fea','陳郎中贈韓子蒼集','王十朋','宋','宋诗','song-poetry','','[]','唐宋詩人六七作，李杜韓柳歐蘇黄。',128,'全唐诗/poet.song.118000.json','["唐宋詩人六七作，李杜韓柳歐蘇黄。", "近來江西立宗派，妙句更推韓子蒼。", "非坡非谷自一家，鼎中一臠曾已嘗。", "丈人珍重贈全集，開卷爛然光焰長。", "詩如此公固足貴，賜出仁者尤難忘。", "兼金白璧不足道，願寶茲集爲家藏。", "鯫生幸脫場屋累，老境欲入詩門牆。", "古詩三百未能學，句法且學今陵陽。"]'),
('67e82275-e763-45b8-9c99-716befbc1ccb','章季子贈端硯','王十朋','宋','宋诗','song-poetry','','[]','有客贈端紫，剛方如正人。',48,'全唐诗/poet.song.118000.json','["有客贈端紫，剛方如正人。", "裔傳家萬石，力助筆千鈞。", "磨鐵嗟吾老，著書欣爾新。", "何當與毛穎，相約侍嚴宸。"]'),
('a1b0c166-8039-4d16-84b0-192a5c20d804','次韵陳大監赴天申節宴','王十朋','宋','宋诗','song-poetry','','[]','聖主仁心等南北，燧息邊庭兵不宿。',160,'全唐诗/poet.song.118000.json','["聖主仁心等南北，燧息邊庭兵不宿。", "兩階干羽來遠人，大度端能包濮祝。", "萬歲三呼誕彌月，四海千秋太平曲。", "宴開文德賜群臣，喜溢天顔明四目。", "向來獻壽人誰在，元凱重登共鯀逐。", "武夷戎監老風騷，去國十年官始復。", "捧觴首賦天保章，遥指南山祝君福。", "更獻曲江金鑑錄，不但能歌連理木。", "賤臣逢時最僥倖，歸美寧辭管城禿。", "願同韓愈頌元和，兼美武公歌綠竹。"]'),
('f1821ea4-994b-405f-80a1-9dc8ea235db6','謝李侍郎贈御書','王十朋','宋','宋诗','song-poetry','','[]','君不見西京孝武稱材雄，致治欲與唐虞同。',198,'全唐诗/poet.song.118000.json','["君不見西京孝武稱材雄，致治欲與唐虞同。", "詔求賢良論闕政，翻取曲學公孫弘。", "又不見文宗在唐號儒雅，制詔勤勤策群下。", "劉蕡切直棄不收，卒使太阿歸宦者。", "吾皇策士親臨軒，不爲故事求空言。", "猶疑有司效馮宿，或恐前列登公孫。", "九天賜下飛奎翰，照眼昭回悼雲漢。", "抑尚忠諛有訓詞，品題高下由宸斷。", "儒宗被命持文衡，銀鈎拜賜恩非輕。", "歸將樂石刊聖語，分貺下及狂愚生。", "畎畆惓倦蓄忠憤，射策自慙言不盡。", "它日倘陪鴛鷺行，願效魏公攄底藴。"]'),
('fcdddb42-ab11-4595-907a-3358aa622330','塗中得寶印叔二詩次韵  其一','王十朋','宋','宋诗','song-poetry','','[]','十年行役厭間關，一第初收鬢已斑。',32,'全唐诗/poet.song.118000.json','["十年行役厭間關，一第初收鬢已斑。", "重念此生難報處，君親恩德重丘山。"]'),
('4ae5254e-092f-4f69-bb13-3a36753396c0','塗中得寶印叔二詩次韵  其二','王十朋','宋','宋诗','song-poetry','','[]','雙親不見不勝悲，銜恨何曾有住時。',32,'全唐诗/poet.song.118000.json','["雙親不見不勝悲，銜恨何曾有住時。", "二叔尚存俱白首，歸來猶足慰衰遲。"]'),
('eac8caf5-5d5b-4a16-bc53-69794f53f57c','次韵寶印叔題壁二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','風掃園林萬木殘，道人眼界却宜看。',32,'全唐诗/poet.song.118000.json','["風掃園林萬木殘，道人眼界却宜看。", "北窗趺坐對松柏，人物青青俱歲寒。"]'),
('3d062cdb-8530-42b6-913b-db576746f538','次韵寶印叔題壁二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','早已心潛不二門，猶將土苴與人論。',32,'全唐诗/poet.song.118000.json','["早已心潛不二門，猶將土苴與人論。", "未須隻履西歸去，且作人間老世尊。"]'),
('e0c8dc25-b906-4adf-820b-831f40a00a24','萬府君挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','不廢東平業，思興畢萬門。',48,'全唐诗/poet.song.118000.json','["不廢東平業，思興畢萬門。", "短檠書自照，鐵硯志長存。", "冠玉貧寧久，蘭亭秀更蕃。", "一門今盛大，詩禮荷公恩。"]'),
('10877880-47e1-4fee-b668-19ecd816eb84','萬府君挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','肯歎儒冠誤，長隨舉子忙。',48,'全唐诗/poet.song.118000.json','["肯歎儒冠誤，長隨舉子忙。", "阿戎成雅志，小阮發幽光。", "原冷鴒猶近，椿摧桂始芳。", "老成嗟不見，猶記貌堂堂。"]'),
('e40f9a70-39cc-4e9e-8235-485e471d9fe5','致政宋承事挽詞','王十朋','宋','宋诗','song-poetry','','[]','蘭玉盈庭戲綵衣，顔如童子壽期頤。',64,'全唐诗/poet.song.118000.json','["蘭玉盈庭戲綵衣，顔如童子壽期頤。", "臨行四絕勝四偈，遯世五休高五噫。", "藍袖晚霑天子命，芳樽首致使君詞。", "誰云汲冢藏書富，應媿無公千首詩。"]'),
('871676a9-8dbe-4cab-a98e-8622429ed0a4','張德惠挽詞','王十朋','宋','宋诗','song-poetry','','[]','隠居高躅已茫然，潛德如公亦足賢。',64,'全唐诗/poet.song.118000.json','["隠居高躅已茫然，潛德如公亦足賢。", "早見鄉評稱孝子，晚聞詩史記凶年。", "事殊伯道兒宜有，行過王珪廟已先。", "滿腹玄談共誰語，九原歸去訪伊川。"]'),
('cb0bb42c-fd40-4603-a44d-539552e4fb16','宿羅漢三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','梵舍十八所，道場皆矩羅。',24,'全唐诗/poet.song.118000.json','["梵舍十八所，道場皆矩羅。", "茲獨號羅漢，想應無漏多。"]'),
('f6173453-a355-48c7-a985-2d21bd08fab6','宿羅漢三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','雁蕩屢經眼，箇中方再游。',24,'全唐诗/poet.song.118000.json','["雁蕩屢經眼，箇中方再游。", "何時脫塵鞅，來此飽清幽。"]'),
('748b7b58-2870-4efa-8c21-96798be8246a','宿羅漢三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','故鄉從此去，借問幾時還。',24,'全唐诗/poet.song.118000.json','["故鄉從此去，借問幾時還。", "先自思兄弟，那堪宿雁山。"]'),
('f389276c-80f7-473f-a70b-e20e8b01aebc','游大龍湫和前韵','王十朋','宋','宋诗','song-poetry','','[]','十年重到大龍湫，千尺新流勝舊流。',32,'全唐诗/poet.song.118000.json','["十年重到大龍湫，千尺新流勝舊流。", "會見四方霖雨足，老龍還向此藏頭。"]'),
('81c0609a-1f69-4db3-9a36-a3d377043bfd','游靈巖輝老索詩至靈峯寄數語','王十朋','宋','宋诗','song-poetry','','[]','雁蕩冠天下，靈巖尤絕奇。',156,'全唐诗/poet.song.118000.json','["雁蕩冠天下，靈巖尤絕奇。", "烟霞列屏障，日月明旌旗。", "巖前有卓筆，可以書雄詞。", "天聰况非遥，𣶈然聽無疑。", "願起靈湫龍，霖雨行何爲。", "願用真柱石，永支廊廟危。", "願煽造化爐，四海歸淳熙。", "願招鸞鳳友，朝廷相羽儀。", "何人夢石室，妄誕夸一時。", "那能了世緣，未兌貪嗔癡。", "名山誤見汙，公議安可欺。", "願借靈湫水，一洗了堂碑。", "詩以寄老禪，狂言勿吾嗤。"]'),
('f5b62b78-dcc3-4e30-8379-63839435d906','題瑞巖','王十朋','宋','宋诗','song-poetry','','[]','雁蕩看不足，瑞巖游更貪。',48,'全唐诗/poet.song.118000.json','["雁蕩看不足，瑞巖游更貪。", "鬭奇雖有媿，藴秀了無慙。", "澗古水鳴玉，寺幽山染藍。", "怱怱一宿去，未暇問三三。"]'),
('8e5a083b-2e50-4baf-a7b1-faa61e6c184f','題天台國清寺','王十朋','宋','宋诗','song-poetry','','[]','十里松聲接澗泉，清音入耳夜無眠。',64,'全唐诗/poet.song.118000.json','["十里松聲接澗泉，清音入耳夜無眠。", "宜於四絕中稱絕，誰向三賢後更賢。", "寺就已無陳日月，時清長是宋山川。", "明朝杖屨尋劉阮，不待桃花入洞天。"]'),
('0650bcec-cf84-458f-b5cc-5d97467ecc2f','題大慈寺','王十朋','宋','宋诗','song-poetry','','[]','巍嶺迢迢入翠微，梵宮佛隴鎖烟霏。',32,'全唐诗/poet.song.118000.json','["巍嶺迢迢入翠微，梵宮佛隴鎖烟霏。", "斷碑古寺曾經眼，剛笑陳隋徃事非。"]'),
('5a8adae0-9c12-4a87-8931-c0bbec9a03a8','題石橋二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','路隔仙凡意可通，石橋容我踏長虹。',32,'全唐诗/poet.song.118000.json','["路隔仙凡意可通，石橋容我踏長虹。", "橋旁方廣人游久，不在登臨杖屨中。"]'),
('6a8e27d0-9eea-4310-9b8e-73fbd5268adb','題石橋二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','石橋未到已先知，入眼端如入夢時。',32,'全唐诗/poet.song.118000.json','["石橋未到已先知，入眼端如入夢時。", "僧喚我爲嚴首坐，前生曾寫此橋碑。"]'),
('798fbbe9-6579-4d92-bc8b-7e4542bba497','萬年贈鄉僧賁老  其一','王十朋','宋','宋诗','song-poetry','','[]','夢魂驚斷石橋邊，身带烟霞入萬年。',32,'全唐诗/poet.song.118000.json','["夢魂驚斷石橋邊，身带烟霞入萬年。", "賓主相逢意良厚，永嘉縫掖永嘉禪。"]'),
('fa065082-780c-44d2-81f1-a27443b81c13','萬年贈鄉僧賁老  其二','王十朋','宋','宋诗','song-poetry','','[]','學通儒釋浩無邊，江浙聲名二十年。',32,'全唐诗/poet.song.118000.json','["學通儒釋浩無邊，江浙聲名二十年。", "見說胸中有論語，欲從師向此參禪。"]'),
('b793d3bd-cb6a-4ee5-9ccd-fa79b5366862','過鑑湖','王十朋','宋','宋诗','song-poetry','','[]','朔風吹水鑑湖寒，千里扁舟赴幕官。',32,'全唐诗/poet.song.118000.json','["朔風吹水鑑湖寒，千里扁舟赴幕官。", "路入蓬萊天尺五，眼中見日與長安。"]'),
('988d0299-29eb-41da-a418-c5fcbf3a0b35','民事堂','王十朋','宋','宋诗','song-poetry','','[]','親擢深蒙聖主恩，宜知民事訓詞溫。',64,'全唐诗/poet.song.118000.json','["親擢深蒙聖主恩，宜知民事訓詞溫。", "仰惟睿意思邦本，要使書生識治原。", "不憚勤勞馳禹會，敢忘精白奉堯言。", "它時上問蒼生事，願竭孤忠慷慨論。"]'),
('14995a6b-2d25-4e15-a0d8-ec700758a364','臘月望日出郊探春游告成觀謁大禹祠酌菲飲泉遂至龍瑞宮觀禹穴薄暮而還','王十朋','宋','宋诗','song-poetry','','[]','禹葬稽山不記年，丹青落盡廟依然。',64,'全唐诗/poet.song.118000.json','["禹葬稽山不記年，丹青落盡廟依然。", "神文秘在藏書穴，儉德流爲菲飲泉。", "龍瑞峯巒高近日，鑑湖烟水闊浮天。", "東州佳處畧經眼，自笑好奇如馬遷。"]'),
('9a7a460e-2dfd-452b-ad6c-1779673e1d94','采蕺  其一','王十朋','宋','宋诗','song-poetry','','[]','陟彼越山，言采其蕺。',40,'全唐诗/poet.song.118000.json','["陟彼越山，言采其蕺。", "我思古人，中心悒悒。", "維國有耻，吳弗遑粒。", "膽于坐隅，霸勳以集。"]'),
('1d15453f-0c02-467e-8a59-a24b72c30f75','采蕺  其二','王十朋','宋','宋诗','song-poetry','','[]','陟彼越山，言采其茗。',40,'全唐诗/poet.song.118000.json','["陟彼越山，言采其茗。", "我思古人，中心炳炳。", "維國有耻，夕弗遑瞑。", "焦心以思，沼吳之境。"]'),
('1d805f8c-157f-4ad5-a494-d8862a176be2','采蕺  其三','王十朋','宋','宋诗','song-poetry','','[]','厥草匪甘，厥蔬匪香。',40,'全唐诗/poet.song.118000.json','["厥草匪甘，厥蔬匪香。", "維其味之，豈曰嗜之。", "心焉孔焦，膽焉亟嘗。", "唯其苦之，是以取之。"]'),
('cee66dad-72e6-4b94-8524-7216dfd9d21b','采蕺  其四','王十朋','宋','宋诗','song-poetry','','[]','我陟高崗，瞻望東越。',40,'全唐诗/poet.song.118000.json','["我陟高崗，瞻望東越。", "訪王之祀，曠古有闕。", "宜廟于山，世享不絕。", "何以薦之，蕺茗是擷。"]'),
('9e1a510b-6fc4-45ad-9c99-ce7c978a52f5','秦望','王十朋','宋','宋诗','song-poetry','','[]','瞻彼秦望，崇于會稽。',202,'全唐诗/poet.song.118000.json','["瞻彼秦望，崇于會稽。", "曷云其崇，登焉而紫。", "孰登是山，西方之人兮。", "瞻彼秦望，輕于會稽。", "曷崇而輕，名之以嬴。", "孰名是山，東方之人兮。", "我登稽山，思禹之績。", "吾儕不魚，繄帝之力。", "我瞻秦望，哀秦之過。", "虐彼黔首，其誰之禍。", "禹駕而游，夏民以休。", "有翼其行，稷卨是謀。", "政轍而狩，嬴隨以仆。", "孰稔其惡，斯高左右。", "孤竹兄弟，殍于首陽。", "山與其人，嘉名孔章。", "谿辱以愚，泉汚以盜。", "物之不幸，名惡而暴。", "浙濤如銀，鑑流如紳。", "濯彼崔嵬，勿汚以秦。"]'),
('c1264a5b-0838-48cc-a2f2-af26fc06df19','迎春遇雪','王十朋','宋','宋诗','song-poetry','','[]','飛雪送殘臘，带花迎早春。',24,'全唐诗/poet.song.118000.json','["飛雪送殘臘，带花迎早春。", "西疇農事及，媿是不耕人。"]'),
('0d27561a-86b9-45b6-8194-85528a196772','元日冒雪赴天慶觀朝拜既趨府拜表還舍飲屠蘇酒因思去年元日亦不在家感而有作','王十朋','宋','宋诗','song-poetry','','[]','幕府初官媿不才，琳宮朝拜獲參陪。',64,'全唐诗/poet.song.118000.json','["幕府初官媿不才，琳宮朝拜獲參陪。", "籃輿去踏攙先雪，蓬鬢歸銜最後杯。", "禹穴地幽寒未歇，堯天日近暖先回。", "年年元日身爲客，孤負吾廬溪上梅。"]'),
('5cb7790d-5f3d-435b-a739-00689317d595','賀何正言用蔡君謨韵','王十朋','宋','宋诗','song-poetry','','[]','御筆親除真諫官，翕然輿論已騰歡。',64,'全唐诗/poet.song.118000.json','["御筆親除真諫官，翕然輿論已騰歡。", "正人得路言無諱，聖主虛懷聽不難。", "莫厭封章箴衮闕，要令奸膽落毫端。", "鯫生雅服陽公德，時把昌黎諫論看。"]'),
('7590bb70-a6e1-4afe-8e35-1ea4b5bf8252','寓小能仁寺即事書懷','王十朋','宋','宋诗','song-poetry','','[]','小國青徑梅溪老，綠水紅蓮越幕賓。',64,'全唐诗/poet.song.118000.json','["小國青徑梅溪老，綠水紅蓮越幕賓。", "藥裹隨身多半夏，花枝照眼只常春。", "郡樓鼓角聽殊遠，僧舍鍾魚聞已頻。", "窗外清風數竿竹，澹然相對浄無塵。"]'),
('61e6d894-89fa-4045-b873-c8fbf2319a50','同莫教授朱縣丞朱司理游西園','王十朋','宋','宋诗','song-poetry','','[]','黎明出城郭，偶作西園游。',72,'全唐诗/poet.song.118000.json','["黎明出城郭，偶作西園游。", "春淺花未都，池寒綠初抽。", "湖山欲縱目，烟靄浮不收。", "初來興非淺，心賞殊未酬。", "頼有三君子，清談洗牢愁。", "更期春色濃，携樽泛仙舟。"]'),
('f5dc8e29-7523-4483-a1b4-572a74629059','次韵濮十太尉賞梅','王十朋','宋','宋诗','song-poetry','','[]','春向群芳頂上來，可人風味亦奇哉。',64,'全唐诗/poet.song.118000.json','["春向群芳頂上來，可人風味亦奇哉。", "未於茅舍踈籬見，先爲金枝玉葉開。", "竹外橫斜纔數點，笛中摇落已千堆。", "因公撩我惜花意，深憶去年湖上杯。"]'),
('4ec70774-9476-4db4-9b9d-ae22f4c36839','題壽樂堂用東坡韵贈楊元賓僉判','王十朋','宋','宋诗','song-poetry','','[]','蓬萊閣下蒼龍古，萬壑千巖擁仙府。',160,'全唐诗/poet.song.118000.json','["蓬萊閣下蒼龍古，萬壑千巖擁仙府。", "壽樂堂西面卧龍，壑月巖風滿窗戶。", "蒼松溜雨大十圍，綠水浮荷深一股。", "作堂主人久黄壤，仁智風猶似鄒魯。", "詩仙騎龍已上天，妙句光芒照寰宇。", "青山偃蹇只如昔，高處去天無尺五。", "楊侯淮泗老儒學，文字撐腸筆風雨。", "朅來贊幕古東州，要與青山作盟主。", "虛堂宴坐飽風月，此外一毫端不取。", "它日從公物外游，貝闕珠宮酌瓊乳。"]'),
('a8f94795-2d81-420c-98aa-f6cdde937cf4','元賓贈紅梅數枝','王十朋','宋','宋诗','song-poetry','','[]','江梅孤潔太絕俗，紅杏酣酣風味薄。',64,'全唐诗/poet.song.118000.json','["江梅孤潔太絕俗，紅杏酣酣風味薄。", "梅花精神杏花色，春入蓮洲初破蕚。", "膽瓶分贈兩三枝，醒我沉痾不須藥。", "願公及早辦芳樽，酒暈冰肌易銷落。"]'),
('abaccd38-2f6c-42e3-8dfd-1b0b2459bfa8','廨舍有脩竹數竿瀟洒可愛','王十朋','宋','宋诗','song-poetry','','[]','誰栽窗外碧琅玕，瀟灑尤宜老眼看。',32,'全唐诗/poet.song.118000.json','["誰栽窗外碧琅玕，瀟灑尤宜老眼看。", "寄語後人毋翦伐，更須時爲報平安。"]'),
('416a7b67-fde7-4041-976c-c43b61444bcd','龍瑞道士贈蘭','王十朋','宋','宋诗','song-poetry','','[]','有客贈芳友，滿堂聞國香。',48,'全唐诗/poet.song.118000.json','["有客贈芳友，滿堂聞國香。", "清含道流氣，輕带羽衣黄。", "綴佩風光別，橫琴旨趣長。", "重須尋禹穴，一曲聽揚揚。"]'),
('ea67b01f-2df4-420d-b989-68d65a0f9f93','吳秀才以壽樂蓮洲中千葉梅花爲贈酬以詩','王十朋','宋','宋诗','song-poetry','','[]','東君次第染群芳，更與南枝別樣粧。',64,'全唐诗/poet.song.118000.json','["東君次第染群芳，更與南枝別樣粧。", "水漲春洲浮鴨綠，日烘花臉带鵝黄。", "雪中瓊蘂不多辦，酒後玉肌無此香。", "玉潤冰清總佳士，驛筒相繼贈春光。"]'),
('a806d8fb-5963-4844-b9c7-c38cf5ddc545','上丁釋奠備數獻官書十二韵呈莫子齊教授趙可大察推','王十朋','宋','宋诗','song-poetry','','[]','魯人呼東家，陳蔡不火食。',144,'全唐诗/poet.song.118000.json','["魯人呼東家，陳蔡不火食。", "當時雖高第，往往亦慍色。", "孰知夢奠後，廟祀亙無極。", "嵬然衮冕尊，王侯面俱北。", "武成祭上戊，龍棄配社稷。", "隆殺良不同，論功豈如德。", "去載游上庠，觀禮杏壇側。", "備樂閲九奏，銀袍爛千億。", "茲焉客蓮幕，濫與俎豆職。", "登階瞻睿容，炳睟若親識。", "壯哉芹藻宮，不減魯侯國。", "歸賡泮水頌，才劣慙史克。"]'),
('52814771-d8ae-4661-b527-4108740aa9e6','會稽三賢祠詩 吳先生祠','王十朋','宋','宋诗','song-poetry','','[]','安定先生賢矣哉，一時高第俱英材。',198,'全唐诗/poet.song.118000.json','["安定先生賢矣哉，一時高第俱英材。", "詵然達者播廊廟，貧賤亦足光蓬萊。", "會稽吳君更超絕，至今士子猶能說。", "講堂鳴鼓規使君，可使清風聳朝烈。", "求田問舍遺子孫，錢愚地僻何紛紛。", "不惜池塘種芹藥，一段奇事前無聞。", "君不見唐室蓬山稱賀老，乞得鑑湖歸去好。", "却將儒服變流沙，更遣門闌亦歸道。", "又不見晉朝名士高陽公，才名上下王謝中。", "乃心欲出三界外，山陰宅化瞿曇宮。", "先生識見高流俗，不作二公緣禍福。", "寄語多才鄭廣文，乞與毫端記高躅。"]'),
('e20fd026-bcbf-4be9-96f0-de2785ce8038','會稽三賢祠詩 旌忠廟','王十朋','宋','宋诗','song-poetry','','[]','國家徃徃艱難中，搢紳節義掃地空。',168,'全唐诗/poet.song.118000.json','["國家徃徃艱難中，搢紳節義掃地空。", "靖康有一忠愍公，建炎獨有唐侯忠。", "唐侯爵位何曾隆，身居行伍儕羆熊。", "平生經史漫不通，嚴霜烈日藴在衷。", "憤然一奮不顧躬，太尉奪笏嗟怱怱。", "子房鐵椎計已窮，張巡就縛氣尚雄。", "杲卿鋸解駡未終，忠血義肉塗地紅。", "烈氣英魂薄蒼穹，事驚朝野聞帝聰。", "立廟旌忠浙江東，睢陽雙廟同高風。", "名書青史等岱崧，當時開門誰納戎，貽臭千古如蛆蟲。"]'),
('55a3617a-0c3c-42e4-8117-ff5fcd005616','會稽三賢祠詩 愍孝廟','王十朋','宋','宋诗','song-poetry','','[]','我昔嘗讀黄絹碑，長歎越國無男兒。',272,'全唐诗/poet.song.118000.json','["我昔嘗讀黄絹碑，長歎越國無男兒。", "孰知種山山下水，千載有此一段奇。", "嗚呼哀哉蔡孝子，風烈遠過恢與覊。", "乃翁白首困縲絏，半年不脫兒心悲。", "請身荷械代父罪，或甘黥涅居軍麾。", "况遇兵興擊叛卒，身先矢石死不辭。", "當時非無賢太守，孝子抱志終不施。", "人間無路可赴訴，投命河伯祈天知。", "自爲銘誌及訟牒，欲愬以魂贖以屍。", "精哀意切語不怨，孝與忠厚俱天資。", "臨河更效結纓死，顛沛於禮曾無虧。", "父脫纍囚子願畢，身在九泉甘若飴。", "名聞九重獲旌表，賜廟愍孝風華夷。", "胡爲祠宇乃如許，一間破屋河之湄。", "未聞設誄有度尚，絕妙更欠邯鄲詞。", "我來贊幕欽孝烈，顧瞻廟貎成吁嘻。", "他年太史作佳傳，願於紙尾書吾詩。"]'),
('3b2041be-61c2-40aa-8d4a-be2e960c5b22','某比緣職事朝拜殯宮瞻望松柏愴然悲涕遂成小詩','王十朋','宋','宋诗','song-poetry','','[]','崇觀升平主，神游在九霄。',48,'全唐诗/poet.song.118000.json','["崇觀升平主，神游在九霄。", "稽山嗟葬禹，寰海痛思堯。", "天上仙宮別，人間寶祚遥。", "微臣望松柏，魂思黯然銷。"]'),
('eb726597-37a7-4985-a5b2-58f59496dde1','鑑湖行','王十朋','宋','宋诗','song-poetry','','[]','蒼蒼凉凉紅日生，葱葱鬰鬰佳氣橫。',160,'全唐诗/poet.song.118000.json','["蒼蒼凉凉紅日生，葱葱鬰鬰佳氣橫。", "鑑湖春色三百里，桃花水漲扁舟行。", "花間啼鳥傳春意，聲落行舟驚夢寐。", "胡牀兀坐心境清，轉覓湖山有風味。", "鑑中風物幾經春，身在鑑中思古人。", "禹迹茫茫千載後，疏鑿功歸馬太守。", "太守湖成坐鬼責，後代風流屬狂客。", "狂客不長家鑑湖，惟有漁人至今得。", "日暮東風吹棹回，花枝照眼入蓬萊。", "回首湖山何處是，欵乃聲中畫圖裏。"]'),
('a1462baf-7d6e-4d97-b524-633264536f52','禹廟歌','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君不見蜂目英雄吞四海，血祀初期千萬載。',313,'全唐诗/poet.song.118000.json','["君不見蜂目英雄吞四海，血祀初期千萬載。", "稽山木像棄長江，逆泝波濤鬼無餒。", "鳥喙辛勤十九年，平吳覇越世稱賢。", "故國無人念遺烈，山間廟貌何凄然。", "馬守開湖利源迥，歲沃黄雲九千頃。", "年來遺迹半湮蕪，廟鎖湖邊篆烟冷。", "吳越國王三節還，盡將錦綉裹江山。", "自從王氣熄牛斗，廟比昭王屋一間。", "迺知流光由德厚，祀典誰能如夏后。", "九年洪水滔天流，下民昏墊堯心憂。", "帝懼萬國生魚頭，錫禹洪範定九州。", "功成執玉朝冕旒，奔走訟獄歸歌謳。", "南巡會稽覲諸侯，書藏䰠穴千丈幽。", "蟬脫塵寰不肯留，千古靈廟依松楸。", "吾皇盛德與禹侔，菲食卑宮惡衣裘。", "思禹舊績祀事脩，小臣效職躬薦羞。", "仰瞻黻冕懷遠猷，退惜分陰慙惰偷。", "嗟乎越山高兮可夷而丘，鑑湖深兮可理而疇。", "惟有禹貢聲名長不朽，告成世祀無時休。"]'),
('f93620bb-0d86-4203-ab99-f7c83fce59ab','與趙安撫乞疏獄','王十朋','宋','宋诗','song-poetry','','[]','小麥青青大麥熟，秧老欲移蠶欲簇。',176,'全唐诗/poet.song.118000.json','["小麥青青大麥熟，秧老欲移蠶欲簇。", "皇天彌旬作淫雨，害及農桑一何酷。", "麥枯秧腐蠶不絲，無食無衣豈能育。", "使君今世賢方伯，政過龔黄同舜牧。", "僦金蠲放官與私，喜氣歡聲傾比屋。", "仁風已慰黎庶心，誠感蒼穹理宜速。", "胡爲烝泄尚如許，陰沴干陽埋日轂。", "豈惟泥濘困牛車，更恐魚龍上平陸。", "閭閻競畫指日蠻，香火遥祈上天竺。", "傷和無乃有冤民，蠹政尚疑多大族。", "使君有術開青天，按劾奸贓疏滯獄。"]'),
('fb4e6ece-99ee-46bf-a757-d5b8c5e126fb','次韵濮十太尉詠知宗牡丹七絕  其一','王十朋','宋','宋诗','song-poetry','','[]','憶昔洛陽花盛日，品第况逢歐六一。',32,'全唐诗/poet.song.118000.json','["憶昔洛陽花盛日，品第况逢歐六一。", "姚黄一品價無雙，更有左花千葉密。"]'),
('e2e0fc44-d9e5-42cf-9ccc-020723215403','次韵濮十太尉詠知宗牡丹七絕  其二','王十朋','宋','宋诗','song-poetry','','[]','月陂春色滿花枝，國色天香照雪肌。',32,'全唐诗/poet.song.118000.json','["月陂春色滿花枝，國色天香照雪肌。", "當日栽陪恐無地，如今誰保舊園池。"]'),
('9aacd6de-0ebc-4c42-b5ef-c7e70c077042','次韵濮十太尉詠知宗牡丹七絕  其三','王十朋','宋','宋诗','song-poetry','','[]','開元往事感傷中，遺種猶餘一擫紅。',32,'全唐诗/poet.song.118000.json','["開元往事感傷中，遺種猶餘一擫紅。", "借問通宵配妃子，何如及早念姚崇。"]'),
('33c1d658-1963-4e9f-84ec-d8b4dd64e13e','次韵濮十太尉詠知宗牡丹七絕  其四','王十朋','宋','宋诗','song-poetry','','[]','春色遥興洛陽念，風俗聊於記中驗。',32,'全唐诗/poet.song.118000.json','["春色遥興洛陽念，風俗聊於記中驗。", "今日苧羅山下魂，猶向人間吐妖艷。"]'),
('cbf8e750-21d9-43a2-a8a6-b21738a7ebd7','次韵濮十太尉詠知宗牡丹七絕  其五','王十朋','宋','宋诗','song-poetry','','[]','地近堯天饒雨露，花王窈窕多風度。',32,'全唐诗/poet.song.118000.json','["地近堯天饒雨露，花王窈窕多風度。", "書生不辦買花錢，空解摇毫爲花賦。"]'),
('ea39b30d-e8a3-41da-b27d-58370b54bbac','次韵濮十太尉詠知宗牡丹七絕  其六','王十朋','宋','宋诗','song-poetry','','[]','香苞初拆曉霞凝，甲第名園冠紹興。',32,'全唐诗/poet.song.118000.json','["香苞初拆曉霞凝，甲第名園冠紹興。", "玉葉金枝老詩伯，更將好語爲褒稱。"]'),
('ee02ee57-8939-4a6f-a6b1-df2279e68e77','次韵濮十太尉詠知宗牡丹七絕  其七','王十朋','宋','宋诗','song-poetry','','[]','造化無私處處芳，家山想見亦春藏。',32,'全唐诗/poet.song.118000.json','["造化無私處處芳，家山想見亦春藏。", "無端竊祿身爲客，孤負吾廬十八香。"]'),
('e1319189-3b01-4e23-b6a3-aa538631f013','送僧游徑山','王十朋','宋','宋诗','song-poetry','','[]','潛澗家風不蕪沒，禪講詵詵盡瓜葛。',96,'全唐诗/poet.song.118000.json','["潛澗家風不蕪沒，禪講詵詵盡瓜葛。", "如今更有奇兒孫，雲水飄然繼衣鉢。", "徑山禪伯僧中龍，向來名節真無雙。", "我昔題詩已推許，兩度相逢不曾語。", "子今此行真得師，掃除妄想叩深機。", "我待衣冠掛林下，遲子歸來話瀟洒。"]'),
('8fc049be-c5a6-49be-8158-7bfd2cac4ac2','三月晦日邵憲宴僚屬于西園某與焉趙提幹即席賦詩次韵','王十朋','宋','宋诗','song-poetry','','[]','送春開宴種山西，翠幄重重眼界迷。',64,'全唐诗/poet.song.118000.json','["送春開宴種山西，翠幄重重眼界迷。", "一段清和人共物，十分幽勝地臨溪。", "鴛鴻曲水閣中集，鶑燕落花枝上啼。", "賢榻獲陪文字飲，不嫌蹤跡間雲泥。"]'),
('62ddc329-d3bd-470f-b762-a95f8fea5942','送昌齡弟還鄉兼簡夢齡','王十朋','宋','宋诗','song-poetry','','[]','束書千里赴王畿，戰藝賢關事偶違。',64,'全唐诗/poet.song.118000.json','["束書千里赴王畿，戰藝賢關事偶違。", "鑑水天高鴻雁集，左原山遠鶺鴒啼。", "夜牀風雨客情惡，春草池塘詩思飛。", "勉力還家對燈火，待看雙桂擢秋闈。"]'),
('abd39994-bff2-4722-acf6-dba9bb4e25b9','糶米行','王十朋','宋','宋诗','song-poetry','','[]','詔書發廩周饑荒，使君減價糶黄粱。',88,'全唐诗/poet.song.118000.json','["詔書發廩周饑荒，使君減價糶黄粱。", "奉行上意固已良，小人用心胡不臧。", "斗米大半雜以糠，橫索民錢名貼量。", "怨語嗷嗷盈道傍，我慙寸祿偷太倉。", "見之不言咎誰當，言之人指爲輕狂，作詩聊語同舍郎。"]'),
('85b8a1d0-80d8-46a1-9714-e85caada1d5e','送會稽林簿棄官還鄉','王十朋','宋','宋诗','song-poetry','','[]','望秦秦望山蒼蒼，未秋先作歸意濃。',96,'全唐诗/poet.song.118000.json','["望秦秦望山蒼蒼，未秋先作歸意濃。", "三山深處孟園好，松菊恨君歸不早。", "拂衣高舉追冥鴻，不將詩別乖崖翁。", "年來處士徑尤捷，美秩清資等閑躐。", "君獨高歌慕隠淪，林下何曾見一人。", "芋魁豆飯吾亦有，深愧折腰貪五斗。"]'),
('297cf456-2620-4ce2-9c28-639b3c1ddf0f','戊辰歲嘗和韓退之贈張徹詩寄曹夢良至今十年夢良方和以寄因贈一絕','王十朋','宋','宋诗','song-poetry','','[]','欲識交情久遠期，十年方和和韓詩。',32,'全唐诗/poet.song.118000.json','["欲識交情久遠期，十年方和和韓詩。", "他時更踐詩中語，偕隠谿山不可遲。"]'),
('1389dc73-10ef-47e5-b232-580d68d3e888','送趙可大如浙西','王十朋','宋','宋诗','song-poetry','','[]','幕府游從盛一時，之人襟宇更瑰奇。',32,'全唐诗/poet.song.118000.json','["幕府游從盛一時，之人襟宇更瑰奇。", "西風莫作鱸蓴戀，越國江山日要詩。"]'),
('09616c3a-8aa9-4368-8b4f-b593cbb78782','中秋賞月蓬萊閣呈同官','王十朋','宋','宋诗','song-poetry','','[]','中秋翫月小蓬萊，風送嬋娟入座來。',64,'全唐诗/poet.song.118000.json','["中秋翫月小蓬萊，風送嬋娟入座來。", "樽俎論文清有味，湖山照眼凈無埃。", "雲生脚底蛟龍卧，影落人間鼓角催。", "把酒問天兼問月，何時此夜更銜盃。"]'),
('b594deb2-50b7-4f53-8df0-6e795688cd4c','中秋見月方以爲喜既而陰蔽意殊不滿東坡云良天佳月即中秋不以日月斷也諸君有醵會之約復用前韵','王十朋','宋','宋诗','song-poetry','','[]','中秋翫月小蓬萊，雲掩清光不放來。',64,'全唐诗/poet.song.118000.json','["中秋翫月小蓬萊，雲掩清光不放來。", "頗覺襟懷增梗槩，欲凭欄檻掃氛埃。", "清宵忍放嘉賓散，明日還驚俗務催。", "底用區區校時節，良天佳月即傾杯。"]'),
('e611350e-1f62-4e5a-b345-49fded89ba11','記夢','王十朋','宋','宋诗','song-poetry','','[]','夜夢隨先君，梅溪策黎杖。',48,'全唐诗/poet.song.118000.json','["夜夢隨先君，梅溪策黎杖。", "杉徑早開闢，歸休預標榜。", "魂思驚曉醒，精神發秋爽。", "披衣照孤燈，洒涕書惚怳。"]'),
('3eddf739-9276-44c3-96e8-f5eaf505b799','士人僧道俱贈巖桂','王十朋','宋','宋诗','song-poetry','','[]','巖桂來三家，清標共秋風。',48,'全唐诗/poet.song.118000.json','["巖桂來三家，清標共秋風。", "聯芳近禹穴，擢秀疑蟾宮。", "膽瓶金粟妍，鼻觀天香通。", "無心妄區別，妙契將無同。"]'),
('3c1857ad-183b-4cce-be8b-035465791bd6','府吏有以老求退者詢其年猶未六十詰其去之由云欲全身避禍耳予善其知機勇退可以媿嗜進之士夫有感而作','王十朋','宋','宋诗','song-poetry','','[]','升高蝜蝂墮，粘壁蝸牛枯。',48,'全唐诗/poet.song.118000.json','["升高蝜蝂墮，粘壁蝸牛枯。", "搢紳鴆粱肉，是亦蝸蝜徒。", "抽身箠楚中，勇退媿此胥。", "衣冠與刀筆，未可分賢愚。"]'),
('64d32cba-7772-4e45-810e-fc8683e65623','觀習水勝','王十朋','宋','宋诗','song-poetry','','[]','漢武英雄思拓邊，昆明習戰遺風傳。',64,'全唐诗/poet.song.118000.json','["漢武英雄思拓邊，昆明習戰遺風傳。", "吾皇仁心異武帝，思患姑爲預防計。", "爾曹生長行伍間，操舟習水便宜閑。", "異日捐軀宜報國，勿效水烏爲盜賊。"]'),
('c0b128de-685c-48fe-9e39-a0f7f7a4ce38','龍瑞道士贈巖桂','王十朋','宋','宋诗','song-poetry','','[]','巖桂遥從禹穴來，天香全似月宮栽。',32,'全唐诗/poet.song.118000.json','["巖桂遥從禹穴來，天香全似月宮栽。", "金風凄峭飄龍腦，想見吾廬爛熳開。"]'),
('475bb66b-3f5b-4e6b-8263-e73c70cb88d7','九日登蕺山','王十朋','宋','宋诗','song-poetry','','[]','九日同登古蕺山，眼明天濶興清閑。',64,'全唐诗/poet.song.118000.json','["九日同登古蕺山，眼明天濶興清閑。", "杯傳但覺歡無盡，帽落俄驚鬢已斑。", "鄉思遥馳三徑裏，秋聲近在八松間。", "茱萸未許陪朝士，頼有清流數徃還。"]'),
('2d788e45-f376-40e6-90f0-dc50de7ac117','夢齡九日有詩兼懷昌齡次韵','王十朋','宋','宋诗','song-poetry','','[]','長記去年今日好，門外秋香噴沉腦。',128,'全唐诗/poet.song.118000.json','["長記去年今日好，門外秋香噴沉腦。", "弟兄隣里同登高，把菊行觴樂非少。", "山殽海錯鄉味佳，銀瓶索酒不用賒。", "醉中不記脫巾卧，明日頭上猶黄花。", "今年豈不欲行樂，竊祿東州官事束。", "那堪送酒無白衣，旋糶黄粱買桑落。", "何如與子俱休休，誰能長抱離鄉憂。", "移書問訊惠連弟，三徑許我歸來不。"]'),
('77e011b0-b215-4ed7-8862-08ad4d86266b','贈莊童子','王十朋','宋','宋诗','song-poetry','','[]','日誦千言七歲兒，方員動靜早能知。',32,'全唐诗/poet.song.118000.json','["日誦千言七歲兒，方員動靜早能知。", "還家更讀韓公序，器業他年必大奇。"]'),
('9319165e-a66f-4c54-8c75-9b7f85790d75','送朱丞','王十朋','宋','宋诗','song-poetry','','[]','一片秋懷似亂雲，不堪行客話離群。',64,'全唐诗/poet.song.118000.json','["一片秋懷似亂雲，不堪行客話離群。", "紅蓮綠水尚留我，鉅竹老槐深憶君。", "千里從今遥共月，一樽何日更論文。", "好將平昔家傳學，勉力登朝立世勳。"]'),
('05e07cb9-92c9-412c-82ab-1193fa7dc9b3','贈夢齡兼懷昌齡','王十朋','宋','宋诗','song-poetry','','[]','我緣竊祿寓東州，子亦相從千里游。',64,'全唐诗/poet.song.118000.json','["我緣竊祿寓東州，子亦相從千里游。", "鐵硯功名壯心在，短檠燈火夜窗幽。", "治書晁錯宜登第，射策公孫定取侯。", "他日三人老兄弟，結廬相共保松楸。"]'),
('f6576c61-494b-4ff0-97cc-155aba9cf908','和夢齡十月朔日書懷','王十朋','宋','宋诗','song-poetry','','[]','歲事遽如許，玄冥威欲伸。',48,'全唐诗/poet.song.118000.json','["歲事遽如許，玄冥威欲伸。", "地爐猶未火，客坐况無茵。", "日短驚瞻昴，天寒怯報寅。", "尤憐對牀弟，尚與短檠親。"]'),
('29c141fb-c445-494c-9627-22c4cea2fc69','贈喻叔奇縣尉','王十朋','宋','宋诗','song-poetry','','[]','同舍同年友，天資迥不群。',36,'全唐诗/poet.song.118000.json','["同舍同年友，天資迥不群。", "詩文侵晉宋，兄弟類機雲。", "梅市訪仙侶，蘭亭懷右軍。"]'),
('fd24ef21-8add-4fed-acb6-b9ef73fdc166','贈王吉老縣尉','王十朋','宋','宋诗','song-poetry','','[]','臣子大節孝與忠，父母仇讎天不同。',166,'全唐诗/poet.song.118000.json','["臣子大節孝與忠，父母仇讎天不同。", "賢哉會稽王孝子，感槩有古烈士風。", "松楸一夕盜破冢，親獲鼠輩聞之公。", "有司守法貸其命，孝子銜恨無終窮。", "誰謂書生膽如許，貌若尫羸中甚武。", "手斬凶人提髑髏，請死申冤詣公府。", "君不見齊襄內行世所羞，春秋賢之緣復讐。", "又不見子胥鞭屍報父怨，太史爲之作佳傳。", "君今枕戈志已伸，更須移孝爲忠臣。", "他年當作傅介子，誓斬樓蘭雪國耻。"]'),
('c07e6086-a119-4933-a643-583d7ad1c6b2','十月望日買菊一株頗佳  其一','王十朋','宋','宋诗','song-poetry','','[]','秋去菊方好，天寒花自香。',24,'全唐诗/poet.song.118000.json','["秋去菊方好，天寒花自香。", "深懷傲霜意，那肯媚重陽。"]'),
('7d864104-b5bf-44db-a679-362a9832bf4d','十月望日買菊一株頗佳  其二','王十朋','宋','宋诗','song-poetry','','[]','菊晚不害好，固宜登我堂。',24,'全唐诗/poet.song.118000.json','["菊晚不害好，固宜登我堂。", "書生自頭白，奚用泣馨香。"]'),
('a8bae861-ea23-4639-90dc-60db775fdefd','聞詩生日','王十朋','宋','宋诗','song-poetry','','[]','良天逢十月，嘉節過三元。',72,'全唐诗/poet.song.118000.json','["良天逢十月，嘉節過三元。", "汝父初生子，吾親喜抱孫。", "長成今若許，氣習有餘溫。", "雁序自相友，麟經可與言。", "志宜存遠大，學必探淵源。", "但務勤修德，年齡不用論。"]'),
('c80e2e3a-09c5-47f4-b9de-e7a8328a92e8','十月十六日欲與夢齡弟及聞詩聞禮同游蘭亭仍約喻叔奇偕行會天氣不佳喻亦以疾辭出門而止兀坐終日懷抱殊惡','王十朋','宋','宋诗','song-poetry','','[]','我欲游蘭亭，天氣殊不佳。',48,'全唐诗/poet.song.118000.json','["我欲游蘭亭，天氣殊不佳。", "同行感微恙，杖屨不可偕。", "出門興遽闌，茲游竟未諧。", "遺文閲永和，聊用慰此懷。"]'),
('7f6ff2c4-17fc-405f-992f-571057bf27e8','和喻叔奇集蘭亭序語四絕  其一','王十朋','宋','宋诗','song-poetry','','[]','我自扁舟入越初，蘭亭已向夢中如。',32,'全唐诗/poet.song.118000.json','["我自扁舟入越初，蘭亭已向夢中如。", "崇山峻嶺至今阻，唱和詩成無處書。"]'),
('8872f7f8-5a22-46f2-a3b5-8a499fdb4798','和喻叔奇集蘭亭序語四絕  其二','王十朋','宋','宋诗','song-poetry','','[]','群賢少長畢經過，曲水流觴憶永和。',32,'全唐诗/poet.song.118000.json','["群賢少長畢經過，曲水流觴憶永和。", "一代風流已陳迹，世殊事異感傷多。"]'),
('df61e2c2-b1ed-4ee4-a815-149666f3de86','和喻叔奇集蘭亭序語四絕  其三','王十朋','宋','宋诗','song-poetry','','[]','晤言一室許誰親，相過無非我輩人。',32,'全唐诗/poet.song.118000.json','["晤言一室許誰親，相過無非我輩人。", "放浪形骸嗟老矣，仰觀宇宙尚艱辛。"]'),
('31b4094a-ebd1-42a0-a806-2cdf783bc9a7','和喻叔奇集蘭亭序語四絕  其四','王十朋','宋','宋诗','song-poetry','','[]','茂林脩竹未成徃，游目騁懷聊自欣。',32,'全唐诗/poet.song.118000.json','["茂林脩竹未成徃，游目騁懷聊自欣。", "暢敘幽情有齊契，一觴一詠細論文。"]'),
('b8821b59-85a9-40eb-8e70-e71b4dc608b0','和韓退之晚菊贈喻叔奇','王十朋','宋','宋诗','song-poetry','','[]','嘉菊何太晚，十月纔黄花。',48,'全唐诗/poet.song.118000.json','["嘉菊何太晚，十月纔黄花。", "既晚好何益，三嗅良可嗟。", "開日乃佳節，芳樽對年家。", "今夕苟不飲，如此黄花何。"]'),
('17fe1c75-3e1f-4591-811b-b5add953872c','夜讀書于民事堂意有所感和韓公縣齋讀書韵','王十朋','宋','宋诗','song-poetry','','[]','宦游寓幕府，幽懷屬山林。',96,'全唐诗/poet.song.118000.json','["宦游寓幕府，幽懷屬山林。", "兀坐窗几間，默求聖賢心。", "沉潛偶會意，嘆息常彌襟。", "世塗豈能騖，古道聊自斟。", "䰠穴思欲探，丹書未容尋。", "青銅每自照，白髮已見侵。", "事業浩無窮，筋力媿不任。", "丈夫固有志，寧在官與金。"]'),
('1deebbe3-dce7-42df-8b40-8e4d25fb6cf4','李資深贈古瓦硯及詩','王十朋','宋','宋诗','song-poetry','','[]','世貴銅雀硯，常患僞亂真。',132,'全唐诗/poet.song.118000.json','["世貴銅雀硯，常患僞亂真。", "千金買渴雀，虛名何足珍。", "李生心好古，身困道不貧。", "得此佳陶泓，製由萬道人。", "慇懃持贈我，器古詩清新。", "置之窗几間，日與毛穎親。", "未能草太玄，姑用注獲麟。", "羅文及端紫，貴幸無比倫。", "屈爾居蓬窗，與我同艱辛。", "研磨媚權貴，揮染勞精神。", "茲我所不敢，銘以書諸紳。"]'),
('fcd27915-0f21-4587-8e0c-e557202b155d','喻叔奇惠川墨','王十朋','宋','宋诗','song-poetry','','[]','子墨客卿來自蜀，綉川家藏尤不惡。',128,'全唐诗/poet.song.118000.json','["子墨客卿來自蜀，綉川家藏尤不惡。", "明窗研磨出珠玉，客卿於君德良渥。", "嗟予經年客蓮幕，交絕方兄澀囊橐。", "文房諸子亦蕭索，同年於予契非薄。", "特遣卿來助予學，不才拜賜心愧怍。", "客卿之意殊不樂，陶泓毛穎登臺閣。", "陳玄待詔同著作，卿從予游失所託。", "惟清惟靜惟寂寞，但有詩篇日酬酢。"]'),
('3b108382-86c6-4599-a021-cf897cba85d0','戴夫人挽詞','王十朋','宋','宋诗','song-poetry','','[]','勤儉肥家福亦肥，晚年門戶更光輝。',64,'全唐诗/poet.song.118000.json','["勤儉肥家福亦肥，晚年門戶更光輝。", "滿庭蘭玉俱藍袖，照眼雲仍盡綵衣。", "方外客携因果去，月中人折桂枝歸。", "回頭徃事夢幻影，丹旐五雲原上飛。"]'),
('75264699-5b6f-4cbe-b706-e8e12e63f897','和趙可大四絕 僧舍雨中','王十朋','宋','宋诗','song-poetry','','[]','僧居岑寂異官居，索句搜腸撚斷鬚。',32,'全唐诗/poet.song.118000.json','["僧居岑寂異官居，索句搜腸撚斷鬚。", "那更雨中思底事，夢魂歸到種山隅。"]'),
('867221f1-47d6-4d40-bd43-b95cc1fc50f4','和趙可大四絕 聞子規','王十朋','宋','宋诗','song-poetry','','[]','杜宇聲中春欲歸，少陵老淚不禁揮。',32,'全唐诗/poet.song.118000.json','["杜宇聲中春欲歸，少陵老淚不禁揮。", "與君共被浮蝸誤，不似淵明早見幾。"]'),
('c1a6d65a-0c47-49e9-9bd9-e75ff04199c7','和趙可大四絕 不寐','王十朋','宋','宋诗','song-poetry','','[]','唾手科名尚少年，無窮事業更居前。',32,'全唐诗/poet.song.118000.json','["唾手科名尚少年，無窮事業更居前。", "辛勤不寐思經意，却笑邊韶好晝眠。"]'),
('0ef9f137-adcd-4bc7-a545-41994ca1d4fa','和趙可大四絕 朝永祐陵','王十朋','宋','宋诗','song-poetry','','[]','萬壑千巖擁越岡，朝陵追念舊天王。',32,'全唐诗/poet.song.118000.json','["萬壑千巖擁越岡，朝陵追念舊天王。", "自嗟無路攀弓劍，尚忍興言及虎狼。"]'),
('35719151-4480-4f04-be9c-9c3922be2d11','送黄機宜游四明','王十朋','宋','宋诗','song-poetry','','[]','游宦東州識老成，坐間談笑欲風生。',64,'全唐诗/poet.song.118000.json','["游宦東州識老成，坐間談笑欲風生。", "人如元祐氣尤直，詩不江西語自清。", "雪棹非緣尋舊隠，夜牀端欲對難兄。", "行聞太史奏星聚，四皓聯珠臨四明。"]'),
('2d93c663-6c89-44b9-a1fa-40c534286299','盧仁及縣丞挽辭','王十朋','宋','宋诗','song-poetry','','[]','妙齡才譽冠東嘉，百戰功成暮景斜。',64,'全唐诗/poet.song.118000.json','["妙齡才譽冠東嘉，百戰功成暮景斜。", "人在盧前有慙色，禮從戴後獨名家。", "藍田美績誰能記，絳帳奇兒最可夸。", "鄉里搢紳官業冷，因公淪落倍興嗟。"]'),
('f482413d-a16e-4028-98c6-d5d7495f8cc6','贈術者','王十朋','宋','宋诗','song-poetry','','[]','枉道貴何益，正塗窮亦榮。',24,'全唐诗/poet.song.118000.json','["枉道貴何益，正塗窮亦榮。", "誰辭談義命，試問小君平。"]'),
('cc90649f-7ae3-4c51-b13b-5065e28eff50','游天衣寺','王十朋','宋','宋诗','song-poetry','','[]','拂曉籃輿出蠡城，稽山照眼鑑湖明。',64,'全唐诗/poet.song.118000.json','["拂曉籃輿出蠡城，稽山照眼鑑湖明。", "千巖深處十峯好，萬壑流中雙澗清。", "香靄噓成普賢像，風松吹作法華聲。", "靈烏不肯來城郭，長伴高僧避寵榮。"]'),
('81b52263-4ad7-4b84-9fcf-038abbfa4061','次梁尉韵','王十朋','宋','宋诗','song-poetry','','[]','探春連騎入山城，更喜梅仙亦會盟。',64,'全唐诗/poet.song.118000.json','["探春連騎入山城，更喜梅仙亦會盟。", "文字偶同吾輩飲，聖賢滿爲使君傾。", "詩逢好境天然好，山爲清流分外清。", "瀟洒宗之最年少，我慙叨預八仙名。"]'),
('3fe993be-92bd-4bf4-924c-535dd3c7577a','酬陸宰用梁尉韵','王十朋','宋','宋诗','song-poetry','','[]','收拾湖山付管城，士衡獨步張文盟。',64,'全唐诗/poet.song.118000.json','["收拾湖山付管城，士衡獨步張文盟。", "湧泉詩思逼人捷，屑玉笑談終席傾。", "天色亦緣吾輩好，路人能道長官清。", "要令巧匠鎸山骨，記取同行八士名。"]'),
('07221c74-3330-414b-b307-71d7f377e368','和喻叔奇游天衣四十韵','王十朋','宋','宋诗','song-poetry','','[]','稽山高入雲，鑑湖濶浮空。',288,'全唐诗/poet.song.118000.json','["稽山高入雲，鑑湖濶浮空。", "禹秦有餘迹，晉宋多鉅公。", "我來歲及周，夢寐懷清風。", "茲欣天氣佳，扶桑欲瞳曨。", "駕言天衣游，盍簪盡鴛鴻。", "經夕戒行李，如期集仙宮。", "聯騎出城南，行行指秦峯。", "千巖競吐秀，眼界清無窮。", "招提在何許，十里松陰濃。", "林端忽鍾磬，與客爲先容。", "群簪擁花界，雙佩鳴寒空。", "試將比天台，大畧如思豐。", "首讀邑浩碑，妙理開昏蒙。", "細觀元白詩，丘壑羅胸中。", "蕭壁尚堪面，梁薪幾經烘。", "茲宮現有相，禪客談無同。", "朝陽最嶄絕，白雲抹其胸。", "杜鵑天下無，至今映山紅。", "鷄僧始開山，道業聞清衷。", "思舉照不起，高價傾江東。", "袈裟縷黄金，宮女自針工。", "昭明親抱送，禮意何太恭。", "白馬忽渡江，臺城喪英雄。", "國破遺衣在，丹青落塵容。"]'),
('be17c343-100a-4cff-9210-1893f3add7f2','州宅','王十朋','宋','宋诗','song-poetry','','[]','鑑水稽山擁卧龍，黄堂人似坐仙宮。',32,'全唐诗/poet.song.118000.json','["鑑水稽山擁卧龍，黄堂人似坐仙宮。", "風流惟有元才子，終日賦詩屏障中。"]'),
('7206da8b-a3d2-40c6-9794-640c76488112','蓬萊閣','王十朋','宋','宋诗','song-poetry','','[]','祖龍車轍遍塵寰，只道蓬萊在海間。',32,'全唐诗/poet.song.118000.json','["祖龍車轍遍塵寰，只道蓬萊在海間。", "空上望秦山上望，不知此處是神山。"]'),
('e0b27a30-59b7-48c4-a3c5-70f3564da19c','清白堂','王十朋','宋','宋诗','song-poetry','','[]','錢清地古思劉寵，泉白堂虛憶范公。',32,'全唐诗/poet.song.118000.json','["錢清地古思劉寵，泉白堂虛憶范公。", "印綬紛紛會稽守，誰能無愧一賢風。"]'),
('65c5435c-fc9d-4278-8e9a-0eb3ca12b91d','清白泉','王十朋','宋','宋诗','song-poetry','','[]','聖人達節猶憎盜，志士清心肯飲貪。',32,'全唐诗/poet.song.118000.json','["聖人達節猶憎盜，志士清心肯飲貪。", "試問卧龍山下酌，世間無似此泉甘。"]'),
('8e961418-3130-4b6a-8503-0defa5d7aded','觀風堂','王十朋','宋','宋诗','song-poetry','','[]','薄俗澆風有萬端，欲將眼力見應難。',32,'全唐诗/poet.song.118000.json','["薄俗澆風有萬端，欲將眼力見應難。", "但令心境無塵垢，端坐斯堂便可觀。"]'),
('a3bbcb6b-3e1c-4ab9-973a-5da993abe441','望月臺','王十朋','宋','宋诗','song-poetry','','[]','明珠遥吐卧龍頭，漸覺清光萬里浮。',32,'全唐诗/poet.song.118000.json','["明珠遥吐卧龍頭，漸覺清光萬里浮。", "人望使君如望月，要須如鏡莫如鈎。"]'),
('e7012f1a-c724-4293-924a-181c6b6a0013','秦望閣','王十朋','宋','宋诗','song-poetry','','[]','紙上觀秦尚過秦，那堪山作眼中塵。',32,'全唐诗/poet.song.118000.json','["紙上觀秦尚過秦，那堪山作眼中塵。", "爲言高閣登臨者，莫作秦人視越人。"]'),
('a819bbcd-a21c-4d2c-9eff-a1ff524e9668','望海亭','王十朋','宋','宋诗','song-poetry','','[]','踏雪遥登望海亭，扶桑日上卧龍醒。',32,'全唐诗/poet.song.118000.json','["踏雪遥登望海亭，扶桑日上卧龍醒。", "微臣望處非滄海，只望堯天萬里青。"]'),
('c6606795-fa83-4559-bac1-a7883ced808f','卧龍山','王十朋','宋','宋诗','song-poetry','','[]','鑑水連天僅可容，稽山照眼五雲濃。',32,'全唐诗/poet.song.118000.json','["鑑水連天僅可容，稽山照眼五雲濃。", "只憂旱歲無霖雨，誰識東州有卧龍。"]'),
('21dc32a3-ca1c-45a5-8914-d9c4f357be4b','種山','王十朋','宋','宋诗','song-poetry','','[]','决策平吳覇業成，青山長占大夫名。',32,'全唐诗/poet.song.118000.json','["决策平吳覇業成，青山長占大夫名。", "子胥忠義無生死，怒氣隨潮到越城。"]'),
('13b5c185-1574-4b08-b4e1-2d22a8103cff','競秀閣','王十朋','宋','宋诗','song-poetry','','[]','憲臺高閣偶躋攀，萬壑千巖指顧間。',32,'全唐诗/poet.song.118000.json','["憲臺高閣偶躋攀，萬壑千巖指顧間。", "山色元來本無競，人心自是錯看山。"]'),
('33c098c0-f7fe-455a-92b4-980fd7a7e9ec','戢山','王十朋','宋','宋诗','song-poetry','','[]','十九年間膽厭嘗，盤羞野菜當含香。',32,'全唐诗/poet.song.118000.json','["十九年間膽厭嘗，盤羞野菜當含香。", "春風又長新芽甲，好擷青青薦越王。"]'),
('8b134d27-3f85-4019-9af8-9f1d51a06e14','八松','王十朋','宋','宋诗','song-poetry','','[]','瀟灑荀家好弟兄，秦封不污有餘清。',32,'全唐诗/poet.song.118000.json','["瀟灑荀家好弟兄，秦封不污有餘清。", "鍾成一種棟梁氣，散作八方風雨聲。"]'),
('1c13575e-7198-4e45-a764-5513697972aa','右軍祠堂','王十朋','宋','宋诗','song-poetry','','[]','欲弔右軍千載魂，祠堂荆棘斷碑存。',32,'全唐诗/poet.song.118000.json','["欲弔右軍千載魂，祠堂荆棘斷碑存。", "老僧相見話前事，問我蘭亭幾世孫。"]'),
('44acc9a5-f7ba-4c39-9f41-9e1d3a416283','鵝池','王十朋','宋','宋诗','song-poetry','','[]','鶂鶂能鳴異衆禽，池邊墨客最知音。',32,'全唐诗/poet.song.118000.json','["鶂鶂能鳴異衆禽，池邊墨客最知音。", "世間多是山陰嫗，應恐悞猜君子心。"]'),
('c6597c42-ec54-470e-8e69-da17d0713a57','硯池','王十朋','宋','宋诗','song-poetry','','[]','鳳翥龍蟠字字奇，陶泓湯沐向斯池。',32,'全唐诗/poet.song.118000.json','["鳳翥龍蟠字字奇，陶泓湯沐向斯池。", "波心雨後一魚躍，猶似當年吞墨時。"]'),
('709b349e-d025-4dcf-ab55-23dd9b1c7f45','題扇橋','王十朋','宋','宋诗','song-poetry','','[]','右軍一畫千金重，妙意寧容市嫗知。',32,'全唐诗/poet.song.118000.json','["右軍一畫千金重，妙意寧容市嫗知。", "明日重來堪一笑，管城那肯更臨池。"]'),
('35d838a6-a900-4f65-9ddd-f1fbe9b73e15','雷門','王十朋','宋','宋诗','song-poetry','','[]','吳越興亡事若何，譙門遺迹枕山阿。',32,'全唐诗/poet.song.118000.json','["吳越興亡事若何，譙門遺迹枕山阿。", "大聲曾作雷霆震，應笑人間布鼓多。"]'),
('c7e2c3a9-a9ac-4e24-bab4-3d0a57f046a6','曲水閣','王十朋','宋','宋诗','song-poetry','','[]','王謝蘭亭久寂寥，茂林脩竹自蕭騷。',32,'全唐诗/poet.song.118000.json','["王謝蘭亭久寂寥，茂林脩竹自蕭騷。", "蔣侯近代風流守，曲水流觴意亦高。"]'),
('f857c36d-c4cc-4df4-b5e6-2e1c52a4a8f5','西園','王十朋','宋','宋诗','song-poetry','','[]','西園風物冠東州，飛蓋紛紛爛熳游。',32,'全唐诗/poet.song.118000.json','["西園風物冠東州，飛蓋紛紛爛熳游。", "惟有紅蓮幕中客，倚欄纔得片時留。"]'),
('76db0545-628d-4d79-ac53-0921384030d0','望湖亭','王十朋','宋','宋诗','song-poetry','','[]','杖屨登臨望鑑湖，湖中一半已湮蕪。',32,'全唐诗/poet.song.118000.json','["杖屨登臨望鑑湖，湖中一半已湮蕪。", "誰能更繼東都守，長使山陰水旱無。"]'),
('d1130417-6e05-47ee-9b1e-60c6de2349c2','吳先生祠','王十朋','宋','宋诗','song-poetry','','[]','右軍宅化空王寺，秘監家爲羽士宮。',32,'全唐诗/poet.song.118000.json','["右軍宅化空王寺，秘監家爲羽士宮。", "惟有先生舊池舘，春風歸在杏壇中。"]'),
('78e37d85-2d8a-4f79-a445-865560ce2dfa','賀知章祠','王十朋','宋','宋诗','song-poetry','','[]','賀老祠堂枕鑑湖，霓裳羽化宅荒蕪。',32,'全唐诗/poet.song.118000.json','["賀老祠堂枕鑑湖，霓裳羽化宅荒蕪。", "無人更問君王覓，轉使高風千載孤。"]'),
('df8149dc-1fad-4673-8e7d-48e4f9506d68','鑑湖','王十朋','宋','宋诗','song-poetry','','[]','胸中萬頃元才子，方外孤標賀季真。',32,'全唐诗/poet.song.118000.json','["胸中萬頃元才子，方外孤標賀季真。", "鑑水縈回三百里，風流何止兩唐人。"]'),
('00fe5b83-abf6-4258-b915-34c47a26fa0d','禹廟','王十朋','宋','宋诗','song-poetry','','[]','越國遺民念帝功，稽山廟貌勝卑宮。',32,'全唐诗/poet.song.118000.json','["越國遺民念帝功，稽山廟貌勝卑宮。", "少陵莫歎丹青落，紙上丹青自不窮。"]'),
('13927b86-c51d-41c5-8927-012a2912bfe9','菲泉','王十朋','宋','宋诗','song-poetry','','[]','梵王宮近夏王宮，一水清含節儉風。',32,'全唐诗/poet.song.118000.json','["梵王宮近夏王宮，一水清含節儉風。", "越俗不知王好惡，泉名却在酒名中。"]'),
('fd217632-ddd6-459a-a654-a88dd8c6ab77','禹穴','王十朋','宋','宋诗','song-poetry','','[]','好古貪奇司馬遷，胸中史記越山川。',32,'全唐诗/poet.song.118000.json','["好古貪奇司馬遷，胸中史記越山川。", "如今禹穴無尋處，洞鎖陽明石一拳。"]'),
('4ec1f323-99cf-476e-9dbf-7d2f3feeffe6','馬太守廟','王十朋','宋','宋诗','song-poetry','','[]','會稽疏鑿自東都，太守功從禹後無。',32,'全唐诗/poet.song.118000.json','["會稽疏鑿自東都，太守功從禹後無。", "能使越人懷舊德，至今廟食賀家湖。"]'),
('2d362deb-9690-40fd-a3eb-d38e05b7604b','吳越王廟','王十朋','宋','宋诗','song-poetry','','[]','一劍功成三節還，盡將錦綉裹江山。',32,'全唐诗/poet.song.118000.json','["一劍功成三節還，盡將錦綉裹江山。", "斗牛氣滅英靈泯，廟比昭王屋一間。"]'),
('58b292d1-5084-46a4-a5a9-861c1e6d7f52','望秦山','王十朋','宋','宋诗','song-poetry','','[]','洛思昔有人思洛，秦望今無客望秦。',32,'全唐诗/poet.song.118000.json','["洛思昔有人思洛，秦望今無客望秦。", "回首長安在何處，誰能念彼下泉人。"]'),
('2fc6e34f-2770-4027-a306-dcb59d32ba25','少微山','王十朋','宋','宋诗','song-poetry','','[]','出郭舟行十里間，少微山近若蕡山。',32,'全唐诗/poet.song.118000.json','["出郭舟行十里間，少微山近若蕡山。", "山中處士已長往，一點客星雲外閑。"]'),
('e259c827-5f73-4434-b60b-0747bec9cc19','梅梁','王十朋','宋','宋诗','song-poetry','','[]','結實幾調商鼎味，成材宜作禹祠梁。',32,'全唐诗/poet.song.118000.json','["結實幾調商鼎味，成材宜作禹祠梁。", "世間何歲無風雨，鐵鎖無端誤見殃。"]'),
('387c1dff-11a2-49bc-a27e-e1cb8a3a4078','窆石','王十朋','宋','宋诗','song-poetry','','[]','越俗流傳素可疑，禹陵窆石果何時。',32,'全唐诗/poet.song.118000.json','["越俗流傳素可疑，禹陵窆石果何時。", "只應便是專車骨，未可呼爲沒字碑。"]'),
('03711db3-1a64-4533-941d-5c226f8db319','和昌齡弟見寄','王十朋','宋','宋诗','song-poetry','','[]','經年游宦思家鄉，枕間魂夢長飛揚。',128,'全唐诗/poet.song.118000.json','["經年游宦思家鄉，枕間魂夢長飛揚。", "甌越相望數百里，魚雁來徃安能常。", "水綠蓮紅王儉幕，我愧才踈筆常閣。", "居官不事羨長卿，執一無權猶子莫。", "昔年姜被今獨眠，何時更作三珠連。", "左原風物亦不惡，溪蓴抽絲蕨吐拳。", "阿連春草詩篇好，勸我歸來宜及早。", "代笠亭前烟雨中，共把鋤犁寧待老。"]'),
('db3ba2f0-0569-4cc8-b514-b26dbfe4fbb6','懷喻叔奇','王十朋','宋','宋诗','song-poetry','','[]','結得賢關雁塔因，東州相遇益相親。',64,'全唐诗/poet.song.118000.json','["結得賢關雁塔因，東州相遇益相親。", "凌雲三賦我慚馬，清唱百篇君勝秦。", "冀北群空殊昔別，江東日暮倍傷神。", "同年四百二十六，莫逆論交能幾人。"]'),
('63b51614-0006-4d71-bd3e-060ab7ef25bf','次韵周堯夫贈睡香','王十朋','宋','宋诗','song-poetry','','[]','長向春前臘後開，要將風味鬭梅魁。',64,'全唐诗/poet.song.118000.json','["長向春前臘後開，要將風味鬭梅魁。", "名從廬阜夢中得，根自鄮山嘉處來。", "風拆錦囊香不斷，日烘寶蓋翠成堆。", "定須移向梅谿去，栽伴吾廬桂與槐。"]'),
('b98d33f5-b709-42b9-81d9-10940f1fab0a','送陳元佐游四明','王十朋','宋','宋诗','song-poetry','','[]','鑑水悠悠接鄮川，宦情客况兩凄然。',64,'全唐诗/poet.song.118000.json','["鑑水悠悠接鄮川，宦情客况兩凄然。", "扁舟乘興梅花月，樽酒送行燈火天。", "我似鄭虔官舍冷，君如馮子主人賢。", "虞庠春榜無多日，行看香名動日邊。"]'),
('188201dc-4c21-4abd-82c2-a3a20d7fd539','聞禮生日','王十朋','宋','宋诗','song-poetry','','[]','桃水仲春月，蓂階雙莢生。',48,'全唐诗/poet.song.118000.json','["桃水仲春月，蓂階雙莢生。", "添丁慰盧老，小子慶徐卿。", "稟得中和氣，看成遠大名。", "青春已如許，勉力繼家聲。"]'),
('46ddb8f8-c752-40fc-915c-e40eeea38507','次韵趙觀使鴛鴦梅','王十朋','宋','宋诗','song-poetry','','[]','奴視紛紛晳與休，芳心那肯貯離愁。',64,'全唐诗/poet.song.118000.json','["奴視紛紛晳與休，芳心那肯貯離愁。", "結成冰玉岳湛侶，開伴紵羅施鄭流。", "影照嬋娟如並卧，枝橫清淺似雙浮。", "不知他日調金鼎，勝得櫻桃氣味不。"]'),
('dcc87e39-9dde-4da6-b56f-ccdf1f075f56','亡友孫子尚藁葬會稽山大禹寺之側某至官八日出郊訪其墓不獲明年春被命祀禹訪而得之又明年春再往酹酒因植柏十根哭之以詩','王十朋','宋','宋诗','song-poetry','','[]','疇昔相知似弟昆，那知半世死生分。',64,'全唐诗/poet.song.118000.json','["疇昔相知似弟昆，那知半世死生分。", "無緣更飲盃中物，想見能修地下文。", "有愧乘車葬元伯，僅同解劔弔徐君。", "他年黛色參天處，是子會稽山下墳。"]'),
('e10c2649-d78b-4159-a7de-ae35ac740dbb','子尚墓種柏','王十朋','宋','宋诗','song-poetry','','[]','子尚乃如許，壯年墳已荒。',24,'全唐诗/poet.song.118000.json','["子尚乃如許，壯年墳已荒。", "我來親種柏，含淚待蒼蒼。"]'),
('ab62fb41-198b-45fc-b182-f8251336d6d5','鄭夫人挽詞','王十朋','宋','宋诗','song-poetry','','[]','好谿太守非常好，慈母端如孟母賢。',64,'全唐诗/poet.song.118000.json','["好谿太守非常好，慈母端如孟母賢。", "熊膽調成真器業，魚軒游徧舊山川。", "顔間日有平反喜，方外時修香火緣。", "身世九齡家萬石，定應含笑向重泉。"]'),
('f95a3c46-ee30-4de6-be24-50902ef4ccc6','錢夫人挽詞','王十朋','宋','宋诗','song-poetry','','[]','忠孝之家女亦良，教傳彤管有遺芳。',64,'全唐诗/poet.song.118000.json','["忠孝之家女亦良，教傳彤管有遺芳。", "藁砧舊擢儒林秀，桂子新飄月窟香。", "方擬魚軒霑寵渥，遽驚風樹變凄凉。", "稽山鑑水青春暮，薤露聲中恨更長。"]'),
('4a813696-4198-4730-a6d6-5231a9b480e1','連月不雨農事失時府帥决獄廩饑德政動天霈然而雨某吟成律詩一章以賀','王十朋','宋','宋诗','song-poetry','','[]','旱魃爲災罕似今，霈然一雨慰群心。',64,'全唐诗/poet.song.118000.json','["旱魃爲災罕似今，霈然一雨慰群心。", "非關菩薩解爲澤，自是使君能作霖。", "躬慮滯囚寃盡釋，廣開義廩惠尤深。", "佇公歸國調元氣，散盡愆陽與伏陰。"]'),
('27db00f7-906c-4d87-916a-cad75c10d513','次韵濮十太尉喜雨','王十朋','宋','宋诗','song-poetry','','[]','去歲秋大水，民食方苦艱。',180,'全唐诗/poet.song.118000.json','["去歲秋大水，民食方苦艱。", "丁壯尚流離，而况白與班。", "今春又不雨，事與安危関。", "使符下列郡，呼雩舞童鬟。", "投文責老龍，貪睡何癡頑。", "我聞救災術，迺在人事間。", "興師古有衛，决獄唐稱顔。", "年因弔伐有，雨送軺車還。", "嗟此旱魃虐，和氣知誰干。", "半歲幸一雨，人心寧不歡。", "麥秀禾可植，田里庶少安。", "上紓當宁憂，吏責亦稍寬。", "我家簫峯下，山長路漫漫。", "東臯有先業，頗亦知艱難。", "歸耕願及早，免起將蕪嘆。"]'),
('2ebd15e3-05a2-4f00-b586-5fa8f3831908','叔父寶印師往永嘉妙果院未期年而退弟子德純住龍翔一日歸省其師亦退居林下緇素挽留之乃遁於異郡不踰月間師弟子相繼退休識者高之目爲僧中二疏某竊祿將一考矣有媿二高僧因書一絕庶幾他日或蹈其高躅云','王十朋','宋','宋诗','song-poetry','','[]','掛冠林下近來無，誰謂僧中有二疏。',32,'全唐诗/poet.song.118000.json','["掛冠林下近來無，誰謂僧中有二疏。", "應笑紅蓮幕中客，故園三徑已荒蕪。"]'),
('65f56266-339d-4fd9-b0d3-2301b7fe5b7c','寄黄簿','王十朋','宋','宋诗','song-poetry','','[]','六一移書責司諫，聱隅聞命避徂徠。',64,'全唐诗/poet.song.118000.json','["六一移書責司諫，聱隅聞命避徂徠。", "茲風不作已久矣，吾子所爲何壯哉。", "在列諸公顔有媿，附炎群小膽應摧。", "要須終始全名節，莫遣心隨利祿回。"]'),
('23a438c0-4acc-47c8-bf7f-b6d6839e517b','次韵濮十太尉題禹穴','王十朋','宋','宋诗','song-poetry','','[]','寰瀛三十六名郡，越在東南雄四鎮。',192,'全唐诗/poet.song.118000.json','["寰瀛三十六名郡，越在東南雄四鎮。", "宛委周回三百里，草木山川有光潤。", "秦山鑑水藴秀異，人物風流夸漢晉。", "傳聞禹穴自太史，好古無人若爲問。", "杖屨飄然尋洞天，照眼千巖若攢刃。", "細看盤石心愈疑，遐想丹書氣猶振。", "禹貢無傳豈其闕，遁甲所書何足訓。", "彜倫敘自九疇錫，水土平繇五行順。", "洛書六十有五字，王業巍巍此途進。", "八卷飛沉天與泉，茲說荒唐理難信。", "吾儕去古恨大遠，企首難窺禹牆仞。", "穴傍有井清且甘，一酌端能洗驕吝。"]'),
('95774de9-dca5-4cd6-b288-757c016983f6','薛師約撫幹召飯于圓通寺主僧瀹茗索詩','王十朋','宋','宋诗','song-poetry','','[]','綠暗梅欲雨，風薰麥初秋。',48,'全唐诗/poet.song.118000.json','["綠暗梅欲雨，風薰麥初秋。", "官舍厭卑濕，僧廬訪清幽。", "儒餐慣蔬飯，道話便茶甌。", "鑑湖倘容覓，杖屨時來游。"]'),
('d1c2eff3-9651-43cd-aafa-7a6495424a6f','潘知縣弟撫幹和詩復用前韵','王十朋','宋','宋诗','song-poetry','','[]','堂堂紫微公，氣節橫清秋。',48,'全唐诗/poet.song.118000.json','["堂堂紫微公，氣節橫清秋。", "風流屬猶子，胸壑羅奇幽。", "詩篇粲華萼，名字宜金甌。", "州縣聊爾耳，行矣天池游。"]'),
('0a3db258-6ea6-4b08-9eeb-504c079d5b94','酬富陽張叔清縣尉','王十朋','宋','宋诗','song-poetry','','[]','尺素遥傳到越城，入懷珠玉照人明。',64,'全唐诗/poet.song.118000.json','["尺素遥傳到越城，入懷珠玉照人明。", "登科雅服才名早，筮仕喜聞官業清。", "空把交情對山色，要令音問續潮聲。", "怱怱作答無他語，莫羨人間勢利榮。"]'),
('46c9fa56-abd5-4848-9222-19cd430e251a','周德貽得子以錢果爲貺僕不獲爲湯餠客賀之以詩','王十朋','宋','宋诗','song-poetry','','[]','雙鯉來從古嵊州，喜聞英物誕東州。',64,'全唐诗/poet.song.118000.json','["雙鯉來從古嵊州，喜聞英物誕東州。", "清和時節綠陰滿，秀異谿山佳氣浮。", "分貺金錢意殊厚，欲爲湯餠客無由。", "乃翁指日身龍虎，况有奇兒氣食牛。"]'),
('672dd9ab-7485-4705-a86b-51f02e876c2d','喻叔奇迎侍赴桐川榜其堂曰戲綵書來求詩寄題一絕','王十朋','宋','宋诗','song-poetry','','[]','桐州綵棒暫宣威，首闢萱堂上壽巵。',32,'全唐诗/poet.song.118000.json','["桐州綵棒暫宣威，首闢萱堂上壽巵。", "堂上慈顔笑還語，老萊文采媿吾兒。"]'),
('d5c1b9db-10a4-4b26-828f-362d11d79fe5','女子生日','王十朋','宋','宋诗','song-poetry','','[]','吾女何時見，薰風欲半時。',48,'全唐诗/poet.song.118000.json','["吾女何時見，薰風欲半時。", "年齡今稍長，禮法要須知。", "好讀班姬誡，休吟謝女詩。", "萱堂有慈母，淑德可爲師。"]'),
('6bc38731-ab24-4dec-a43b-4f5a32db5b43','范文正公祠堂詩','王十朋','宋','宋诗','song-poetry','','[]','堂堂范公真天人，配我仁祖爲元臣。',280,'全唐诗/poet.song.118000.json','["堂堂范公真天人，配我仁祖爲元臣。", "材兼文武懷經綸，先憂後樂不爲身。", "上與夔卨相等倫，正色朝端批逆鱗。", "三黜愈光名愈聞，一麾東游禹所巡。", "作詩懷蠡祠季真，卧龍山麓井久湮。", "綆而汲之清且新，堂于其旁記厥因。", "名標清白垂不泯，規爾官師意諄諄。", "洗貪濯盜思還淳，人亡迹在嗟己陳。", "斷碑徃徃埋荆榛，後人不識真天人。", "但能日飲堂中春，使君好事賢且仁。", "治民律己惟公遵，登堂感槩懷斯人。", "刻石繪像揚清芬，丹青炳耀如麒麟。", "凜然如生見如親，躬修祀事率幕賓。", "手酌寒泉羞澗蘋，一酌清我僚吏民。", "再酌爲國清簪紳，要將清白風無垠。", "庶俾范公遺志伸，公乎爲仙爲明神。", "爲澤爲瑞爲星辰，當宁焦勞思若人，九原喚起清邊塵。"]'),
('02f1c7c4-aaba-4d17-a35c-db631559bdfb','次韵梁尉秦碑古風','王十朋','宋','宋诗','song-poetry','','[]','姬嬴遺迹存者希，世傳石鼓稽山碑。',384,'全唐诗/poet.song.118000.json','["姬嬴遺迹存者希，世傳石鼓稽山碑。", "石鼓揄揚得韓子，文與二雅爭驅馳。", "秦碑夸大頌功德，埋沒草莽無人知。", "或言山頂石猶在，上有虎豹龍蛇螭。", "神藏鬼護荆棘蔽，崖懸磴絕登無岐。", "廣文好奇穴探禹，梅仙喜事僧尋支。", "我贊其行要親睹，勿受世俗流傳欺。", "望秦秦望兩嶄絕，何山壁立東南涯。", "豊碑屹植最高處，不知磨滅從何時。", "剔苔掃墨了無有，模糊片紙亦足奇。", "濃雲霮䨴黯將雨，古木槎牙蟠老枝。", "歸來走筆出險語，訶政叱斯同小兒。", "詩成得得寫寄我，詞嚴意偉法退之。", "我聞秦人滅六國，酷若犬磔臨江麋。", "先王法爲秦所負，負秦况有秦有司。", "五經灰飛儒濺血，堯舜周孔何能爲。", "上蔡獵師妙小篆，奴視俗體徒肥皮。", "東封太山南入越，大書深刻光陸離。", "沙丘風腥人事變，鬼饑族赤誰嗟咨。", "漢興萬事一掃去，惟有篆刻餘刑儀。", "磨崖欲作不朽計，其如曆數不及期。", "蚩尤五兵紂漆器，人物美惡寧相疵。", "我雖過秦愛遺畫，南山入望頻支頤。", "不須嶧陽訪棗刻，不用遷史觀雄辭。"]'),
('cdb53442-2954-4c13-bba1-269a1a08f577','府帥王公中秋宴客蓬萊閣分茶賞月于清白亭某以幕僚與焉坐上成二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','使君開宴小蓬瀛，幕客參陪亦與榮。',32,'全唐诗/poet.song.118000.json','["使君開宴小蓬瀛，幕客參陪亦與榮。", "茗煮寒泉飲清白，酒斟佳月賞分明。"]'),
('db27e28f-26b9-49c9-b627-36e1ef95b9e5','府帥王公中秋宴客蓬萊閣分茶賞月于清白亭某以幕僚與焉坐上成二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','白髮青衫老幕官，蓬萊秋月兩年看。',32,'全唐诗/poet.song.118000.json','["白髮青衫老幕官，蓬萊秋月兩年看。", "興來端欲乘風去，不怕瓊樓玉宇寒。"]'),
('95ae167b-3345-44f8-8119-c72e1f3adb3d','又和趙仲永撫幹二首  其一','王十朋','宋','宋诗','song-poetry','','[]','冰輪飛出暮雲端，更向蓬萊頂上看。',64,'全唐诗/poet.song.118000.json','["冰輪飛出暮雲端，更向蓬萊頂上看。", "端似虹橋翫金餠，絕勝華屋見銀盤。", "光浮酒面杯尤滑，清入詩腸句不寒。", "又與鑑湖添勝事，一時賓主盡鴛鸞。"]'),
('1ef4968f-bff4-4ede-85c3-e99015e7e164','又和趙仲永撫幹二首  其二','王十朋','宋','宋诗','song-poetry','','[]','千巖競秀越王州，地勝錢塘與虎丘。',64,'全唐诗/poet.song.118000.json','["千巖競秀越王州，地勝錢塘與虎丘。", "龍卧半天頭吐月，鑑湖千里影涵樓。", "宴開秋色平分際，人在蓬壺最上頭。", "不負良天更輸我，此中此夜兩年游。"]'),
('2ef36283-6c31-4bff-8b22-d80766bc7e18','再和  其一','王十朋','宋','宋诗','song-poetry','','[]','崢嶸高閣聳雲端，萬壑千巖坐上看。',64,'全唐诗/poet.song.118000.json','["崢嶸高閣聳雲端，萬壑千巖坐上看。", "八百里湖寒鑑瑩，二千年國卧龍盤。", "金風吹面掃殘暑，明月入懷生嫩寒。", "見說神山正相偶，醉中端欲駕仙鸞。"]'),
('ec103674-ebc1-4e79-a336-699166dee07c','再和  其二','王十朋','宋','宋诗','song-poetry','','[]','家在東嘉山水州，玉簫丹竈古仙丘。',64,'全唐诗/poet.song.118000.json','["家在東嘉山水州，玉簫丹竈古仙丘。", "兩年秋月登蓬閣，千里鄉心繞謝樓。", "作賦端同比窗裏，思歸長詠大刀頭。", "與君何日脫塵鞅，杖屨逍遥物外游。"]'),
('0db4182d-9155-4e48-9cfa-b52b635308bd','又用看字韵酬趙仲永','王十朋','宋','宋诗','song-poetry','','[]','紅蓮分幕忝同官，秋月揚輝並席看。',32,'全唐诗/poet.song.118000.json','["紅蓮分幕忝同官，秋月揚輝並席看。", "句好湖山添秀氣，談清齒頰带微寒。"]'),
('6d21776c-a3ba-4328-b98a-f74410407925','故參政李公挽詩三首  其一','王十朋','宋','宋诗','song-poetry','','[]','一代高明學，三朝骨鯁臣。',48,'全唐诗/poet.song.118000.json','["一代高明學，三朝骨鯁臣。", "淮南憚長孺，楚國忌靈均。", "死尚憂王室，生寧問大鈞。", "姜山同峴首，千古淚行人。"]'),
('1c31f09b-770e-415e-a33d-524732bd016d','故參政李公挽詩三首  其二','王十朋','宋','宋诗','song-poetry','','[]','方面功尤著，朝端氣最剛。',48,'全唐诗/poet.song.118000.json','["方面功尤著，朝端氣最剛。", "身能縛元濟，城不陷睢陽。", "思奮少連笏，耻同袁盎堂。", "永嘉瞻五馬，遺愛可能忘。"]'),
('ed0574b6-89ea-46ce-b13e-3ff08e437da5','故參政李公挽詩三首  其三','王十朋','宋','宋诗','song-poetry','','[]','公在南荒日，迹危名愈尊。',48,'全唐诗/poet.song.118000.json','["公在南荒日，迹危名愈尊。", "芝蘭坐奇禍，瓜葛醖讒言。", "斥去權臣力，生還聖主恩。", "衛公精爽在，何用些招魂。"]'),
('0fd9bc2c-54a8-4c90-9546-dcae760d984c','九日與同官游戒珠寺用去年韵','王十朋','宋','宋诗','song-poetry','','[]','九日重登古蕺山，勞生又得片時閑。',64,'全唐诗/poet.song.118000.json','["九日重登古蕺山，勞生又得片時閑。", "菊花今歲殊不惡，蓬鬢去年猶未班。", "藍水楚山詩興裏，鑑湖秦望酒盃間。", "醉中同訪右軍迹，題扇橋邊踏月還。"]'),
('f66d33bc-a0dc-4908-864b-c62863106c26','顯仁皇后挽詞三首  其一','王十朋','宋','宋诗','song-poetry','','[]','媯汭嬪天子，塗山毓聖人。',48,'全唐诗/poet.song.118000.json','["媯汭嬪天子，塗山毓聖人。", "聰明配昭獻，慈儉繼宣仁。", "湯沐寧私己，園陵不病民。", "鴻休耀彤管，無復數娀㜪。"]'),
('a545b660-7b1b-41a8-8b11-429bb36553d2','顯仁皇后挽詞三首  其二','王十朋','宋','宋诗','song-poetry','','[]','八秩年無憾，三仁謚有輝。',48,'全唐诗/poet.song.118000.json','["八秩年無憾，三仁謚有輝。", "瑶池燕仙侶，窆石葬遺衣。", "忽睹龍輴去，猶疑騩馭歸。", "聖情哀不盡，淚向禹陵揮。"]'),
('d46ce3d1-0dd2-4927-8f72-36ed7691bb02','顯仁皇后挽詞三首  其三','王十朋','宋','宋诗','song-poetry','','[]','代邸迎歸日，炎圖喜中興。',48,'全唐诗/poet.song.118000.json','["代邸迎歸日，炎圖喜中興。", "解將天下養，惟有聖人能。", "方慶朝長樂，俄驚望獻陵。", "寢園祗奉處，擁紼淚垂膺。"]'),
('91d1a4cf-fa75-4cf5-bc26-1534bcd2e2f7','胡氏挽詩','王十朋','宋','宋诗','song-poetry','','[]','婺女生賢女，端宜配德星。',48,'全唐诗/poet.song.118000.json','["婺女生賢女，端宜配德星。", "登堂飲姑乳，調膽教兒經。", "子舍春猶盛，孫枝葉已青。", "韓碑紀遺懿，彤管繼芳馨。"]'),
('cd3ea4c8-4448-4713-9f41-4266e80ffafd','次韵喻叔奇追感去冬天衣之游','王十朋','宋','宋诗','song-poetry','','[]','去年同會類高陽，蠟屐登臨雅興長。',64,'全唐诗/poet.song.118000.json','["去年同會類高陽，蠟屐登臨雅興長。", "可但山光向人好，更欣天氣爲吾良。", "路經禹穴深懷白，目對秦峯遠憶黄。", "日線又添人正遠，尺書千里慰相望。"]'),
('d0b06315-1037-4d6c-aae5-0e1e661786ed','次韵劉判官見贈','王十朋','宋','宋诗','song-poetry','','[]','篋藏詩墨尚澄鮮，長記東嘉共綺筵。',64,'全唐诗/poet.song.118000.json','["篋藏詩墨尚澄鮮，長記東嘉共綺筵。", "游宦俱爲蓮幕客，異鄉重見菊花天。", "謝池一別真成夢，鑑水相逢似有緣。", "小小園林吾欲老，看君功業上凌烟。"]'),
('74ec68bc-b0b6-4bea-8f99-3da36204ef66','趙仲永以御茗密雲龍薰衣香見贈仍惠小詩次韵','王十朋','宋','宋诗','song-poetry','','[]','天上人回餠賜龍，香沾衣袖十分濃。',32,'全唐诗/poet.song.118000.json','["天上人回餠賜龍，香沾衣袖十分濃。", "明珠照室光生豔，三絕全勝萬石封。"]'),
('0db0ce63-3522-4253-9dea-a0fb10f63fed','仲永再和三絕復和以酬  其一','王十朋','宋','宋诗','song-poetry','','[]','間世宗英學海龍，交情尤爲野人濃。',32,'全唐诗/poet.song.118000.json','["間世宗英學海龍，交情尤爲野人濃。", "天香御茗分奇絕，盡是殷勤手自封。"]'),
('d9b978dd-e18e-4373-8a0c-e79b71064068','仲永再和三絕復和以酬  其二','王十朋','宋','宋诗','song-poetry','','[]','手汲寒泉碾小龍，天香一炷滿衣濃。',32,'全唐诗/poet.song.118000.json','["手汲寒泉碾小龍，天香一炷滿衣濃。", "與君慷慨論時事，欲吐丹心上實封。"]'),
('1c378644-5979-45eb-b301-2f593e02ff20','仲永再和三絕復和以酬  其三','王十朋','宋','宋诗','song-poetry','','[]','長記中秋踏卧龍，尚餘詩興至今濃。',32,'全唐诗/poet.song.118000.json','["長記中秋踏卧龍，尚餘詩興至今濃。", "羨君豪邁如韓子，聯句猶容李正封。"]'),
('5b2280c9-1d52-4d7f-8e2d-c17765485e00','寄題周堯夫碧梧軒','王十朋','宋','宋诗','song-poetry','','[]','鳳凰梧棲竹實食，胡爲使之在枳棘。',64,'全唐诗/poet.song.118000.json','["鳳凰梧棲竹實食，胡爲使之在枳棘。", "開軒種梧高幾尺，鳳兮凰兮聊爾息。", "莫羨風微燕雀高，一飛定展沖天翼。", "覽輝瑞世鳴朝陽，此梧長向人間碧。"]'),
('8b0d5d22-77f4-4dd5-a7fe-427b10e4b2ce','留別民事堂','王十朋','宋','宋诗','song-poetry','','[]','二年宦東州，民事了無補。',48,'全唐诗/poet.song.118000.json','["二年宦東州，民事了無補。", "俯仰媿斯堂，何以報明主。", "故家蕭峯下，歸耕及春雨。", "平生畎畝心，感槩聊自許。"]'),
('a4b8120c-c414-4775-9b5b-aa39dc6f2d71','題雙峰資深堂  其一','王十朋','宋','宋诗','song-poetry','','[]','書生紙上誦糟粕，釋子舌端談葛藤。',32,'全唐诗/poet.song.118000.json','["書生紙上誦糟粕，釋子舌端談葛藤。", "道在湛然方寸地，不知深造有誰能。"]'),
('5f68dd17-1c78-42b2-8034-d129cbf99c21','題雙峰資深堂  其二','王十朋','宋','宋诗','song-poetry','','[]','我到雙峯尋寶月，爲留一宿話資深。',32,'全唐诗/poet.song.118000.json','["我到雙峯尋寶月，爲留一宿話資深。", "但能造得儒宗語，便是能傳佛隴心。"]'),
('0beb4ad0-d930-4060-9827-cf37552cfbd5','題雙峰資深堂  其三','王十朋','宋','宋诗','song-poetry','','[]','雁山門戶此中入，南北兩峯相對尖。',32,'全唐诗/poet.song.118000.json','["雁山門戶此中入，南北兩峯相對尖。", "我與林泉有盟約，問師覓取一峯潛。"]'),
('7036d41f-e10f-4417-8bc2-40a45e16e37c','題雙峰資深堂  其四','王十朋','宋','宋诗','song-poetry','','[]','千峯已見見雙峯，甌越山川在眼中。',32,'全唐诗/poet.song.118000.json','["千峯已見見雙峯，甌越山川在眼中。", "吾祖吹簫定何所，會須乘鶴訪遺風。"]'),
('94719c0e-3595-4a2d-bd18-9291c3006273','題雙峰資深堂  其五','王十朋','宋','宋诗','song-poetry','','[]','堂名石刻兩俱存，令我深懷舊長官。',32,'全唐诗/poet.song.118000.json','["堂名石刻兩俱存，令我深懷舊長官。", "學道資深更深處，居安能使庶民安。"]'),
('0969e5bb-b10a-4eca-a2a2-0b81caa0faa0','宿靈巖贈長老敏行','王十朋','宋','宋诗','song-poetry','','[]','籃輿謝公嶺，杖屨矩羅室。',120,'全唐诗/poet.song.118000.json','["籃輿謝公嶺，杖屨矩羅室。", "凈名訪維摩，一菴僅容膝。", "尋僧畫屏中，徃徃多八十。", "平生看不足，靈巖最奇絕。", "老禪蜀中來，心印傳佛日。", "脚力窮天下，稱此爲第一。", "茲山昔未開，藏閉最深密。", "倘不遇熙朝，造物肯容出。", "孫公賦天台，勝地尚遺佚。", "我欲續金聲，願借山中筆。"]'),
('ff90aab4-0663-4ebf-a493-12a87c77259e','己卯臘月七日解官離越十九日至家明年正月二日被命除秘書省校書郎卜以八日行書二十字','王十朋','宋','宋诗','song-poetry','','[]','梅花照歸眼，春色戒行裝。',24,'全唐诗/poet.song.118000.json','["梅花照歸眼，春色戒行裝。", "君命不俟駕，安敢懷故鄉。"]'),
('f48028d7-cfab-4f3f-9fd5-2d5cf0dc39fd','次韵馮員仲正字湖上有作','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','甌蜀異鄉客，西湖同日看。',48,'全唐诗/poet.song.118000.json','["甌蜀異鄉客，西湖同日看。", "浪花隨去棹，風絮逐歸鞍。", "水浸吳天闊，山涵佛界寬。", "春光無限好，共媿縛微官。"]'),
('a0f43326-b591-4d23-8752-67d884ac14d9','次韵趙仲永悠然閣','王十朋','宋','宋诗','song-poetry','','[]','越絕山川深更深，不須登覽自來臨。',64,'全唐诗/poet.song.118000.json','["越絕山川深更深，不須登覽自來臨。", "胸中丘壑忽相遇，眼底塵埃無復侵。", "得趣早同彭澤徑，把杯時赴廣文襟。", "知君指日歸天祿，莫負平生閣上心。"]'),
('74d6f461-f82b-40b0-96a7-20ce870f780b','次韵皇子建王題明遠樓','王十朋','宋','宋诗','song-poetry','','[]','百尺崇珠邸，恩隆地更親。',96,'全唐诗/poet.song.118000.json','["百尺崇珠邸，恩隆地更親。", "壯侔巢鳳閣，危切飲牛津。", "眼凈全無礙，心明自不塵。", "登高宜暇日，爲善及良辰。", "炳煥瞻宸畫，沉潛味道真。", "書中端得趣，筆下已如神。", "語带江山好，名隨棟宇新。", "應憐天下士，蝸舍不容身。"]'),
('3733c59d-fdd6-4875-9e58-944ffb6e6c55','劉韶美辭試館職','王十朋','宋','宋诗','song-poetry','','[]','學問稱博洽，向後無此劉。',96,'全唐诗/poet.song.118000.json','["學問稱博洽，向後無此劉。", "太一然青藜，遲君天祿游。", "給札試玉堂，故事久不修。", "遴選先實才，聞之輒掉頭。", "我迺行祕書，肯隨鉛槧流。", "三日掃虛室，佇想心悠悠。", "張羅君不顧，竊食吾懷羞。", "西風吹兼葭，倚玉嗟無由。"]'),
('46c0d90c-70df-4eff-9fb8-459028ba4584','再用前韵贈韶美','王十朋','宋','宋诗','song-poetry','','[]','平生少相識，摸索能記劉。',96,'全唐诗/poet.song.118000.json','["平生少相識，摸索能記劉。", "東南小蓬萊，二年同宦游。", "濯纓鑑湖水，佩蘭以潔修。", "自倚骯髒門，不撼富貴頭。", "西泛吳江瀾，委身謾乘流。", "回首望故鄉，天高路遐悠。", "慷慨君自喜，伊優吾亦羞。", "乘桴倘有志，願言呼仲由。"]'),
('04271cef-1089-4750-913e-29d8e9e9bf80','次韵韶美送劉夷叔二詩 悼夷叔','王十朋','宋','宋诗','song-poetry','','[]','蜀山高巖巖，英物世非少。',120,'全唐诗/poet.song.118000.json','["蜀山高巖巖，英物世非少。", "青藜卯金子，高步絕雲杪。", "思苦鳴輒悲，詞深誼難曉。", "知音有古人，紙上自傾倒。", "我昔賢關游，相逄粲衣表。", "東歸拜言贈，篋笥至今好。", "重來已鬼錄，魂魄蜀天渺。", "蓬山訪高躅，空舍不停繞。", "定尋窮孟郊，相酬類雙鳥。", "莫作人間來，世路轉難拗。"]'),
('4ecbcf17-2a9b-4318-a652-4884f13fb600','次韵韶美送劉夷叔二詩 贈韶美','王十朋','宋','宋诗','song-poetry','','[]','西南有佳士，岷峨秀匈中。',144,'全唐诗/poet.song.118000.json','["西南有佳士，岷峨秀匈中。", "標高語更妙，寫出岷峨容。", "青天道路難，冥冥慕蜚鴻。", "翩然下人間，海闊洪濤舂。", "尋幽入禹穴，杖屨誰相從。", "萬卷蟠腹笥，一榻眠禪叢。", "時來訪予語，自愧賢非戎。", "世態冷處薄，交情淡中濃。", "去歲鑑湖別，分甘老巖松。", "行藏果誰使，離合情無窮。", "田園有深約，耘耔當自充。", "異時甌蜀間，林下見兩翁。"]'),
('18768591-cd34-494e-8eb9-f604ff985561','皇子建王生日','王十朋','宋','宋诗','song-poetry','','[]','黄花過後梅花前，雲披愛日烘青天。',240,'全唐诗/poet.song.118000.json','["黄花過後梅花前，雲披愛日烘青天。", "月良陰剝陽欲旋，蓂餘八莢時半千。", "鬰葱佳氣燭星躔，帝子來從天日邊。", "淑質岐嶷貌端然，少親師傅學問專。", "六籍奧旨能心傳，百家諸司咸窮研。", "餘事翰墨工詩篇，平居爲善心拳拳。", "君親忠孝尤兩全，放遠聲色塵管絃。", "明窗自結賢聖緣，吾皇知子能擇賢。", "斷自宸衷愛不牽，九重一日丹詔宣。", "歡聲喜氣溢幅員，願王自愛思無愆。", "仰佩天眷奉周旋，保持王體如臨淵。", "日親端士遠佞便，紙上興衰鑒古先。", "誕宸朱邸錫玳筵，鼎來福祿方綿綿。", "不須丹竈求神仙，不用貝葉慕真詮。", "誠存性盡萬善圓，身與國壽俱千年。"]'),
('a9469e35-247a-4ec7-a187-9f25ff50054a','寄新曆日與夢齡昌齡弟','王十朋','宋','宋诗','song-poetry','','[]','老去驚看曆日新，宦情尤憶故園春。',32,'全唐诗/poet.song.118000.json','["老去驚看曆日新，宦情尤憶故園春。", "吾鄉親舊如相問，爲道明年已五旬。"]'),
('014e8011-250b-40dd-9f73-620990081d73','送查元章二首  其一','王十朋','宋','宋诗','song-poetry','','[]','聖主德寬大，小臣言激昂。',48,'全唐诗/poet.song.118000.json','["聖主德寬大，小臣言激昂。", "虜情殊未測，淮甸可無防。", "直氣思開日，寒威誤隕霜。", "芳姿等蘭蕙，摧折更芬香。"]'),
('2c511d0a-883b-4bf2-984b-456fb5f190dd','送查元章二首  其二','王十朋','宋','宋诗','song-poetry','','[]','肝腦不自愛，精忠爲上殫。',48,'全唐诗/poet.song.118000.json','["肝腦不自愛，精忠爲上殫。", "危言犯顔易，直道立身難。", "去國名逾重，還家迹始安。", "相將吾亦去，林下掛衣冠。"]'),
('7d9ae27f-0bd5-4e55-ad65-7b284e1946a0','祕書省後園脩竹可愛胡正字有詩次韵','王十朋','宋','宋诗','song-poetry','','[]','不俗更嫌俗，風枝時拂牆。',48,'全唐诗/poet.song.118000.json','["不俗更嫌俗，風枝時拂牆。", "青青映藜燭，細細雜芸香。", "勁節老方見，清陰寒欲藏。", "蕭疎似吾輩，味向靜中長。"]'),
('38ea4e6b-86bd-453f-838f-a2fce3618608','魏邦式通判挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','挺挺魏公後，重聞別乘賢。',48,'全唐诗/poet.song.118000.json','["挺挺魏公後，重聞別乘賢。", "有時同貞觀，無地上凌烟。", "雨足嘉禾穗，風清婺女蓮。", "吟魂招不返，遺恨越江邊。"]'),
('b2abf1c9-34d2-4e63-a39d-88d3ba9fe999','魏邦式通判挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','耆舊嗟零落，公年又不長。',48,'全唐诗/poet.song.118000.json','["耆舊嗟零落，公年又不長。", "雙旌空入夢，半刺橫罹殃。", "子舍三珠秀，吾鄉一鑑亡。", "平生可書事，椽筆有星郎。"]'),
('7a24d35b-a15f-414c-8108-9445dd6fe4ba','次韵程泰之正字雪中五絕  其一','王十朋','宋','宋诗','song-poetry','','[]','幻玉蜚花濕帝城，蓬萊燈火冷中清。',32,'全唐诗/poet.song.118000.json','["幻玉蜚花濕帝城，蓬萊燈火冷中清。", "人間草木舊相識，頃刻還驚面目生。"]'),
('798bf459-9050-4659-b775-5f2e3c937d21','次韵程泰之正字雪中五絕  其二','王十朋','宋','宋诗','song-poetry','','[]','栖烏驚起天無月，化鶴歸來頂不朱。',32,'全唐诗/poet.song.118000.json','["栖烏驚起天無月，化鶴歸來頂不朱。", "錯認湖山作西子，眩人疑是玉肌膚。"]'),
('d8aae70c-218c-41f1-8259-0855af44c4b9','次韵程泰之正字雪中五絕  其三','王十朋','宋','宋诗','song-poetry','','[]','點綴工夫巧更奇，崑崙玉果半葳蕤。',32,'全唐诗/poet.song.118000.json','["點綴工夫巧更奇，崑崙玉果半葳蕤。", "嗅梅咀雪欲腸斷，况讀高生人日詩。"]'),
('cdd1822a-78e1-42fe-a948-15938276e3b2','次韵程泰之正字雪中五絕  其四','王十朋','宋','宋诗','song-poetry','','[]','預知禾麥定登場，六出攙先瑞衆芳。',32,'全唐诗/poet.song.118000.json','["預知禾麥定登場，六出攙先瑞衆芳。", "更喜江梅自蕭灑，不緣摧壓減清香。"]'),
('3525ae14-c2c7-4e14-b86d-c46c59e9b698','次韵程泰之正字雪中五絕  其五','王十朋','宋','宋诗','song-poetry','','[]','卧聞征雁作回音，遥想吾廬玉滿林。',32,'全唐诗/poet.song.118000.json','["卧聞征雁作回音，遥想吾廬玉滿林。", "乘興扁舟定歸去，草堂深處伴猿吟。"]'),
('7a1dff54-4c17-40c2-9f8f-56dd21a73343','泰之用歐蘇潁中故事再作五絕勉强繼韵  其一','王十朋','宋','宋诗','song-poetry','','[]','君詩雅勝五言城，白雪篇章分外清。',32,'全唐诗/poet.song.118000.json','["君詩雅勝五言城，白雪篇章分外清。", "不許同僚持寸鐵，筆尖戰退老書生。"]'),
('9a6e2459-b0d9-4ceb-9d09-649198c1f3de','泰之用歐蘇潁中故事再作五絕勉强繼韵  其二','王十朋','宋','宋诗','song-poetry','','[]','寒侵睡思那成夢，酒著衰顔誤抹朱。',32,'全唐诗/poet.song.118000.json','["寒侵睡思那成夢，酒著衰顔誤抹朱。", "待詔先生應怯冷，餐氈使者可稱膚。"]'),
('6ea40d80-553c-4235-a04d-8810295d352f','泰之用歐蘇潁中故事再作五絕勉强繼韵  其三','王十朋','宋','宋诗','song-poetry','','[]','穀精蜚處人爲日，冰鑑頒時律應蕤。',32,'全唐诗/poet.song.118000.json','["穀精蜚處人爲日，冰鑑頒時律應蕤。", "照耀元宵更盈尺，不容燈火占新詩。"]'),
('dfcf3d14-ae29-4634-8d0a-ba7cb21b19bc','泰之用歐蘇潁中故事再作五絕勉强繼韵  其四','王十朋','宋','宋诗','song-poetry','','[]','煮海神功不計場，逼真冷焰奪春芳。',32,'全唐诗/poet.song.118000.json','["煮海神功不計場，逼真冷焰奪春芳。", "東君深恐成堆積，急遣雷公喚阿香。"]'),
('41c8fac7-8045-49b7-9a65-cb539c343220','泰之用歐蘇潁中故事再作五絕勉强繼韵  其五','王十朋','宋','宋诗','song-poetry','','[]','夜靜微聞折竹音，驚禽何處更投林。',32,'全唐诗/poet.song.118000.json','["夜靜微聞折竹音，驚禽何處更投林。", "寒生習氣無繇掃，遥對湖山忍凍吟。"]'),
('1490f4fe-d698-42ae-8a29-75e562e9dc43','趙仲永和東坡汝陰雪詩并舉趙德麟賑濟故事見示遂次其韵','王十朋','宋','宋诗','song-poetry','','[]','不作秦人視越人，深憐里舍甑生塵。',64,'全唐诗/poet.song.118000.json','["不作秦人視越人，深憐里舍甑生塵。", "恨無廣厦容寒士，安得洪爐煖曲身。", "草木照人俱有艷，珠璣滿地不憂貧。", "憑誰扶取浮雲破，莫待功成始放春。"]'),
('f54af548-230c-4b57-9ad5-8f391174a083','次韵洪景盧編修省中紅梅','王十朋','宋','宋诗','song-poetry','','[]','不爲怕寒貪睡遲，東君妙意端可知。',128,'全唐诗/poet.song.118000.json','["不爲怕寒貪睡遲，東君妙意端可知。", "雪英零落眼界寂，放此孤瘦紅南枝。", "蓬萊更向逸遠地，草木寧有夭饒姿。", "氷容戲作桃杏色，醉臉雅與神仙宜。", "江兄蠟友已前輩，黄生後出非同時。", "丹心獨與勁節侶，疏影共浸清漣漪。", "騷人相顧最不惡，何用車馬紛蚩蚩。", "典衣莫惜共携酒，對華一展思鄉眉。"]'),
('ae5f8533-03d0-41e9-b183-223e4c283294','李德遠寺簿敢言勇退今之古人也東嘉王某賦詩以高其行','王十朋','宋','宋诗','song-poetry','','[]','吳山蒼蒼烟靄橫，皇都日日春風生。',128,'全唐诗/poet.song.118000.json','["吳山蒼蒼烟靄橫，皇都日日春風生。", "利塗捷徑走輪轂，古道荆棘惟君行。", "吳江洪濤拍天洶，萬楫千帆日相踵。", "六鰲入釣猶不歸，急流知退惟君勇。", "斜川勝事今臨川，錦袍風月追謫仙。", "芋魁豆飯吾亦有，脫屣有媿君翩然。", "我輩情鍾惜離索，爲國惜賢情更惡。", "江頭送別春尚寒，回首冥鴻已寥廓。"]'),
('b498d2fc-37f8-4043-81c1-a768cb6ddafc','省中黄梅盛開同舍命予賦詩戲成四韵','王十朋','宋','宋诗','song-poetry','','[]','照眼非梅亦非菊，千葉繁英刻琮玉。',64,'全唐诗/poet.song.118000.json','["照眼非梅亦非菊，千葉繁英刻琮玉。", "色含天苑鵝兒黄，影蘸瀛波鴨頭綠。", "日烘喜氣光燭鬚，雨洗道裝鮮映肉。", "此梅開後更無梅，莫惜攀條飲醽醁。"]'),
('82229ac1-568e-4b44-91ad-2ecf4b5555fb','送王嘉叟編修','王十朋','宋','宋诗','song-poetry','','[]','上書請劔人未復，開口薦賢君又行。',96,'全唐诗/poet.song.118000.json','["上書請劔人未復，開口薦賢君又行。", "堂上伊優笑絕倒，紛紛去國皆狂生。", "搢紳敢言似慶曆，風俗漸美如東京。", "手揩老眼看除目，一遷一去知誰榮。", "南昌別駕亦不惡，三王高閣尋宗盟。", "吳江漫漫楚天闊，羨君一葉春舟輕。"]'),
('21aa2339-c09a-4ce9-9c36-a1285b078a3f','送陳阜卿出守吳興','王十朋','宋','宋诗','song-poetry','','[]','臺閣輟名士，符竹分帝憂。',96,'全唐诗/poet.song.118000.json','["臺閣輟名士，符竹分帝憂。", "搢紳有清議，欲爲朝端留。", "才名四十年，骯髒成白頭。", "方開公道口，遽中讒人鈎。", "觸邪孤壯志，歛惠施一州。", "命義二大戒，能言亦能由。", "去矣霅水清，孰障天下流。", "願言如季路，乘桴共公浮。"]'),
('af1e7a50-caea-48e3-9ad0-81df88d403ad','次韵程泰之酴醾','王十朋','宋','宋诗','song-poetry','','[]','青春果作堂堂去，啼鳥喚春春不住。',128,'全唐诗/poet.song.118000.json','["青春果作堂堂去，啼鳥喚春春不住。", "明珠萬顆玉爲錢，欲買風光嗟已莫。", "蓬山地冷花木稀，祗有寒梅已先雨。", "誰遣虬枝上高架，稍覺雲陰覆行路。", "雨餘景物猶未佳，葉底精神不多露。", "鼻觀疑聞班馬香，姿比何郎更風度。", "平生惜春如惜別，老眼待花如待哺。", "幽亭相對止三人，草草杯盤爲花具。"]'),
('ceb65262-a24a-4904-a345-17debb400b08','送胡正字分韵得來字','王十朋','宋','宋诗','song-poetry','','[]','武夷之山高崔嵬，武夷先生賢矣哉。',240,'全唐诗/poet.song.118000.json','["武夷之山高崔嵬，武夷先生賢矣哉。", "山中高卧似孤竹，顔蒼節勁清無埃。", "吾君養老過西伯，不遠千里歸乎來。", "胸中萬卷可醫國，首薦廊廟真人才。", "人言朝奏暮必逐，天顔獨爲忠言開。", "崇文三館不浪闢，端爲天下收奇瓌。", "平時論議即涵養，富貴豈以三緘媒。", "西京老儒作符命，蒼黄投閣良可哀。", "何如皇朝有歐范，開口不憚干霆雷。", "先生學力到前輩，一時盛事光麟臺。", "宸衷宵旰急忠讜，佇觀前席延鄒枚。", "先生掉頭竟不往，扁舟自載高風回。", "道山游從盡英雋，顧我晚進寧容陪。", "梅花滿枝柳弄色，賦詩送別同銜杯。", "吾廬三徑亦荒草，松菊怪我何遲徊。"]'),
('2ab28fe2-ac37-4c7d-bf8f-8aae1b7ec2f2','四月四日祀赤帝于慈雲嶺凈名寺祀畢游易安齋至江次送黄子升通判還鄉','王十朋','宋','宋诗','song-poetry','','[]','祀罷燈花喜，山游曉色新。',24,'全唐诗/poet.song.118000.json','["祀罷燈花喜，山游曉色新。", "江頭送歸客，我亦是行人。"]'),
('0a77f470-41e9-4088-9232-89c55692bec5','送太學生徐易歸天台','王十朋','宋','宋诗','song-poetry','','[]','天台古仙山，藥物固非一。',48,'全唐诗/poet.song.118000.json','["天台古仙山，藥物固非一。", "采之年可延，厥品惟參朮。", "茲誠籠中物，不可亡一日。", "良醫苟能用，可治天下疾。"]'),
('5969c0c7-393c-4145-b17d-adc0b30677f1','章季子教授惠顧渚茶報以宣城筆戲成三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','春回顧渚雪芽生，香味尤宜祕水亭。',32,'全唐诗/poet.song.118000.json','["春回顧渚雪芽生，香味尤宜祕水亭。", "搜我枯腸欠書卷，飲君清德頼詩情。"]'),
('9e4e157f-f37d-4f3f-94c6-9b4f4275a81b','章季子教授惠顧渚茶報以宣城筆戲成三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','白齒新芽不出山，青囊誰遣到人間。',32,'全唐诗/poet.song.118000.json','["白齒新芽不出山，青囊誰遣到人間。", "午窗驚覺還鄉夢，紗帽籠頭捧兔班。"]'),
('59792367-6ed0-4e2f-922b-0300613aa9b1','章季子教授惠顧渚茶報以宣城筆戲成三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','霅水書來寄葉嘉，中山人去代瓊華。',32,'全唐诗/poet.song.118000.json','["霅水書來寄葉嘉，中山人去代瓊華。", "定將絳帳鑄人手，散出毫端千種花。"]'),
('eb946b51-3eaf-46c0-b1fc-da0a96ea7be6','趙仲永和胡正字竹詩見贈用韵以酬','王十朋','宋','宋诗','song-poetry','','[]','憶昔游蓮幕，獲登君子牆。',48,'全唐诗/poet.song.118000.json','["憶昔游蓮幕，獲登君子牆。", "蓬萊醉秋月，龍鳳啜天香。", "臺閣子將集，山林予欲藏。", "新詩似脩竹，風味更高長。"]'),
('6cd11d97-56df-4ecf-afc7-279dc7e986a5','張閣學挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','南渡已三紀，衣冠今幾存。',48,'全唐诗/poet.song.118000.json','["南渡已三紀，衣冠今幾存。", "傷心失遺老，回首慨中原。", "去國權臣力，全軀聖主恩。", "致君堯舜術，妙意託空言。"]'),
('aecb736b-6718-4c72-81ef-4df8554086c7','張閣學挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','公在南昌日，含沙禍最奇。',48,'全唐诗/poet.song.118000.json','["公在南昌日，含沙禍最奇。", "語蜚無限謗，獄具不過詩。", "天道何嘗遠，人心自太危。", "蓋棺公論定，盛德合豐碑。"]'),
('b2f81141-1eac-4397-b78d-b06ed176641f','寶月師刻予舊題以寄因書二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','資深堂上偶留題，多謝高僧不掃泥。',32,'全唐诗/poet.song.118000.json','["資深堂上偶留題，多謝高僧不掃泥。", "更與慇懃琢山骨，惡詩傳到浙江西。"]'),
('888f8bd5-c311-4907-b751-eaf91908cdd7','寶月師刻予舊題以寄因書二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','冊府經年已倦游，夢魂隨雁到峯頭。',32,'全唐诗/poet.song.118000.json','["冊府經年已倦游，夢魂隨雁到峯頭。", "山中老宿如相問，爲道歸期不待秋。"]'),
('cb3f4386-e934-4f46-862d-af482f516c00','五月十八日去國明日宿富陽廟山懷館中同舍','王十朋','宋','宋诗','song-poetry','','[]','去國懷明主，離群念舊游。',24,'全唐诗/poet.song.118000.json','["去國懷明主，離群念舊游。", "翻令到家夢，終夜繞瀛洲。"]'),
('f8a91282-0584-4714-87a0-f7cf59f6c00e','寄馮員仲','王十朋','宋','宋诗','song-poetry','','[]','相見惟言去，吾今去已成。',24,'全唐诗/poet.song.118000.json','["相見惟言去，吾今去已成。", "著鞭先幾日，不及送君行。"]'),
('3849fb7c-f3d3-4935-8bd1-cac8e81821a7','釣臺','王十朋','宋','宋诗','song-poetry','','[]','漢高嫚駡四皓隠，周武干戈伯夷餓。',64,'全唐诗/poet.song.118000.json','["漢高嫚駡四皓隠，周武干戈伯夷餓。", "南陽故人幸無失，先生胡爲亦高卧。", "清風却在夷皓上，千古真能激貪懦。", "客星夜向釣灘明，想像年時臨帝座。"]'),
('34c181ca-9504-4241-8082-4e8e0a968b20','嚴州龍門院滿散天申節','王十朋','宋','宋诗','song-poetry','','[]','棹弭龍門下，誠馳天闕邊。',24,'全唐诗/poet.song.118000.json','["棹弭龍門下，誠馳天闕邊。", "平生畎畝意，祝聖更惓惓。"]'),
('dd88a981-b646-425f-a387-4bcf3d19b96b','宿永康縣黄塘店觀稼有感','王十朋','宋','宋诗','song-poetry','','[]','路入黄塘喜更疑，地名雖是里閭非。',32,'全唐诗/poet.song.118000.json','["路入黄塘喜更疑，地名雖是里閭非。", "眼中禾稼已如許，薄有田園宜早歸。"]'),
('f46965e3-b67d-40ce-9ad3-750445bdf595','永康有嶺名花錦被','王十朋','宋','宋诗','song-poetry','','[]','要將山水替埃塵，六月還家不憚辛。',32,'全唐诗/poet.song.118000.json','["要將山水替埃塵，六月還家不憚辛。", "炎暑厭聞花錦被，清凉宜近竹夫人。"]'),
('b0abfa96-9c75-4309-bfcc-dbeff53e4bea','舟中偶題','王十朋','宋','宋诗','song-poetry','','[]','綠水客星瀨，薰風婺女谿。',24,'全唐诗/poet.song.118000.json','["綠水客星瀨，薰風婺女谿。", "來尋處士隠，歸向斗中棲。"]'),
('59532627-cc4e-43fd-ad73-6afa9c2ae95b','游石門洞','王十朋','宋','宋诗','song-poetry','','[]','雁山飽見兩龍湫，洗眼新觀石洞流。',64,'全唐诗/poet.song.118000.json','["雁山飽見兩龍湫，洗眼新觀石洞流。", "欲向故鄉尋白鹿，先來仙隠訪青牛。", "破荒喜誦劉郎句，躋險思從謝客游。", "天下林泉看未足，分將身世早休休。"]'),
('4c190b40-fdc1-48b9-81f6-f1228a461677','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 贈明仲','王十朋','宋','宋诗','song-poetry','','[]','君家梅嶼我梅溪，一笑相逢郡治西。',32,'全唐诗/poet.song.118000.json','["君家梅嶼我梅溪，一笑相逢郡治西。", "要使衆山同對酒，芰荷香裏具親携。"]'),
('bdd564d9-4a59-4e95-8c9a-f651bd7ecafc','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 懷舊游','王十朋','宋','宋诗','song-poetry','','[]','塘餘春草遥思謝，樓面蒼陂重憶劉。',32,'全唐诗/poet.song.118000.json','["塘餘春草遥思謝，樓面蒼陂重憶劉。", "人昔共游今孰在，蘆花飛雪上吾頭。"]'),
('c53d69ea-d59a-4ace-9a95-93e5a5d60689','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 贈諸公 其一','王十朋','宋','宋诗','song-poetry','','[]','五人二百六十五，尊酒相逢非偶然。',32,'全唐诗/poet.song.118000.json','["五人二百六十五，尊酒相逢非偶然。", "把手共爲他日約，莫緣富貴負林泉。"]'),
('5c8c1de0-e2ee-49a2-b9b6-d3ea1b70b1d5','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 贈諸公 其二','王十朋','宋','宋诗','song-poetry','','[]','遥岑出碧明雙目，境入韓詩已飽參。',32,'全唐诗/poet.song.118000.json','["遥岑出碧明雙目，境入韓詩已飽參。", "湖上軒窗對遥碧，新詩寫出舊城南。"]'),
('290bd85d-7bb5-4429-a7be-86644c6999b5','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 題宋莊','王十朋','宋','宋诗','song-poetry','','[]','地環碧玉軒窗瑩，舟入紅雲笑語香。',32,'全唐诗/poet.song.118000.json','["地環碧玉軒窗瑩，舟入紅雲笑語香。", "下筆慚無少陵句，老懷徒愛宋公莊。"]'),
('a40f7ab9-9bd3-4861-ba0a-d3d6253c032c','林明仲自梅嶼挐舟招丁道濟道揆張思豫及予同飲索詩坐間成六絕七月朔日 題西岑','王十朋','宋','宋诗','song-poetry','','[]','西岑風物冠吾鄉，十里烟波興味長。',32,'全唐诗/poet.song.118000.json','["西岑風物冠吾鄉，十里烟波興味長。", "不用扁舟鑑湖去，餘生甘向此徜徉。"]'),
('2588205f-2da9-4820-9e7d-243214d5a595','次韵昌齡至樂齋讀書','王十朋','宋','宋诗','song-poetry','','[]','端慕顔回樂，真同陋巷居。',48,'全唐诗/poet.song.118000.json','["端慕顔回樂，真同陋巷居。", "息心容膝地，得趣滿牀書。", "檠短燈宵永，窗明日晷舒。", "相看有脩竹，心爲主人虛。"]'),
('075227a5-eb71-4764-9e62-afb94cc96169','寶印叔示詩且索碑刻以南明山六大字爲獻仍次韵','王十朋','宋','宋诗','song-poetry','','[]','不才詎可登臺省，早問君王覓閑冷。',64,'全唐诗/poet.song.118000.json','["不才詎可登臺省，早問君王覓閑冷。", "聊尋商嶺綺與園，未羨雲臺寇并耿。", "掛碑滿屋寧寮饑，嗜好與叔真相宜。", "試寄南明六大字，想像年少西游時。"]'),
('b801040e-550d-45fa-9dc9-394f2ba3f261','寶印叔辯上人各贈瑞香花','王十朋','宋','宋诗','song-poetry','','[]','小小園林意自憐，名花十八擬唐賢。',32,'全唐诗/poet.song.118000.json','["小小園林意自憐，名花十八擬唐賢。", "瑞香一種來潛澗，學士新添兩少年。"]'),
('9d9b4c70-a657-4034-8470-eb8689568f61','曹夢良自許峰來訪留山間數日賦詩數十章復出四絕見贈次韵  其一','王十朋','宋','宋诗','song-poetry','','[]','徑荒猶有淵明菊，囊澀寧求季子金。',32,'全唐诗/poet.song.118000.json','["徑荒猶有淵明菊，囊澀寧求季子金。", "老矣此身何處著，入山惟恐未能深。"]'),
('099af6a1-8730-4962-b169-3e497c9f02c0','曹夢良自許峰來訪留山間數日賦詩數十章復出四絕見贈次韵  其二','王十朋','宋','宋诗','song-poetry','','[]','謾有忠懷徒耿耿，恨無長策捄元元。',32,'全唐诗/poet.song.118000.json','["謾有忠懷徒耿耿，恨無長策捄元元。", "張儀舌在知何用，莫莫休休且勿言。"]'),
('f7339c8c-9ca7-4ebd-8e62-fe635835895c','曹夢良自許峰來訪留山間數日賦詩數十章復出四絕見贈次韵  其三','王十朋','宋','宋诗','song-poetry','','[]','平生風義慕相如，筆硯從游二紀餘。',32,'全唐诗/poet.song.118000.json','["平生風義慕相如，筆硯從游二紀餘。", "直許交情定金石，肯同餘耳但光初。"]'),
('b53d59f5-4055-4bab-8f6a-addea0cc87d2','曹夢良自許峰來訪留山間數日賦詩數十章復出四絕見贈次韵  其四','王十朋','宋','宋诗','song-poetry','','[]','與君連夕燈前語，勝讀千年窗下書。',32,'全唐诗/poet.song.118000.json','["與君連夕燈前語，勝讀千年窗下書。", "八斗文章千里足，未應低首掾桐廬。"]'),
('16d54061-468a-4de3-8694-03f3718871d4','先人舊題東山墓亭三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','入堂無復見雙親，建此來寧似在神。',32,'全唐诗/poet.song.118000.json','["入堂無復見雙親，建此來寧似在神。", "天地深恩難以報，含悲唯有淚霑巾。"]'),
('09b6a67b-99bb-46c1-b887-6622f3de01ad','先人舊題東山墓亭三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','門枕青山戶傍谿，青山流水助悽悽。',32,'全唐诗/poet.song.118000.json','["門枕青山戶傍谿，青山流水助悽悽。", "雙親既遠神何在，對此追思獨怨啼。"]'),
('15c79519-4983-4ef4-b385-c063a95635b4','先人舊題東山墓亭三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','新築茅廬澗壑圍，山光水色共依依。',32,'全唐诗/poet.song.118000.json','["新築茅廬澗壑圍，山光水色共依依。", "野人不爲閑中趣，誰會朝來與暮歸。"]'),
('c763881b-0ed4-4208-a9c6-a8074c9ebeee','某辛巳秋歸自武林省先隴遂修亭宇濬溪流因思先人舊詩已隨屋璧壞矣尚能記憶遂追和  其一','王十朋','宋','宋诗','song-poetry','','[]','殘生無計可榮親，一見松楸一損神。',32,'全唐诗/poet.song.118000.json','["殘生無計可榮親，一見松楸一損神。", "惟有青山知此意，晨昏長戴白雲巾。"]'),
('e727db74-fa2d-4019-95e1-a0a7a1ebc7f9','某辛巳秋歸自武林省先隴遂修亭宇濬溪流因思先人舊詩已隨屋璧壞矣尚能記憶遂追和  其二','王十朋','宋','宋诗','song-poetry','','[]','重葺山亭濬舊溪，杖藜來徃獨悲悽。',32,'全唐诗/poet.song.118000.json','["重葺山亭濬舊溪，杖藜來徃獨悲悽。", "追思四十年間事，風爲哀號鳥爲啼。"]'),
('3b8fba1f-b869-4bb9-b337-c5496bc25cd4','某辛巳秋歸自武林省先隴遂修亭宇濬溪流因思先人舊詩已隨屋璧壞矣尚能記憶遂追和  其三','王十朋','宋','宋诗','song-poetry','','[]','丘木森森已十圍，滿林清蔭可棲依。',32,'全唐诗/poet.song.118000.json','["丘木森森已十圍，滿林清蔭可棲依。", "每憂樵牧傷松柏，游宦三年兩度歸。"]'),
('6b5172f4-f9b5-4bda-80b6-44c721dd69e1','送萬先之赴清湘教官','王十朋','宋','宋诗','song-poetry','','[]','早歲聲名滿上庠，青衫今始赴清湘。',64,'全唐诗/poet.song.118000.json','["早歲聲名滿上庠，青衫今始赴清湘。", "得官已晚豈宜冷，行路正難那更長。", "平昔心期良不淺，異時官業可能量。", "鵬程九萬從今日，行見飛飛到帝旁。"]'),
('d3fd4801-f9d7-4cde-9bc0-59ac5db5dad7','送曹夢良赴桐廬戶掾  其一','王十朋','宋','宋诗','song-poetry','','[]','年少論交老愈堅，交情盡在和韓篇。',64,'全唐诗/poet.song.118000.json','["年少論交老愈堅，交情盡在和韓篇。", "短檠業共賢關舍，淡墨名同桂籍年。", "筮仕暫爲三語掾，摛詞行踐八花磚。", "許峯佳讖亦聊耳，何止蓬萊山上仙。"]'),
('0bb7cd3f-71d3-4065-a910-e66eda5b2211','送曹夢良赴桐廬戶掾  其二','王十朋','宋','宋诗','song-poetry','','[]','鷄黍相尋豈偶然，論文尊酒荷留連。',64,'全唐诗/poet.song.118000.json','["鷄黍相尋豈偶然，論文尊酒荷留連。", "秋風初送雁群至，喬木喜聞鶑友遷。", "勸我鑑湖行甚力，送君釣瀨去無緣。", "願將清白師韓范，從此高堂有四賢。"]'),
('ed11be7d-d59b-4a15-86e6-c439ee2a2b86','送曹夢良赴桐廬戶掾  其三','王十朋','宋','宋诗','song-poetry','','[]','需次家鄉五載遲，便便腹笥愈添圍。',65,'全唐诗/poet.song.118000.json','["需次家鄉五載遲，便便腹笥愈添圍。", "才如子建豈論斗，性類西門能佩韋。", "車馬戒塗涂君欲去，田園迷徑我初歸。", "男兒所尚惟名節，莫墮人間富貴機。"]'),
('64035cc9-5c29-4040-b74d-32e460a721fa','十月朔日偶書','王十朋','宋','宋诗','song-poetry','','[]','去年此日對清光，聖德能容一介狂。',32,'全唐诗/poet.song.118000.json','["去年此日對清光，聖德能容一介狂。", "言畧施行非不遇，身雖疏外亦何妨。"]'),
('753c090d-56ce-4cdd-b46c-87438999d857','剪拂花木戲成二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','灑掃衡茅端欲老，剪裁花木自爲春。',32,'全唐诗/poet.song.118000.json','["灑掃衡茅端欲老，剪裁花木自爲春。", "權門炙手非吾事，祇合丘園作散人。"]'),
('e5221058-148d-49d8-a634-b8a42ff8bf09','剪拂花木戲成二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','蔓草芟夷莫許侵，好花封植待成陰。',32,'全唐诗/poet.song.118000.json','["蔓草芟夷莫許侵，好花封植待成陰。", "每於小小園林裏，長抱惓惓畎畝心。"]'),
('1fb40b41-f4e0-4d92-aca3-8211f85c9f63','小小園十月杜鵑花盛開有共蔕雙頭之異因以數語記之','王十朋','宋','宋诗','song-poetry','','[]','一聲杜宇啼春風，明朝緋掛千山叢。',64,'全唐诗/poet.song.118000.json','["一聲杜宇啼春風，明朝緋掛千山叢。", "歲寒此色豈易得，那更朶朶雙頭紅。", "共蔕聯芳友于愛，一吐一含分次第。", "造物私我小園林，此花大勝金腰带。"]'),
('da4dcb5a-02ad-4dbf-ad71-f202611a5e86','題月師桂堂','王十朋','宋','宋诗','song-poetry','','[]','道人以月名身，以桂名堂。',80,'全唐诗/poet.song.118000.json','["道人以月名身，以桂名堂。", "胸中負所有，志在丹霄旁。", "冠巾倘可加，唾手得天香。", "惜哉已世外，此志終莫償。", "山中作堂侔月窟，禪定吟餘思清越。", "要令坐上生清風，須使心中似明月。"]'),
('a811f75b-0e38-4a13-9f6d-153eb2ce187c','十一月二日自金谿訪錢用章于白石覽山川景物之奇以東道之姓爲韵','王十朋','宋','宋诗','song-poetry','','[]','朝離文君故宅邊，莫尋謝守舊行田。',64,'全唐诗/poet.song.118000.json','["朝離文君故宅邊，莫尋謝守舊行田。", "黄羊先示神仙迹，白石俄開洞府天。", "兩派崇崢鳴玉澗，一聲欵乃釣魚船。", "王孫占得湖山勝，明月清風不計錢。"]'),
('dcb5b7ef-30bd-4ee8-9014-37b64907880c','同錢用明用章游白石巖','王十朋','宋','宋诗','song-poetry','','[]','謝公好山水，得郡古東甌。',216,'全唐诗/poet.song.118000.json','["謝公好山水，得郡古東甌。", "造物惜佳境，雅志多不酬。", "松蘿蔽雁蕩，烟靄埋龍湫。", "行田經白石，不到仙山頭。", "寥寥數百年，天付黄冠流。", "巍然萬仞崖，壁立東南州。", "誰將補天手，化出白玉樓。", "兩龕藏洞府，中有群仙游。", "上通尺五天，下接三神洲。", "飛泉落巖腰，碧澗鳴山陬。", "群峯真培塿，滄海爲渠溝。", "隘視人間世，萬象同蜉蝣。", "我家雁山陽，崎嶇厭經丘。", "翩翩錢公子，呼我尋巖幽。", "初驚小雨密，忽掃群陰浮。", "杖屨窮巑岏，一洗塵埃眸。", "山林有真樂，富貴何足求。", "但願乞二山，不願萬戶侯。"]'),
('02ac69fc-b2d3-4664-bd0c-bff595442142','又書巖上','王十朋','宋','宋诗','song-poetry','','[]','十里湖山翠黛橫，兩溪寒玉鬬琮琤。',64,'全唐诗/poet.song.118000.json','["十里湖山翠黛橫，兩溪寒玉鬬琮琤。", "路從飛鳥上頭過，人在白雲高處行。", "巖下行田謝康樂，洞中辟穀李先生。", "憑欄不瞰人間世，轉覺此心名利輕。"]'),
('3ab84522-9e32-4893-8b2d-de3c2c37208d','屑玉泉','王十朋','宋','宋诗','song-poetry','','[]','白石巖腰屑玉泉，佳名初自長官傳。',32,'全唐诗/poet.song.118000.json','["白石巖腰屑玉泉，佳名初自長官傳。", "渾疑齒頰冰霜論，終日霏霏落半天。"]'),
('0da8474c-eeff-4985-868f-52e0e6f1ff43','李少和像','王十朋','宋','宋诗','song-poetry','','[]','少和辛苦學飛仙，遺像今猶在洞天。',32,'全唐诗/poet.song.118000.json','["少和辛苦學飛仙，遺像今猶在洞天。", "都似先生能辟穀，何須太守爲行田。"]'),
('ae1951a5-d24c-4d55-9046-a1153b519bd1','游東際','王十朋','宋','宋诗','song-poetry','','[]','白石三峯下，懸崖七際流。',48,'全唐诗/poet.song.118000.json','["白石三峯下，懸崖七際流。", "穿雲來汩汩，朝海去悠悠。", "石是誰家婦，龍居第幾湫。", "平生不行險，到此即回頭。"]'),
('21526a3e-bc0e-4231-b72b-b83faf2a5f41','次韵寶印叔觀海三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','載地浮天浩莫窮，氣營樓閣聳虛空。',32,'全唐诗/poet.song.118000.json','["載地浮天浩莫窮，氣營樓閣聳虛空。", "道人妙得觀瀾術，萬里滄溟碧眼中。"]'),
('a7b87c65-bb63-436a-bbef-bcb089195e93','次韵寶印叔觀海三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','榴嶼何年改玉環，望中猶是舊青山。',32,'全唐诗/poet.song.118000.json','["榴嶼何年改玉環，望中猶是舊青山。", "遺民不記當時事，惟有潮聲日徃還。"]'),
('8198b33c-d95b-4f0a-aab4-53a41209abbb','次韵寶印叔觀海三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','誤入蓬萊朝未央，至今魂夢記微茫。',32,'全唐诗/poet.song.118000.json','["誤入蓬萊朝未央，至今魂夢記微茫。", "扁舟欲效鴟夷子，遥望滄波興已狂。"]'),
('449ccf0c-6df1-4549-86d8-1eab0f83b77a','李鎮夫闢圃築堂效孟氏之養吾表兄杖屨其間得日涉之趣某來游名堂曰雙植因書三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','不到君家幾換春，眼中風物一番新。',32,'全唐诗/poet.song.118000.json','["不到君家幾換春，眼中風物一番新。", "吾園小小知何用，不似茲園可養親。"]'),
('5a091345-f0a5-4f39-9c08-9d5bc3da10e7','李鎮夫闢圃築堂效孟氏之養吾表兄杖屨其間得日涉之趣某來游名堂曰雙植因書三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','琴書得趣有真樂，軒冕倘來何足干。',32,'全唐诗/poet.song.118000.json','["琴書得趣有真樂，軒冕倘來何足干。", "種德種花兼著力，要須留與子孫看。"]'),
('69419f91-2fe6-4808-982a-0a4b411d6a39','李鎮夫闢圃築堂效孟氏之養吾表兄杖屨其間得日涉之趣某來游名堂曰雙植因書三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','繞堂花木隨宜種，堆案文書取次翻。',32,'全唐诗/poet.song.118000.json','["繞堂花木隨宜種，堆案文書取次翻。", "我待衣冠掛林下，杖藜時復到君園。"]'),
('dcef267f-13a4-49e8-a2bf-8cd5b7573bb5','劉長方自豫章寄書稱砮焦蠣房之美恨未知味書一絕以寄之','王十朋','宋','宋诗','song-poetry','','[]','珠嶼小蠣圓带石，砮焦巨房深若盃。',32,'全唐诗/poet.song.118000.json','["珠嶼小蠣圓带石，砮焦巨房深若盃。", "吾鄉此味亦不惡，故人游宦盍歸來。"]'),
('0991aae4-c8fc-4f83-b243-91b2149fe695','寶印叔得小假山以長篇模寫進士欽逢辰和之某次韵并簡欽','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','越絕天台溫雁蕩，萬壑千巖各形狀。',192,'全唐诗/poet.song.118000.json','["越絕天台溫雁蕩，萬壑千巖各形狀。", "錢塘風物更奇絕，杖屨年時記曾訪。", "歸來戲闢小園林，十里西湖藏甕盎。", "悠然入眼皆吾山，羅列軒窗一何壯。", "止菴道人真有道，種竹蒔花近丘壙。", "何人好事贈假山，潛澗新添小屏嶂。", "却疑遷徙從平泉，更恐飛來自秦望。", "世間贋物何止此，沙佛儒衣龍亦象。", "道人於物意豈留，異日從教散天壤。", "花木篇章兩游戲，林下高風真可尚。", "來游蓮社有詩人，句比昌黎更豪放。", "我休說假復論真，真假通同歸一相。"]'),
('6fa61ee3-5e64-47f9-8020-f1024f100dfd','次韵昌齡西園十詠 黄楊蘚復有生意','王十朋','宋','宋诗','song-poetry','','[]','黄楊庚甲與吾同，樹已蕭踈我亦翁。',32,'全唐诗/poet.song.118000.json','["黄楊庚甲與吾同，樹已蕭踈我亦翁。", "藤蔓稍除苔蘚去，歲寒猶解傲霜風。"]'),
('8c140945-9bfd-4a31-89a3-5b77b6de8e93','次韵昌齡西園十詠 莆萄','王十朋','宋','宋诗','song-poetry','','[]','滿架龍鬚卷復伸，堆盤馬乳釀青春。',32,'全唐诗/poet.song.118000.json','["滿架龍鬚卷復伸，堆盤馬乳釀青春。", "潑醅一斗宜延客，莫博凉州學漢人。"]'),
('d5146328-3918-4b87-b6a6-26de2af51b9d','次韵昌齡西園十詠 脩竹','王十朋','宋','宋诗','song-poetry','','[]','至樂齋西碧玉竿，清陰時過酒杯寒。',32,'全唐诗/poet.song.118000.json','["至樂齋西碧玉竿，清陰時過酒杯寒。", "明年看長纖纖筍，解籜當爲漢帝冠。"]'),
