('8488144a-48ca-4990-8161-ad1a39bfcb08','予還自武林葺先人弊廬浄掃一室晨起焚香讀書於其間興至賦詩客來飲酒啜茶或弈棋爲戲藏書數百卷手自暴之有小園時策杖以游，時遇秋旱驅家僮浚井汲水澆花良天佳月與兄弟鄰里把酒盃同賞過重九方見菊以泛觴有足樂者每覽鏡見蒼顔白髮亦聊自歎也作小詩十五首 覽鏡','王十朋','宋','宋诗','song-poetry','','[]','可正宜頻覽，無塵亦自磨。',24,'全唐诗/poet.song.119000.json','["可正宜頻覽，無塵亦自磨。", "少陵今老矣，功業欲如何。"]'),
('59e13650-1fcc-4f96-9099-7badd0074e4c','予還自武林葺先人弊廬浄掃一室晨起焚香讀書於其間興至賦詩客來飲酒啜茶或弈棋爲戲藏書數百卷手自暴之有小園時策杖以游，時遇秋旱驅家僮浚井汲水澆花良天佳月與兄弟鄰里把酒盃同賞過重九方見菊以泛觴有足樂者每覽鏡見蒼顔白髮亦聊自歎也作小詩十五首 浚井','王十朋','宋','宋诗','song-poetry','','[]','旱久井垂涸，汲多泉更渾。',24,'全唐诗/poet.song.119000.json','["旱久井垂涸，汲多泉更渾。", "浚教泥凈盡，何患不逢原。"]'),
('f0d00af0-058f-4718-a09f-d69e7f64e39b','酬林明仲寄書并長篇','王十朋','宋','宋诗','song-poetry','','[]','江頭一別九十日，路隔烟波望欲迷。',64,'全唐诗/poet.song.119000.json','["江頭一別九十日，路隔烟波望欲迷。", "風送雁群來雁蕩，書從梅嶼到梅谿。", "羨君筆力能豪健，贈我詩篇過品題。", "謝客江山富觀覽，城南何日手重携。"]'),
('30005e90-e800-45de-afdd-7d61837bb2ea','昌齡欲游白石興盡而止予亦思前年之游遂次其韻','王十朋','宋','宋诗','song-poetry','','[]','前年蠟屐遠尋幽，洞府曾經一宿留。',64,'全唐诗/poet.song.119000.json','["前年蠟屐遠尋幽，洞府曾經一宿留。", "詩句親題碧雲裏，夢魂時到白巖頭。", "風生見說欲飛去，興盡何如且罷休。", "他日相呼老兄弟，飄然杖屨共翱游。"]'),
('a5de9e25-2939-433f-baca-ed2bbe07eae7','洪丞不負軒','王十朋','宋','宋诗','song-poetry','','[]','坐此軒無媿，問君何以能。',48,'全唐诗/poet.song.119000.json','["坐此軒無媿，問君何以能。", "所行皆是學，不負豈惟丞。", "鳬鶩文書靜，槐松詩思凝。", "博陵徒種績，踐履亦何曾。"]'),
('2f32574b-ad0b-4f23-a1a3-d4064190ddcb','周丞奉挽詩','王十朋','宋','宋诗','song-poetry','','[]','平生義方教，真是起家媒。',48,'全唐诗/poet.song.119000.json','["平生義方教，真是起家媒。", "有子願已足，無心官自來。", "興隨鳩杖逸，情爲雁行哀。", "想見長塘水，凄凉遶夜臺。"]'),
('de2cd042-fd12-44a9-afac-b1901a4a41b0','黄巖趙十朋賢士也有詩云四枚豚犬教知書二頃良田儘有餘魯酒三盃棋一局客來渾不問親疏予亦有東皋二頃，兩子皆學讀書客至則弈棋飲酒遂用趙君詩意成一絕','王十朋','宋','宋诗','song-poetry','','[]','薄有田園種斗升，兩兒傳授讀書燈。',32,'全唐诗/poet.song.119000.json','["薄有田園種斗升，兩兒傳授讀書燈。", "客來一局三盃酒，王十朋如趙十朋。"]'),
('8118c8f0-5ebf-4685-9193-33b043e0605e','陳商英挽詞','王十朋','宋','宋诗','song-poetry','','[]','貴似金張富石崇，紛紛老死利名中。',64,'全唐诗/poet.song.119000.json','["貴似金張富石崇，紛紛老死利名中。", "退居不見香山老，肥遁誰知秀野翁。", "溪上園因種花闢，牀頭金爲好賓空。", "潸然痛念公兄弟，二十年前筆硯同。"]'),
('24da1913-8f02-4c80-95b1-dc9d50f95000','陳商霖挽詞','王十朋','宋','宋诗','song-poetry','','[]','疇昔游從分不輕，十年鄉校讀書燈。',64,'全唐诗/poet.song.119000.json','["疇昔游從分不輕，十年鄉校讀書燈。", "德星會聚三兄弟，詩社追隨八友朋。", "去國悲凉老王粲，還鄉牢落失陳登。", "誦君生死炎凉句，斜日寒天涕滿膺。"]'),
('cd3c6b24-66a1-44ba-a4c8-2869996e00b8','萬清之有詩三絕呈司理賈丈并簡某因次其韻  其一','王十朋','宋','宋诗','song-poetry','','[]','燈花端爲故人然，留客殷勤爲擊鮮。',32,'全唐诗/poet.song.119000.json','["燈花端爲故人然，留客殷勤爲擊鮮。", "更覺門闌增喜氣，氷清玉潤兩俱賢。"]'),
('b3e971ce-b033-4ebc-8644-317d3409f5a4','萬清之有詩三絕呈司理賈丈并簡某因次其韻  其二','王十朋','宋','宋诗','song-poetry','','[]','世路塵埃逐日生，鹿巖高卧自風清。',32,'全唐诗/poet.song.119000.json','["世路塵埃逐日生，鹿巖高卧自風清。", "吾皇有詔求遺逸，行見臨雍拜老更。"]'),
('2cbdee4b-d50e-4b16-bae4-00f91cd61c6f','萬清之有詩三絕呈司理賈丈并簡某因次其韻  其三','王十朋','宋','宋诗','song-poetry','','[]','甘言耻效蜜翁翁，逆耳空餘畎畝忠。',32,'全唐诗/poet.song.119000.json','["甘言耻效蜜翁翁，逆耳空餘畎畝忠。", "願子他年似房杜，好將一語記文中。"]'),
('a28651da-6624-44d5-9304-56b670abc2e2','再用前韻 呈司理','王十朋','宋','宋诗','song-poetry','','[]','論文尊酒意歡然，蠟炬高燒夜色鮮。',32,'全唐诗/poet.song.119000.json','["論文尊酒意歡然，蠟炬高燒夜色鮮。", "得壻端同權相國，傳經更似老韋賢。"]'),
('8e27d78b-b824-4a06-82d5-430f7729ac4f','再用前韻 酬清之','王十朋','宋','宋诗','song-poetry','','[]','僚壻欣逢舊友生，人如王謝氣尤清。',32,'全唐诗/poet.song.119000.json','["僚壻欣逢舊友生，人如王謝氣尤清。", "十年前已心相許，細看新詩貌愈更。"]'),
('a75be816-e013-459f-b766-45d87980560c','再用前韻 贈大老','王十朋','宋','宋诗','song-poetry','','[]','士論鄉評重乃翁，賢如狐突教兒忠。',32,'全唐诗/poet.song.119000.json','["士論鄉評重乃翁，賢如狐突教兒忠。", "治安策就君宜獻，宣室開時夜正中。"]'),
('c0589f89-b1ed-4383-9f42-b580cc72dbba','未臘而雪豐年兆也大老有詩次韻  其一','王十朋','宋','宋诗','song-poetry','','[]','明年禾黍定千鍾，瑞雪攙先舞曉風。',32,'全唐诗/poet.song.119000.json','["明年禾黍定千鍾，瑞雪攙先舞曉風。", "更願平淮捷書至，西平禽賊獻司空。"]'),
('9d157402-03d5-4562-8ca7-3fd9149b2fdd','未臘而雪豐年兆也大老有詩次韻  其二','王十朋','宋','宋诗','song-poetry','','[]','主人開燕倒金鍾，坐客俱吟柳絮風。',32,'全唐诗/poet.song.119000.json','["主人開燕倒金鍾，坐客俱吟柳絮風。", "應念人間有貧者，爐星撥盡酒瓶空。"]'),
('38d276f5-4ef9-461a-84ad-5fb88722bd15','雪中寄梅花與清之大老','王十朋','宋','宋诗','song-poetry','','[]','天花除惱臘前雪，香蘂報春溪上梅。',32,'全唐诗/poet.song.119000.json','["天花除惱臘前雪，香蘂報春溪上梅。", "分贈鹿巖龍穴友，異時俱是百花魁。"]'),
('307e4976-690f-4d45-869f-4a02953c7e39','題夢齡五桂堂','王十朋','宋','宋诗','song-poetry','','[]','我昔曾栽會趣堂，子今封植更芬芳。',64,'全唐诗/poet.song.119000.json','["我昔曾栽會趣堂，子今封植更芬芳。", "勝它福峙三珠樹，賽却東嘉五馬坊。", "靖節柳青寧耐久，大夫松老恨無香。", "何如移得蟾宮種，不媿靈椿竇十郎。"]'),
('79586c7a-ab1d-481f-8054-0e29f9cd0f20','寄鯉魚與萬大年','王十朋','宋','宋诗','song-poetry','','[]','江楓摇落江梅破，江上詩人有佳句。',32,'全唐诗/poet.song.119000.json','["江楓摇落江梅破，江上詩人有佳句。", "欲於龍穴覓明珠，試遣鯉魚傳尺素。"]'),
('04245bdd-a148-4554-b5ca-4ab58b078183','梁府君挽詩','王十朋','宋','宋诗','song-poetry','','[]','兩郡三鄉頼保全，乃翁劍學不虛傳。',64,'全唐诗/poet.song.119000.json','["兩郡三鄉頼保全，乃翁劍學不虛傳。", "黄巢詎敢臣周朴，趙勝那能爵魯連。", "仁里化成儒氣象，心田種得佛因緣。", "奇兒自是青雲士，行見榮光燭九泉。"]'),
('4f71e8bb-d1ee-422a-bf92-cce9d22a1bbc','永嘉盧仲脩永年袖文見訪酬以短句','王十朋','宋','宋诗','song-poetry','','[]','地僻原名左，天寒歲欲徂。',48,'全唐诗/poet.song.119000.json','["地僻原名左，天寒歲欲徂。", "遥遥屈佳客，得得訪潛夫。", "一第且慁子，八篇真起予。", "蜚聲參四傑，誰復敢前盧。"]'),
('9bdb939c-f7d0-4bd0-95ff-8dda70c14bfd','林明仲和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','屢戰夷吾卒覇齊，棘棲鸞鳳暫沉迷。',64,'全唐诗/poet.song.119000.json','["屢戰夷吾卒覇齊，棘棲鸞鳳暫沉迷。", "探春想見登梅嶼，乘興何訪從雪溪。", "樓上清歡庾公興，橋間壯志馬卿題。", "四場筆力媒身策，平步青雲豈待携。"]'),
('b140bb13-7ada-4305-ad59-5221a094103f','張器先和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','心欲齊賢媿未齊，遠蒙佳句警昏迷。',64,'全唐诗/poet.song.119000.json','["心欲齊賢媿未齊，遠蒙佳句警昏迷。", "音如鼓瑟鏗清廟，味似煎茶鬭建溪。", "憂國非同長卿病，感時端類少陵題。", "二松豈是淹賢地，鳬鶩文書謾抱携。"]'),
('294c56f2-9307-409b-8471-951d21ff1549','寄蒲墨與明仲','王十朋','宋','宋诗','song-poetry','','[]','四友共文房，蒲君最異常。',24,'全唐诗/poet.song.119000.json','["四友共文房，蒲君最異常。", "研磨發文采，好去奉仇香。"]'),
('b5d1bf02-0146-461d-a36d-4772298ef362','寄沈敦謨','王十朋','宋','宋诗','song-poetry','','[]','二十年前舊友生，緘封遠寄見交情。',32,'全唐诗/poet.song.119000.json','["二十年前舊友生，緘封遠寄見交情。", "舊游回首多零落，大噐如君合晚成。"]'),
('5c7797cb-2920-492b-acd0-9c696ac7bbd8','送謝任之  其一','王十朋','宋','宋诗','song-poetry','','[]','七歲吾從乃祖游，童蒙深媿未能求。',32,'全唐诗/poet.song.119000.json','["七歲吾從乃祖游，童蒙深媿未能求。", "堪嗟四十五年事，昔未裹頭今白頭。"]'),
('b144ceca-bc2c-4247-8aab-5210318ca2e7','送謝任之  其二','王十朋','宋','宋诗','song-poetry','','[]','梅溪闢館子來游，回首如今二十秋。',32,'全唐诗/poet.song.119000.json','["梅溪闢館子來游，回首如今二十秋。", "端似韓張互傳授，要令編剗紹箕裘。"]'),
('f623535a-8841-4e85-a4b0-9fe2319dc4f0','送謝任之  其三','王十朋','宋','宋诗','song-poetry','','[]','去年還家已半年，盍簪尊酒數留連。',32,'全唐诗/poet.song.119000.json','["去年還家已半年，盍簪尊酒數留連。", "歲窮送別溪頭路，手把梅花思黯然。"]'),
('09ea3ec4-c710-457c-82f3-7c6707f3741c','題雙瀑','王十朋','宋','宋诗','song-poetry','','[]','女媧石爛幾經修，天漏猶餘兩派流。',64,'全唐诗/poet.song.119000.json','["女媧石爛幾經修，天漏猶餘兩派流。", "離合無心元不靜，朝宗得路却相投。", "干雲寶劔真同氣，出蕩神龍不異湫。", "何用築門防俗駕，林泉自是少人游。"]'),
('d5358776-cf30-4e4f-84e7-dcb5f8414a20','癸未守歲','王十朋','宋','宋诗','song-poetry','','[]','歲宜鄉里守，杯共弟兄銜。',24,'全唐诗/poet.song.119000.json','["歲宜鄉里守，杯共弟兄銜。", "明日人相問，行年五十三。"]'),
('a2c9ab32-a487-48d9-8a21-b06c0723c5d9','張器先復和詩作五言以寄','王十朋','宋','宋诗','song-poetry','','[]','短棹別孤嶼，故山歸左原。',48,'全唐诗/poet.song.119000.json','["短棹別孤嶼，故山歸左原。", "遥煩雁足字，重到雀羅門。", "歲月添新老，文章憶舊論。", "見詩如見面，氣象有餘溫。"]'),
('aa45d45e-a2a0-4e17-8e12-65b1d0650acd','萬孝全贈金華洞石名雪灑遥峯作進退詩次韻','王十朋','宋','宋诗','song-poetry','','[]','天闢金華一洞奇，洞中石是化羊遺。',64,'全唐诗/poet.song.119000.json','["天闢金華一洞奇，洞中石是化羊遺。", "渾疑雪向閩山落，更訝峯從天竺飛。", "谿上又添乘棹興，案頭如照讀書時。", "故人重我膏肓疾，田不荒蕪應亦歸。"]'),
('648601b1-b855-4abe-ac8c-0922ee88a9eb','元宵鄰里携具就弊廬張燈辭之不獲因成一絕','王十朋','宋','宋诗','song-poetry','','[]','凶年猶幸在家鄉，鄰里相過具豆觴。',32,'全唐诗/poet.song.119000.json','["凶年猶幸在家鄉，鄰里相過具豆觴。", "我輩忍將燈照眼，游人多是火燒腸。"]'),
('3f162b0a-c52c-480c-9329-5abc410b36e1','祈雨不應','王十朋','宋','宋诗','song-poetry','','[]','歉歲還鄉益困窮，瓶無儲粟酒尊空。',32,'全唐诗/poet.song.119000.json','["歉歲還鄉益困窮，瓶無儲粟酒尊空。", "醉經且學文中子，閔雨難祈應上公。"]'),
('4fe698b7-97a9-41aa-a9b3-34d217cd8472','自秋七月不雨至于春二月十九日僅得雨昌齡作賀詩予未及和而雨止矣遂次韻以閔之  其一','王十朋','宋','宋诗','song-poetry','','[]','水旱年年費請求，仰勤湯禱與堯疇。',32,'全唐诗/poet.song.119000.json','["水旱年年費請求，仰勤湯禱與堯疇。", "何時三十六雨足，當宁免懷雲漢憂。"]'),
('03d45e57-f4b0-4402-8985-6566952bfa50','自秋七月不雨至于春二月十九日僅得雨昌齡作賀詩予未及和而雨止矣遂次韻以閔之  其二','王十朋','宋','宋诗','song-poetry','','[]','一杯未吸甕頭春，三疊聊欹雨裛塵。',32,'全唐诗/poet.song.119000.json','["一杯未吸甕頭春，三疊聊欹雨裛塵。", "不用遽興風伯訟，弘羊真是可烹人。"]'),
('112f00eb-52bf-4dd5-b484-ef06a77d0b7d','社日喜雨復用前韻  其一','王十朋','宋','宋诗','song-poetry','','[]','社日簷間不斷流，淵明欣欲事西疇。',32,'全唐诗/poet.song.119000.json','["社日簷間不斷流，淵明欣欲事西疇。", "願言一飽均黎庶，瓶粟無儲不用憂。"]'),
('c99fe9ea-4c9a-42c7-8c0a-dcb59942679a','社日喜雨復用前韻  其二','王十朋','宋','宋诗','song-poetry','','[]','欲放乾坤萬里春，要須先洗庾公塵。',32,'全唐诗/poet.song.119000.json','["欲放乾坤萬里春，要須先洗庾公塵。", "朝紳賀雨詩多少，誰是詩中諷諫人。"]'),
('d70c1e43-a142-4fce-aac5-203171c49b35','家食遇歉有飯不足之憂妻孥相勉以固窮因錄其語','王十朋','宋','宋诗','song-poetry','','[]','淵明事高尚，瓶中缺儲粟。',251,'全唐诗/poet.song.119000.json','["淵明事高尚，瓶中缺儲粟。", "魯公凜名節，乞米給饘粥。", "廣文富才名，官冷飯不足。", "少陵老風騷，橡栗拾山谷。", "嗟予何爲者，處世真碌碌。", "謀生一何拙，甔石無儲蓄。", "三年兩去國，囊橐罄水陸。", "還家索租苗，不了臘與伏。", "前秋遭颶風，摧折數間屋。", "今年丁大侵破甑塵可掬。", "絕糧瘦百指，告糴走群僕。", "鄉鄰苟不捄，定恐填溝瀆。", "家藏千卷書，父子忍饑讀。", "一字不堪煮，何以充我腹。", "細君笑謂我，子命難食肉。", "去歲官臺省，僥倖食君祿。", "有口不三緘，月奏知幾牘。", "聖主倘不容，寧免遠竄逐。", "歸來固已幸，富貴非爾福。", "東皋二頃田，得雨尚可穀。", "子耕我當耘，固窮待秋熟。"]'),
('0800a520-9bae-4cb8-b972-293422f4e8b1','聞小使胡昉抗虜不屈上甚嘉之有旨命右揆撫師仍有和不可成之語皆出睿斷宗社之福也昌齡有詩次韵','王十朋','宋','宋诗','song-poetry','','[]','用儒端可復侵疆，活國何勞別取方。',64,'全唐诗/poet.song.119000.json','["用儒端可復侵疆，活國何勞別取方。", "文帝要須親御馬，子卿寧患遠看羊。", "撫師暫屈黄扉老，論將寧咨白首郎。", "行見車書混天下，豈容南北分三光。"]'),
('3b2839d2-6445-4fa2-8578-4bed78725483','昌齡四月十九日得男請名於予命之曰遲','王十朋','宋','宋诗','song-poetry','','[]','端似中山夢得詩，海中仙果子生遲。',64,'全唐诗/poet.song.119000.json','["端似中山夢得詩，海中仙果子生遲。", "况當首夏清和後，更遇千秋啟建時。", "祝爾願同彭祖壽，命名聊效小蘇兒。", "吾家種德已數世，庭戶合生蘭與芝。"]'),
('dcb43937-85a4-4e28-a476-af8ec3640c03','山丹花','王十朋','宋','宋诗','song-poetry','','[]','四月相將莫，山丹開始都。',48,'全唐诗/poet.song.119000.json','["四月相將莫，山丹開始都。", "真心本來赤，正色自然朱。", "百合晚仍俗，石榴繁更粗。", "誰將僊竈藥，花裏著工夫。"]'),
('32bc20e4-d158-4ee2-9b58-13500531e0ac','七月三日至鄱陽  其一','王十朋','宋','宋诗','song-poetry','','[]','我來鄱君山水州，山水入眼常遲留。',32,'全唐诗/poet.song.119000.json','["我來鄱君山水州，山水入眼常遲留。", "絕境遥通雲錦洞，清音下瞰琵琶洲。"]'),
('f3dd3067-310a-456b-bf12-6db04021387f','七月三日至鄱陽  其二','王十朋','宋','宋诗','song-poetry','','[]','干越亭前晚風起，湖入鄱陽三百里。',32,'全唐诗/poet.song.119000.json','["干越亭前晚風起，湖入鄱陽三百里。", "曉來一雨洗新秋，身在江東畫圖裏。"]'),
('bcc06e3e-deb0-494a-b6b0-9a977ed7f937','次韻何憲子應喜雨','王十朋','宋','宋诗','song-poetry','','[]','亢陽誰謂不爲災，饑饉連年甑有埃。',64,'全唐诗/poet.song.119000.json','["亢陽誰謂不爲災，饑饉連年甑有埃。", "旱魃忽隨寃獄散，雨師遥逐使車來。", "平反盡欲歸中典，調燮端宜位上臺。", "更喜詩如杜陵老，江流坐穩興悠哉。"]'),
('d5709bf4-e634-4329-b056-b6910fdd01c5','登綺霞亭用喜雨韻','王十朋','宋','宋诗','song-poetry','','[]','六月西征遇旱災，脩途千里踏塵埃。',64,'全唐诗/poet.song.119000.json','["六月西征遇旱災，脩途千里踏塵埃。", "雷公俄喚阿香去，霖雨便隨流火來。", "天入滄浪游楚越，雲翻䆉䅉憶溫臺。", "綺霞亭上一回首，滿目湖山壯矣哉。"]'),
('a1ce5b89-4a80-4829-9df0-895364e6ee09','追和范文正公鄱陽詩 郡齋即事','王十朋','宋','宋诗','song-poetry','','[]','理郡端如理亂絲，范公往矣欲誰師。',64,'全唐诗/poet.song.119000.json','["理郡端如理亂絲，范公往矣欲誰師。", "典刑猶有堂中像，光豔長存壁上詩。", "未報國恩嗟老去，不逢人傑恨生遲。", "一尊坐對鄱江月，耿耿忠懷祇自知。"]'),
('604e07ba-6e4e-4a5c-b3f4-c12d554b01cb','追和范文正公鄱陽詩 游芝山寺','王十朋','宋','宋诗','song-poetry','','[]','出郭上崔嵬，山川亦壯哉。',48,'全唐诗/poet.song.119000.json','["出郭上崔嵬，山川亦壯哉。", "三芝誰采去，五老欲飛來。", "懷古情無盡，思鄉首屢回。", "論文一尊酒，天色爲吾開。"]'),
('97075a05-a71a-4571-919a-0f255bab0e70','追和范文正公鄱陽詩 登綺霞亭用碧雲軒韻','王十朋','宋','宋诗','song-poetry','','[]','郡亭臨大澤，霞障截塵紛。',48,'全唐诗/poet.song.119000.json','["郡亭臨大澤，霞障截塵紛。", "有色祇因日，無心元是雲。", "滄浪隨郭轉，欵乃隔江聞。", "文正已仙去，佳名千載芬。"]'),
('8a42d69c-80b8-48b3-bfa6-f72412da0f1d','追和范文正公鄱陽詩 降聖節詣天慶觀因謁顔魯公范文正公祠堂用贈御賜名道士韻','王十朋','宋','宋诗','song-poetry','','[]','顔范遥同異代心，琳宮香火道緣深。',32,'全唐诗/poet.song.119000.json','["顔范遥同異代心，琳宮香火道緣深。", "詩家風味今誰在，定訪彌明與共吟。"]'),
('0cf138dd-49e7-4dd8-a06e-ec70ef660b2f','追和范文正公鄱陽詩 觀文正像用贈傳神道士韻','王十朋','宋','宋诗','song-poetry','','[]','天然形貌寫何難，難得靈臺上筆端。',32,'全唐诗/poet.song.119000.json','["天然形貌寫何難，難得靈臺上筆端。", "朋黨論興三出日，不知誰作正人看。"]'),
('38347140-eba5-49d9-8cb8-de336150a383','追和范文正公鄱陽詩 移竹植郡齋之東用懷慶朔堂韻','王十朋','宋','宋诗','song-poetry','','[]','手移修竹傍牆栽，老眼青青爲竹開。',32,'全唐诗/poet.song.119000.json','["手移修竹傍牆栽，老眼青青爲竹開。", "獨坐書齋誰是伴，清風時作故人來。"]'),
('a536a762-9ea9-4b0c-811a-8033aed7d880','十月望日同官會飯薦福送酒','王十朋','宋','宋诗','song-poetry','','[]','鄱水同僚總不群，公餘相與共論文。',32,'全唐诗/poet.song.119000.json','["鄱水同僚總不群，公餘相與共論文。", "遠公蓮社恐無酒，輒效江州王使君。"]'),
('4c616b48-df02-471a-a255-2416a023b8a3','生日示聞詩聞禮','王十朋','宋','宋诗','song-poetry','','[]','哀哀父母生我勞，生日不見徒悲號。',96,'全唐诗/poet.song.119000.json','["哀哀父母生我勞，生日不見徒悲號。", "今年偶然夢三刀，二千石向鄱陽叨。", "身雖五馬已二毛，烹羊擊鮮斫蟹螯。", "殷勤爲壽勞爾曹，願爾它年著綵袍。", "二親無恙年俱高，更與諸孫持壽醪。", "滿堂賓客來英豪，會看醉臉如仙桃。"]'),
('c2f82f72-baca-41b7-8ce2-03403055ee47','木藴之即席和文字韻詩酬以二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','少年才氣已超群，場屋能摛錦綉文。',32,'全唐诗/poet.song.119000.json','["少年才氣已超群，場屋能摛錦綉文。", "糠秕在前真有愧，春風得意豈如君。"]'),
('122c31d6-afd0-4335-a5cb-84e9b595860f','木藴之即席和文字韻詩酬以二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','回頭遥念蕩中羣，把酒欣論坐上文。',32,'全唐诗/poet.song.119000.json','["回頭遥念蕩中羣，把酒欣論坐上文。", "臭味聊將比兄弟，大馮君與小馮君。"]'),
('22a31dff-9405-438e-b67d-a7073a965a65','觀郡守題名再書一絕','王十朋','宋','宋诗','song-poetry','','[]','濫與江湖岳牧群，於中最慕范希文。',32,'全唐诗/poet.song.119000.json','["濫與江湖岳牧群，於中最慕范希文。", "人才相遠心相似，均是憂時與愛君。"]'),
('0f0fef6a-290b-4fe2-a0a1-9f75cf3348e9','項服善知縣和詩酬以三絕并簡林致一教授  其一','王十朋','宋','宋诗','song-poetry','','[]','膽落庭中雁鶩群，寧容摘紙舞微文。',32,'全唐诗/poet.song.119000.json','["膽落庭中雁鶩群，寧容摘紙舞微文。", "鄱陽賢令知多少，惟有鄱君與項君。"]'),
('048ac80f-7bca-4d93-8843-0a807ba14077','項服善知縣和詩酬以三絕并簡林致一教授  其二','王十朋','宋','宋诗','song-poetry','','[]','牧養功成鮮敗群，絃歌聲裏出詩文。',32,'全唐诗/poet.song.119000.json','["牧養功成鮮敗群，絃歌聲裏出詩文。", "只愁桃李春風近，卧轍無由駐令君。"]'),
('cc549145-3db5-4f95-ac89-ee7a1c6be384','項服善知縣和詩酬以三絕并簡林致一教授  其三','王十朋','宋','宋诗','song-poetry','','[]','無錢令尹陶彭澤，有道先生鄭廣文。',32,'全唐诗/poet.song.119000.json','["無錢令尹陶彭澤，有道先生鄭廣文。", "預約它年還故里，共騎白鹿效文君。"]'),
('880ebd0d-1958-454f-bfeb-ba96c8d87786','題薦福寺莫莫堂','王十朋','宋','宋诗','song-poetry','','[]','休休有室宜歸早，莫莫名堂去恨遲。',32,'全唐诗/poet.song.119000.json','["休休有室宜歸早，莫莫名堂去恨遲。", "禪老相逢應笑我，休休莫莫定何時。"]'),
('1f883bfc-d5b3-411c-a5fc-a4a83989b3e4','哭馮員仲  其一','王十朋','宋','宋诗','song-poetry','','[]','一代奇男子，哀哉命止斯。',48,'全唐诗/poet.song.119000.json','["一代奇男子，哀哉命止斯。", "共天終不忍，蹈海亦何辭。", "下惠已三黜，照鄰俄五悲。", "煩言何足辨，公論不容欺。"]'),
('7aeed2fa-136d-4115-836d-6a9d6ac08155','哭馮員仲  其二','王十朋','宋','宋诗','song-poetry','','[]','身爲多才誤，朝無一日安。',48,'全唐诗/poet.song.119000.json','["身爲多才誤，朝無一日安。", "寧爲獨醒鬼，不作附炎官。", "夢斷吳江冷，魂歸蜀道難。", "郡齋揮老淚，重取近書看。"]'),
('96d514a2-6d39-49a2-b83e-9cf628da487e','陸居士挽詩','王十朋','宋','宋诗','song-poetry','','[]','槐市訪同舍，麟經推阿戎。',48,'全唐诗/poet.song.119000.json','["槐市訪同舍，麟經推阿戎。", "傳家知有子，種德本由公。", "遺訓皆新語，多男類陸終。", "佳城在何處，楚尾白雲中。"]'),
('f183547c-34b8-4a87-97f6-094c244bece3','洪帥陳阜卿寄筍','王十朋','宋','宋诗','song-poetry','','[]','均是蓬山逸遠官，夢中猶問竹平安。',32,'全唐诗/poet.song.119000.json','["均是蓬山逸遠官，夢中猶問竹平安。", "籜龍寄我知君意，要使剛腸飽歲寒。"]'),
('31d7b68a-0a08-4d67-8811-c65cc5815e39','次韻何子應題不欺室','王十朋','宋','宋诗','song-poetry','','[]','公如憂國房玄齡，我如鄭公思批鱗。',96,'全唐诗/poet.song.119000.json','["公如憂國房玄齡，我如鄭公思批鱗。", "隆興天下同貞觀，願爲賢相爲良臣。", "我去公來不同日，各展忠懷對宣室。", "江湖邂逅論赤心，更約聯翩書史筆。", "坤爻敬義誠君子，可惜作銘人已死。", "八十四字騰光芒，便是千年不欺史。"]'),
('873ba740-6c6b-459e-b8a6-5e086e067ebb','郡齋對雪','王十朋','宋','宋诗','song-poetry','','[]','平生爲雪牽詩興，今日無詩奈雪何。',64,'全唐诗/poet.song.119000.json','["平生爲雪牽詩興，今日無詩奈雪何。", "凈几翻書擁爐讀，冷齋呵硯带冰磨。", "寒江獨釣句思柳，銀海光摇人憶坡。", "欲兩三杯賀豐歲，却憂疆埸正干戈。"]'),
('9c8943b7-f152-4866-b493-7be817dae369','子應和詩再用前韻','王十朋','宋','宋诗','song-poetry','','[]','江東臘雪爲誰多，清逼官梅興動何。',64,'全唐诗/poet.song.119000.json','["江東臘雪爲誰多，清逼官梅興動何。", "堂坐玉芝勞想像，句工冰柱老研磨。", "賡酬往事思蓬島，災異狂言忤諫坡。", "聽取金華新號令，要須白戰不持戈。"]'),
('8d86e3c9-b242-4987-ad36-ef1dd2e56d02','祠顔范二公','王十朋','宋','宋诗','song-poetry','','[]','鄱江善政九賢人，文正文忠更絕倫。',64,'全唐诗/poet.song.119000.json','["鄱江善政九賢人，文正文忠更絕倫。", "桃李舊邦千里愛，丹青遺像兩朝臣。", "不同赤土祠劉阮，端勝睢陽廟遠巡。", "安得神仙返魂藥，九原喚起靜邊塵。"]'),
('503b95da-4f63-478f-8474-f7b45f7d0a23','題何子應金華書院圖','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君不見杜陵野客老更狂，浣花溪上結草堂。',246,'全唐诗/poet.song.119000.json','["君不見杜陵野客老更狂，浣花溪上結草堂。", "又不見謫仙世人皆欲殺，匡山讀書頭如雪。", "二公同時鳴有唐，文章萬丈光艷長。", "鈞天無人帝呼去，草堂書館今荒凉。", "太平宰相張居士，外甥似舅金華子。", "胸中萬卷杜陵翁，筆下千篇謫仙李。", "向來衣冠拜僞楚，我乃宋臣惟有死。", "何曾著眼癡宰相，况肯低顔驄御史。", "天邊卿月落九疑，口誦離騷吊湘水。", "誅茅築室小東山，天下蒼生望公起。", "種梅志欲調商鼎，持斧夢刀聊爾耳。", "公生長安我東嘉，天遣邂逅鄱江涯。", "筆頭一語真戲劇，却將鐵面擬金華。", "金華自是金閨彥，金口褒揚兩朝眷。", "末須歸去金華山，行將入侍金華殿。"]'),
('e212ee23-ca4c-4e99-9e9b-3ba799c5fc55','閏月三白三首  其一','王十朋','宋','宋诗','song-poetry','','[]','閏月生明後，江天未臘時。',48,'全唐诗/poet.song.119000.json','["閏月生明後，江天未臘時。", "風翻禹門浪，花糝月宮枝。", "照夜皎珠樹，秀庭祥玉芝。", "定知年大有，何止麥相宜。"]'),
('72beb7d6-2843-403b-83ef-e4e738e96019','閏月三白三首  其二','王十朋','宋','宋诗','song-poetry','','[]','迎臘雪三白，未春花萬株。',48,'全唐诗/poet.song.119000.json','["迎臘雪三白，未春花萬株。", "神山森玉府，天象粲臺符。", "詞吐水流峽，鼎成風擊湖。", "鬢邊絲可織，四皓盍添吾。"]'),
('9502ca7d-bd1e-414f-88f6-5a339ab38d42','閏月三白三首  其三','王十朋','宋','宋诗','song-poetry','','[]','占盡一陽月，分爲六出時。',48,'全唐诗/poet.song.119000.json','["占盡一陽月，分爲六出時。", "韋編照清夜，塞管落南枝。", "獻中荆山玉，開成廟柱芝。", "人間瑞已定，過此却非宜。"]'),
('98c0f3c5-73b4-4aa1-95a5-87b4e5b28073','又和項服善二首  其一','王十朋','宋','宋诗','song-poetry','','[]','風雲頻慘淡，草木屢蒼顔。',48,'全唐诗/poet.song.119000.json','["風雲頻慘淡，草木屢蒼顔。", "詩裏報瓊玖，宮中歸玉環。", "帝庭侯帛至，佛殿寶珠還。", "更有人清白，鄱陽似魯山。"]'),
('46fa4764-157c-4531-9b8b-88d1d9a3cebb','又和項服善二首  其二','王十朋','宋','宋诗','song-poetry','','[]','梅蕊開仍落，同雲合末離。',48,'全唐诗/poet.song.119000.json','["梅蕊開仍落，同雲合末離。", "添爲五大老，真是四無私。", "天女來成粲，冰蠶老欲絲。", "梨花一枝雨，冷艷可能欺。"]'),
('a17cdaea-f75a-4db2-9004-f0c322ff4a7f','又用時字韻','王十朋','宋','宋诗','song-poetry','','[]','黄竹成章日，陽春衆和時。',48,'全唐诗/poet.song.119000.json','["黄竹成章日，陽春衆和時。", "玉階談戰陳，瓊燕賜花枝。", "陶徑還飛絮，商山欠採芝。", "西疇農事及，歸去正吾宜。"]'),
('51feea59-c531-487c-867a-e653a2054e5a','和洪景盧用三白韻作四白詩  其一','王十朋','宋','宋诗','song-poetry','','[]','大似佛世界，端如玉燭時。',48,'全唐诗/poet.song.119000.json','["大似佛世界，端如玉燭時。", "穆家兄弟味，楊氏子孫枝。", "鄞海明瑶柱，鄱亭望秀芝。", "祁寒繇政拙，去倍二誠宜。"]'),
('480843c0-8f40-4939-9a5e-6cd1bc5959d1','和洪景盧用三白韻作四白詩  其二','王十朋','宋','宋诗','song-poetry','','[]','楚士照千乘，韓梨夸數株。',48,'全唐诗/poet.song.119000.json','["楚士照千乘，韓梨夸數株。", "舜門紛執玉，堯岳衒分符。", "寶結文房友，鑑明狂客湖。", "郊圻正多壘，兵會憶夷吾。"]'),
('859df6e2-b74e-4920-8c98-1c784fe0caa1','臘盡日又雪洪復作五白詩再和  其一','王十朋','宋','宋诗','song-poetry','','[]','天地俱同數，嘉平欲盡時。',48,'全唐诗/poet.song.119000.json','["天地俱同數，嘉平欲盡時。", "柳飄彭澤絮，松壓大夫枝。", "越絕山飛洩，文登石産芝。", "濫騎爲郡馬，深願穀相宜。"]'),
('1340cae9-4243-4ae1-bb4b-b914211a05b1','臘盡日又雪洪復作五白詩再和  其二','王十朋','宋','宋诗','song-poetry','','[]','日掩雲間色，榆栽天上株。',48,'全唐诗/poet.song.119000.json','["日掩雲間色，榆栽天上株。", "芳聯仙桂籍，窮送舊桃符。", "遠岫明廬阜，澄江接带湖。", "宣麻開晉國，入蔡憶金吾。"]'),
('195edfde-e811-44d0-b603-9882a1e78751','次韻何子應得宣城筆','王十朋','宋','宋诗','song-poetry','','[]','金華手握管城子，端類睢陽太守鬚。',32,'全唐诗/poet.song.119000.json','["金華手握管城子，端類睢陽太守鬚。", "鬚筆有神人不識，怒時真可氣吞胡。"]'),
('a03404be-d839-4fd5-8a8f-95e1db7cbe43','聞捷報用何韻','王十朋','宋','宋诗','song-poetry','','[]','淮甸流離唐赤子，將軍奇特魏黄鬚。',32,'全唐诗/poet.song.119000.json','["淮甸流離唐赤子，將軍奇特魏黄鬚。", "願將銀管書忠誼，糞土東京趙與胡。"]'),
('1a694753-6de6-4194-9ee3-7019bc741752','不欺室三字參政張公書也筆力勁健如端人正士儼然人望而敬之因成古詩八韻','王十朋','宋','宋诗','song-poetry','','[]','雲山老人國大老，歷代遺編飫探討。',128,'全唐诗/poet.song.119000.json','["雲山老人國大老，歷代遺編飫探討。", "餘事游神翰墨間，乘興濡毫快揮掃。", "嚴霜烈日如魯公，抉石奔泉陋徐浩。", "國朝君謨書第一，大字劣於行與草。", "雲山心畫無不長，筆力縱時書更好。", "我來求字蓋求人，不爲有官緣有道。", "紫巖之銘雲山筆，不欺室中雙至寶。", "玉簫峯下梅花溪，願學雲山歸去早。"]'),
('05af6d8a-b8f8-471f-a727-247612b18656','出郊遇雪','王十朋','宋','宋诗','song-poetry','','[]','小隊出郊聊習戰，朔風吹雪似催詩。',32,'全唐诗/poet.song.119000.json','["小隊出郊聊習戰，朔風吹雪似催詩。", "皇天有意誅驕虜，正類元戎破蔡時。"]'),
('8d19dc86-e5c6-4589-8617-7ddd39ecd7c6','何子應以蜀中文房四寶分贈洪景盧王嘉叟某與焉因成一絕','王十朋','宋','宋诗','song-poetry','','[]','江左風流屬憲臺，筆端妙語出瓊瑰。',32,'全唐诗/poet.song.119000.json','["江左風流屬憲臺，筆端妙語出瓊瑰。", "濫居益友三人列，誤辱文房四寶來。"]'),
('4800e33c-efd6-489f-a0d5-f3c00ed3b8f4','送翁東叟教授  其一','王十朋','宋','宋诗','song-poetry','','[]','鄱陽江上五見雪，鄱江樓上風栗烈。',64,'全唐诗/poet.song.119000.json','["鄱陽江上五見雪，鄱江樓上風栗烈。", "廣文先生不畏冷，弭棹登樓興清絕。", "筆端妙語出離騷，酒後剛腸吐名節。", "芝堂假守老鄉人，明日仙舟那忍別。"]'),
('33c82772-022c-4c9f-ad66-465dfb9882bf','送翁東叟教授  其二','王十朋','宋','宋诗','song-poetry','','[]','三十年間舊友生，眼青頭白見交情。',64,'全唐诗/poet.song.119000.json','["三十年間舊友生，眼青頭白見交情。", "官於湖北况尤冷，詩不江西語自清。", "行李少留吳芮國，夢魂先到謝公城。", "扁舟便合相隨去，薄有田園正可耕。"]'),
('8bdd4e9b-8bd7-4916-b614-2c7a840ca1d5','和寶印叔見寄  其一','王十朋','宋','宋诗','song-poetry','','[]','官舍蕭條怯莫冬，衰顔得酒暈生紅。',32,'全唐诗/poet.song.119000.json','["官舍蕭條怯莫冬，衰顔得酒暈生紅。", "遥思蘭若堂中老，非柏非松自耐風。"]'),
('1dbdc01d-aa3a-4223-9b47-4efac8203c03','和寶印叔見寄  其二','王十朋','宋','宋诗','song-poetry','','[]','濫乘五馬二毛侵，雪滿鄱江坐擁衾。',32,'全唐诗/poet.song.119000.json','["濫乘五馬二毛侵，雪滿鄱江坐擁衾。", "二叔年高兄弟遠，歸期當不待秋砧。"]'),
('4b9c50f8-acf0-4ec3-b0c4-ed9c3aee9196','用韻寄二弟  其一','王十朋','宋','宋诗','song-poetry','','[]','六月離家忽莫冬，郡齋清夜擁爐紅。',32,'全唐诗/poet.song.119000.json','["六月離家忽莫冬，郡齋清夜擁爐紅。", "細看慶朔堂前雪，正似梅花溪上風。"]'),
('fd3be3ce-33a5-4b80-8b44-a6d00a9104c9','用韻寄二弟  其二','王十朋','宋','宋诗','song-poetry','','[]','甚矣今年老見侵，玉芝堂冷敝衣衾。',32,'全唐诗/poet.song.119000.json','["甚矣今年老見侵，玉芝堂冷敝衣衾。", "夢魂夜夜尋兄弟，率飲亭前坐石砧。"]'),
('7fccb24b-a14d-4f36-9f1c-1776a2cf1f44','送蔡倅','王十朋','宋','宋诗','song-poetry','','[]','白首論文得蔡侯，江東尊酒半年游。',64,'全唐诗/poet.song.119000.json','["白首論文得蔡侯，江東尊酒半年游。", "龍頭家世高千佛，驥足聲名重一州。", "方喜同僚吳芮國，不堪回首仲宣樓。", "送君撩我思鄉意，薄有田園歸去休。"]'),
('b414e32c-ff37-4398-b533-2d819dd326ed','齒落','王十朋','宋','宋诗','song-poetry','','[]','五十行將四，浮生已向殘。',48,'全唐诗/poet.song.119000.json','["五十行將四，浮生已向殘。", "齒疏方咄柳，牙落遽驚韓。", "猶訝年初齔，翻疑頰未丹。", "定知從此去，梨栗怯堆盤。"]'),
('e8ad529e-211c-4cf1-984d-79f07e7ab8a7','次韻李懷安贈何憲五絕  其一','王十朋','宋','宋诗','song-poetry','','[]','元老登朝首剡章，危言凜凜動明光。',32,'全唐诗/poet.song.119000.json','["元老登朝首剡章，危言凜凜動明光。", "掉頭却向江湖去，不肯伊優上北堂。"]'),
('bd1b5257-1fea-4c9a-b1cc-6fe140a1a83d','次韻李懷安贈何憲五絕  其二','王十朋','宋','宋诗','song-poetry','','[]','伊洛橫渠造道深，誰傳衣缽見貞心。',32,'全唐诗/poet.song.119000.json','["伊洛橫渠造道深，誰傳衣缽見貞心。", "儒宗頼有金華子，後學寧憂不嗣音。"]'),
('d5b563d7-bcab-4f92-974b-7be9eda0efc8','次韻李懷安贈何憲五絕  其三','王十朋','宋','宋诗','song-poetry','','[]','夢魂聞說到無何，曾共神官壯者哦。',32,'全唐诗/poet.song.119000.json','["夢魂聞說到無何，曾共神官壯者哦。", "妙墨雄文滿天下，士衡應亦患才多。"]'),
('730568f1-a0f9-4c39-8ef0-f6eb10bf7417','次韻李懷安贈何憲五絕  其四','王十朋','宋','宋诗','song-poetry','','[]','炙手權門盡好官，雲山高卧老江干。',32,'全唐诗/poet.song.119000.json','["炙手權門盡好官，雲山高卧老江干。", "相期晚景全名節，富貴何須著眼看。"]'),
('75684a8e-8622-463a-b844-04d4d7bc7b1e','次韻李懷安贈何憲五絕  其五','王十朋','宋','宋诗','song-poetry','','[]','元白詩筒數往還，小生閣筆媿言艱。',32,'全唐诗/poet.song.119000.json','["元白詩筒數往還，小生閣筆媿言艱。", "異時應起鄱江念，公在金華我雁山。"]'),
('645750cd-3905-45a4-82f6-6ab5012eceec','李懷安擁麾入蜀道出鄱江見贈二詩依韻奉酬  其一','王十朋','宋','宋诗','song-poetry','','[]','不肯隨群慕鶴軒，慨然丹陛吐危言。',64,'全唐诗/poet.song.119000.json','["不肯隨群慕鶴軒，慨然丹陛吐危言。", "坐看蜀道平如地，可見忠臣勇似尊。", "駟馬橋邊驅弩矢，杜鵑聲裏擁旂旛。", "要須入境詢風俗，首訪嚴遵李仲元。"]'),
('4f310095-9502-41fa-973d-bfc20b7f0c23','李懷安擁麾入蜀道出鄱江見贈二詩依韻奉酬  其二','王十朋','宋','宋诗','song-poetry','','[]','一麾出守楚東城，邂逅論交媿孔程。',64,'全唐诗/poet.song.119000.json','["一麾出守楚東城，邂逅論交媿孔程。", "元禮仙舟行色好，子猷雪棹去心輕。", "虎符稔服君家世，雁蕩行逃我姓名。", "酒盞詩篇話時事，江湖何日更尋盟。"]'),
('2a8f58ac-2e3b-4e88-877c-e61f981cc204','國娘生日','王十朋','宋','宋诗','song-poetry','','[]','往歲王司業，初生嫡女孫。',48,'全唐诗/poet.song.119000.json','["往歲王司業，初生嫡女孫。", "命名聊志喜，曰國不忘恩。", "日在元正次，身居輩行尊。", "願如班與孟，賢淑振吾門。"]'),
('91557d8a-0364-45c2-9539-a8d4e5d13ee7','陳阜卿書云聞詩筒甚盛可使流傳江西否戲用竹萌韻以寄','王十朋','宋','宋诗','song-poetry','','[]','江西大帥本仙官，餘事篇章過定安。',32,'全唐诗/poet.song.119000.json','["江西大帥本仙官，餘事篇章過定安。", "欲遣詩筒寄詩伯，恐嫌白俗孟郊寒。"]'),
('05da4c02-b976-4abb-9f03-a25ce80ab8f7','次何憲韻','王十朋','宋','宋诗','song-poetry','','[]','毛穎神明更好鬚，飛騰入月跨蟾蜍。',64,'全唐诗/poet.song.119000.json','["毛穎神明更好鬚，飛騰入月跨蟾蜍。", "誰將銀管爲封邑，端爲金華妙簡書。", "鳳翥龍蟠文未稱，日光玉潔字還疏。", "何如今代何平叔，筆陣詞源總莫如。"]'),
('1061f936-1b1f-4e14-ae40-f9e2d5892c0d','金華先生有奇石名碧遠携來自蜀陳洪州以詩覓之金華輟所嗜以贈亦一段奇事也予家雁蕩群峯錯峙皆几案間物因和二公詩頗起鄉思寓意斷章','王十朋','宋','宋诗','song-poetry','','[]','二公心古貌清癯，趣在林泉世味疏。',64,'全唐诗/poet.song.119000.json','["二公心古貌清癯，趣在林泉世味疏。", "寸碧來從錦江遠，九疑分向錫山居。", "山中丘壑奴金谷，筆下波瀾陋石渠。", "我有千峯藏雁蕩，擎天一柱插空虛。"]'),
('ae0da40c-1d68-4a13-a317-fc7b3a8df814','嘉叟宗丞得郡喜成一絕','王十朋','宋','宋诗','song-poetry','','[]','邸報初聞見姓名，甘棠家世舊專城。',32,'全唐诗/poet.song.119000.json','["邸報初聞見姓名，甘棠家世舊專城。", "伯魚詩禮趨庭處，五馬旌旗夾道迎。"]'),
('895a6425-be3d-44e7-b385-3bd63b9ff731','人日雨次何憲韻','王十朋','宋','宋诗','song-poetry','','[]','元正作佳天，涉七弄春氣。',48,'全唐诗/poet.song.119000.json','["元正作佳天，涉七弄春氣。", "好雨亦知時，綠波行何濟。", "新詩如蜀州，句有梅柳味。", "七升年定豐，一石公當醉。"]'),
('1c5c9de7-8ac0-49f6-ab04-0589c6f6b528','子應贈蜀中石刻十卷詩以謝之','王十朋','宋','宋诗','song-poetry','','[]','金華石刻滿西州，不惜明珠輒暗投。',64,'全唐诗/poet.song.119000.json','["金華石刻滿西州，不惜明珠輒暗投。", "詩泣鬼神追雅頌，義深君父妙春秋。", "隨身連軫崔評事，挿架懸籤李鄴侯。", "掃室焚香讀終卷，光芒萬丈照螺洲。"]'),
('55428521-b325-4d13-a7f9-0daabec1bfdf','次韻嘉叟讀和韓詩','王十朋','宋','宋诗','song-poetry','','[]','孔孟久不作，况雄莫能和。',240,'全唐诗/poet.song.119000.json','["孔孟久不作，况雄莫能和。", "韓公生有唐，力欲拯頹挫。", "文興八代衰，學捄諸子過。", "佛老蔓中華，微公衽其左。", "餘事以詩鳴，語險鬼膽破。", "汗瀾高駕天，捷敏劇飛笴。", "騎龍歸帝旁，玉日人間墮。", "汗流籍湜輩，圭璧分半箇。", "柳和詞擬騷，郊聯語成些。", "咸知太山仰，誰繼北窗卧。", "我本虀鹽生，久供筆硯課。", "幽香摘天葩，光艷拾珠唾。", "後公三百年，杖屨無從荷。", "世無六一翁，孰知珍古貨。", "巴詞擬陽春，僭竊罪宜坐。", "神交有吾宗，涉世同坎軻。", "學繼青箱玉，詩高碧紗播。", "勉令添和篇，才薄知何奈。", "謬同赤效白，深媿愈知賀。", "世事置勿論，蚊睫蟲容麽。"]'),
('507a64ae-17da-4763-a4d6-22a0cd496633','元夕次何憲韻  其一','王十朋','宋','宋诗','song-poetry','','[]','火樹銀花遍九衢，天移星斗下空虛。',32,'全唐诗/poet.song.119000.json','["火樹銀花遍九衢，天移星斗下空虛。", "心憂機婦寒窗士，詩句分明似諫書。"]'),
('f0f66dcb-a4b1-49a4-8fa2-518221378ab3','元夕次何憲韻  其二','王十朋','宋','宋诗','song-poetry','','[]','鄱陽燈火類殘星，風雨那堪更滿城。',32,'全唐诗/poet.song.119000.json','["鄱陽燈火類殘星，風雨那堪更滿城。", "爲郡何如在家好，長檠不似短檠明。"]'),
('4c38ee46-61b4-4737-92c6-fec0069a0252','送何憲行部趣其早還','王十朋','宋','宋诗','song-poetry','','[]','九郡饑民望使軺，陽春有脚不辭遥。',32,'全唐诗/poet.song.119000.json','["九郡饑民望使軺，陽春有脚不辭遥。", "更須速返鄱君國，莫遣詩筒久寂寥。"]'),
('0cd91ea7-ff41-460e-badc-b7fa04e9a234','種金沙花戲呈景盧','王十朋','宋','宋诗','song-poetry','','[]','春光駘蕩楚天涯，李白桃紅次第花。',32,'全唐诗/poet.song.119000.json','["春光駘蕩楚天涯，李白桃紅次第花。", "未向名園看鐵樹，聊於郡圃種金沙。"]'),
('77419547-6377-41fd-a3a8-73e653be5570','郡圃栽花','王十朋','宋','宋诗','song-poetry','','[]','公餘吏隠不相賒，杖屨園林賞物華。',64,'全唐诗/poet.song.119000.json','["公餘吏隠不相賒，杖屨園林賞物華。", "五柳宅邊誰種柳，百花樓畔謾栽花。", "池塘有夢吟春草，屏障無心戀綺霞。", "來歲游人應話我，雁山深處老桑麻。"]'),
('587ba90a-4662-4f20-8572-d487941304a0','二月朔日同嘉叟藴之訪景盧別墅用郡圃栽花韻即席唱和  其一','王十朋','宋','宋诗','song-poetry','','[]','鄱水芝山四望賒，雨餘風物陪光華。',64,'全唐诗/poet.song.119000.json','["鄱水芝山四望賒，雨餘風物陪光華。", "名園種果仍修果，妙手栽花似判花。", "行見晉公開綠野，聊從子美酌流霞。", "坐間賓主皆人傑，我質如蓬頼倚麻。"]'),
('26ed93c0-2e43-43ca-a1b6-03bb20ab9d99','二月朔日同嘉叟藴之訪景盧別墅用郡圃栽花韻即席唱和  其二','王十朋','宋','宋诗','song-poetry','','[]','野處名園境界賒，夷堅博物似張華。',64,'全唐诗/poet.song.119000.json','["野處名園境界賒，夷堅博物似張華。", "參天先種柳州柳，照眼兼看花縣花。", "即席賦詩袍奪錦，論文對酒臉生霞。", "自慚衰病陪行樂，策杖登城脚欲麻。"]'),
('621fbb23-39d2-497a-9247-1480835ecdbc','還舍復用前韻以寄','王十朋','宋','宋诗','song-poetry','','[]','負郭園林路不賒，杖藜徐步賞韶華。',64,'全唐诗/poet.song.119000.json','["負郭園林路不賒，杖藜徐步賞韶華。", "芹宮地近分流水，芝嶺風高送落花。", "簷外梨枝春带雨，城頭桃樹晚蒸霞。", "行看共掌絲綸美，寧復丘中詠有麻。"]'),
('ad567dcc-19da-4032-8980-5b3cc624dea4','景盧嘉叟各和詩五首復用前韻','王十朋','宋','宋诗','song-poetry','','[]','草堂相去不多賒，雨後登臨喚革華。',64,'全唐诗/poet.song.119000.json','["草堂相去不多賒，雨後登臨喚革華。", "心喜淵明尊有酒，眼驚太白筆生花。", "來看四澤滿時水，歸見九光披處霞。", "得兩使君詩十首，郡齋傳寫費川麻。"]'),
('92e7105d-c6ed-45e4-a579-3af5c2b9ab3f','用韻懷何卿','王十朋','宋','宋诗','song-poetry','','[]','送別鄱江日未賒，詩人相問憶金華。',64,'全唐诗/poet.song.119000.json','["送別鄱江日未賒，詩人相問憶金華。", "烏衣巷口見歸燕，萬里橋西思浣花。", "持節要先蘇赤子，攝身未用踏蒼霞。", "行將歸侍玉皇案，不比少陵鞋用麻。"]'),
('704d8252-a31a-4d63-8bc2-b2d91a46cf63','嘉叟和詩至七篇有何時五畝成歸計來作鄰翁伴藝麻之句某鄉心方切復用韻','王十朋','宋','宋诗','song-poetry','','[]','學繼初寮事業賒，閉門寧悔讀南華。',64,'全唐诗/poet.song.119000.json','["學繼初寮事業賒，閉門寧悔讀南華。", "符分興化日烘荔，室寓維摩天雨花。", "故里君應懷北岳，歸心我已到飛霞。", "休休莫莫宜閑處，耕有添丁婦織麻。"]'),
('39254472-8d20-4edc-a000-81b47c96235e','州宅十二詠 平政堂','王十朋','宋','宋诗','song-poetry','','[]','愷悌周君子，循良漢守臣。',24,'全唐诗/poet.song.119000.json','["愷悌周君子，循良漢守臣。", "如今坐堂上，端是政平人。"]'),
('ecc0a7e5-ec09-4e91-8927-c898393305da','州宅十二詠 玉芝堂','王十朋','宋','宋诗','song-poetry','','[]','不是因三秀，名堂意自深。',24,'全唐诗/poet.song.119000.json','["不是因三秀，名堂意自深。", "要居森戟地，毋忘采芝心。"]'),
('8adb0ca2-a3e9-4160-8f31-71af4ed7068d','州宅十二詠 慶朔堂','王十朋','宋','宋诗','song-poetry','','[]','昔日栽花者，官移花未開。',24,'全唐诗/poet.song.119000.json','["昔日栽花者，官移花未開。", "舊花今豈在，猶說范公栽。"]'),
('ebcdc1e2-39b1-4874-8ba2-b0596b156baf','州宅十二詠 退思軒','王十朋','宋','宋诗','song-poetry','','[]','會得名軒意，公餘坐片時。',24,'全唐诗/poet.song.119000.json','["會得名軒意，公餘坐片時。", "退思何及矣，未退早須思。"]'),
('07d3a975-66be-463b-92ad-45294bb8e46f','州宅十二詠 九賢堂','王十朋','宋','宋诗','song-poetry','','[]','猶起才難歎，同時九亂臣。',24,'全唐诗/poet.song.119000.json','["猶起才難歎，同時九亂臣。", "鄱陽千載守，賢豈許多人。"]'),
('3c5297d5-05d2-4519-9dab-cfed755826ba','州宅十二詠 四賢堂','王十朋','宋','宋诗','song-poetry','','[]','誰品鄱陽守，四人賢不知。',24,'全唐诗/poet.song.119000.json','["誰品鄱陽守，四人賢不知。", "如何堯舜世，能使野無遺。"]'),
('c5434f31-c90d-4ccf-9a01-52c771823e42','州宅十二詠 四望亭','王十朋','宋','宋诗','song-poetry','','[]','有澤宜觀水，無簷不見山。',24,'全唐诗/poet.song.119000.json','["有澤宜觀水，無簷不見山。", "鄱君千里國，俯仰一亭間。"]'),
('9b029a37-60db-410a-a21b-ace90888dcee','州宅十二詠 綺霞亭','王十朋','宋','宋诗','song-poetry','','[]','孤鶩同飛處，澄江共賦時。',24,'全唐诗/poet.song.119000.json','["孤鶩同飛處，澄江共賦時。", "晚來亭上看，真是謝公詩。"]'),
('6de6845d-a2c5-4ffc-8826-18ed2bae2bfc','州宅十二詠 清香亭','王十朋','宋','宋诗','song-poetry','','[]','高架添風韻，芳醪共姓名。',24,'全唐诗/poet.song.119000.json','["高架添風韻，芳醪共姓名。", "蘇州凝燕寢，疑是此香清。"]'),
('9f8fdf55-da11-4689-88c8-cbca67df5232','州宅十二詠 百花樓','王十朋','宋','宋诗','song-poetry','','[]','昔日風流守，公餘種百花。',24,'全唐诗/poet.song.119000.json','["昔日風流守，公餘種百花。", "春風不檢點，紅紫落誰家。"]'),
('9865d3ee-8d83-41b4-9ed5-bf5b38745929','州宅十二詠 鄱江樓','王十朋','宋','宋诗','song-poetry','','[]','郭外山橫閣，江邊水照樓。',24,'全唐诗/poet.song.119000.json','["郭外山橫閣，江邊水照樓。", "粗官無暇日，何以得消憂。"]'),
('0b986c6f-549e-451c-bbb7-0135b9de290e','州宅十二詠 蜀錦亭','王十朋','宋','宋诗','song-poetry','','[]','亭廢名猶在，春來花自芳。',24,'全唐诗/poet.song.119000.json','["亭廢名猶在，春來花自芳。", "猶餘蜀中錦，愛惜比甘棠。"]'),
('18a0ea51-acd9-4c04-a44b-b8ce5c586dbe','州宅十二詠 景盧贈人面竹杖','王十朋','宋','宋诗','song-poetry','','[]','奔走方嗟力不任，得公一杖直千金。',64,'全唐诗/poet.song.119000.json','["奔走方嗟力不任，得公一杖直千金。", "竹能有面如人面，人亦虛心似竹心。", "渡水只愁龍欲化，入山應與鳳聯吟。", "翰林虞部相酬贈，同舍交情復見今。"]'),
('f875af17-aa4d-4183-bd87-f6c7e75fe376','鄉人項服善宰鄱陽有政聲人惜其去用郡圃栽花韻作詩數篇敘別遂和以送之  其一','王十朋','宋','宋诗','song-poetry','','[]','七歲名師世胄賒，雲孫行實副文華。',64,'全唐诗/poet.song.119000.json','["七歲名師世胄賒，雲孫行實副文華。", "仁心馴及魯恭雉，和氣種成潘岳花。", "清白見知鄱水月，高明相照楚天霞。", "送君撩我思鄉意，遥想吾廬日長麻。"]'),
('90e5d09d-f29b-4c6b-b538-316298e215c6','鄉人項服善宰鄱陽有政聲人惜其去用郡圃栽花韻作詩數篇敘別遂和以送之  其二','王十朋','宋','宋诗','song-poetry','','[]','鄱江同事半年賒，直諒何人似去華。',64,'全唐诗/poet.song.119000.json','["鄱江同事半年賒，直諒何人似去華。", "吏報圜扉多鞠草，民歌枯木再生花。", "暫留蕭寺行逢雨，剩作新詩語带霞。", "褒德自應侯卓茂，清朝知己况如麻。"]'),
('e8d4e6ba-498a-4535-9afe-6bff3bd8e0d6','鄉人項服善宰鄱陽有政聲人惜其去用郡圃栽花韻作詩數篇敘別遂和以送之  其三','王十朋','宋','宋诗','song-poetry','','[]','江東回首莫雲賒，寒食令人感歲華。',64,'全唐诗/poet.song.119000.json','["江東回首莫雲賒，寒食令人感歲華。", "皎皎丹心惟望日，星星短髮不簪花。", "書傳何處山名雁，酒憶吾鄉水似霞。", "故舊相逢如問我，爲言多病服天麻。"]'),
('33c639a1-c11b-4b7b-895b-2058a1020420','鄉人項服善宰鄱陽有政聲人惜其去用郡圃栽花韻作詩數篇敘別遂和以送之  其四','王十朋','宋','宋诗','song-poetry','','[]','公真有德如元令，我媿無才似李華。',64,'全唐诗/poet.song.119000.json','["公真有德如元令，我媿無才似李華。", "話別芝堂傾竹葉，送行鄱水漲桃花。", "眼看三匝烏逢月，心羨齊飛鶩趁霞。", "它日相期訪劉阮，分桃采藥飲胡麻。"]'),
('c60d3aa0-7b28-473e-933a-2c817dac94ac','予向年少不自量因讀韓詩輒和數篇未嘗敢出以示人蓋二十年矣近因嘉叟見之不能自掩且贈以長篇蒙景盧繼和用韻以謝','王十朋','宋','宋诗','song-poetry','','["\u8861\u5c71"]','少小思尚奇，薰風琴欲和。',240,'全唐诗/poet.song.119000.json','["少小思尚奇，薰風琴欲和。", "規模與時背，場屋屢摧挫。", "大道窺五原，高論讀二過。", "神游京城南，思渺蒸水左。", "竹看金影碎，菊擷霜風破。", "論文摩巨刃，薦士躬彊笴。", "蕭蘭發秋懷，木雁吟齒墮。", "飛飛雙鳥鳴，不數鸝兩箇。", "幽幽十琴操，可僕蘭臺些。", "光餘萬丈長，照我一牀卧。", "未終三百篇，正坐短檠課。", "不敢示友朋，懼遭泥滓唾。", "文章吉太守，臭味夙相荷。", "索我舊詩案，贈以千金貨。", "郡齋哦好句，艷艷月照坐。", "端如陳琳檄，快讀痊轗軻。", "濫把江湖麾，謬聲慚日播。", "祈寒兼苦雨，怨嗟吾豈奈。", "竊效衡山禱，因思鑑湖賀。", "鵬鷃各逍遥，溟蓬無巨麽。"]'),
('900889e3-a64c-4671-9434-b2c132992a6a','次韻陳阜卿讀洪景盧追和玉板詩  其一','王十朋','宋','宋诗','song-poetry','','[]','風采稜稜御史官，旌麾所至庶民安。',32,'全唐诗/poet.song.119000.json','["風采稜稜御史官，旌麾所至庶民安。", "渭川千畆填匈臆，散作毫端風雨寒。"]'),
('cac0f3e4-1c11-440b-958d-d76c93cefab4','次韻陳阜卿讀洪景盧追和玉板詩  其二','王十朋','宋','宋诗','song-poetry','','[]','前世書魚化宰官，肺腸元與竹相安。',32,'全唐诗/poet.song.119000.json','["前世書魚化宰官，肺腸元與竹相安。", "侯生韓子相酬贈，詩句驚人魂膽寒。"]'),
('fc0d1c41-4087-454d-bdd7-4c8ccbb49c36','次韻何憲脩途倦游懷鄱陽唱和之樂','王十朋','宋','宋诗','song-poetry','','[]','馬上詩成驛使馳，社中猶恨使來遲。',64,'全唐诗/poet.song.119000.json','["馬上詩成驛使馳，社中猶恨使來遲。", "不堪冀北群空後，况是江東日莫時。", "春半鶑猶懶呼喚，雨多鳩亦厭分離。", "論文尊酒何時共，公說歸期我去期。"]'),
('f0d725cc-2bf0-4794-9258-cd4b5255c966','次韻何憲太平道中書事','王十朋','宋','宋诗','song-poetry','','[]','明刑清詔使，行部近清明。',48,'全唐诗/poet.song.119000.json','["明刑清詔使，行部近清明。", "况有太平象，想亡愁歎聲。", "問民知疾苦，按郡戒將迎。", "更向金陵看，六朝餘故城。"]'),
('50995ec5-4b1f-47c3-a3fc-cfbf27024ef2','次韵何憲題魯池州通隠堂','王十朋','宋','宋诗','song-poetry','','[]','朝市隠誠好，山林通更嘉。',48,'全唐诗/poet.song.119000.json','["朝市隠誠好，山林通更嘉。", "出非專爲米，去亦不期瓜。", "下惠何妨介，東方未用夸。", "池州知此道，無媿仲連家。"]'),
('7c84ba4d-d762-456a-98d0-63912a139d56','芝山勸農','王十朋','宋','宋诗','song-poetry','','[]','出門非爲采靈芝，端爲農時不可違。',30,'全唐诗/poet.song.119000.json','["出門非爲采靈芝，端爲農時不可違。", "我欲勸農農勸我，田園薄有早。"]'),
('ac8a1876-1f0e-47d9-a4ee-acd4665d6ed2','二月十五日祈晴十七日雷雨再作','王十朋','宋','宋诗','song-poetry','','[]','清香一瓣乞晴回，準擬陽光萬里開。',64,'全唐诗/poet.song.119000.json','["清香一瓣乞晴回，準擬陽光萬里開。", "風伯未吹雲陣破，雷公又喚雨聲來。", "補天石爛疇能鍊，陷濘車深不易推。", "誰坐黄堂稱太守，深慙無術捄天災。"]'),
('d6e57d0d-fc91-4555-8e98-c0e6693ae78a','喜晴再用前韵','王十朋','宋','宋诗','song-poetry','','[]','天閔斯民意已回，群陰不掃自應開。',64,'全唐诗/poet.song.119000.json','["天閔斯民意已回，群陰不掃自應開。", "扶桑曉日曈曈出，玉宇清風習習來。", "水綠漁翁聲欵乃，月明詩客手敲推。", "秧針刺水麥摇浪，定有豐年無後災。"]'),
('ca393663-bf4a-45f3-8027-5c299e0cf4dd','數日天氣朝陰莫晴復用前韵','王十朋','宋','宋诗','song-poetry','','[]','忍饑面目類顔回，僅得青天半日開。',64,'全唐诗/poet.song.119000.json','["忍饑面目類顔回，僅得青天半日開。", "且願催詩無雨至，只宜送月有風來。", "出游偶以文昌霽，待滿當爲桀溺推。", "曰雨曰暘皆帝力，麥苗無害免書災。"]'),
('a922bba8-79e8-4376-be3e-7ac77d0fb0a3','哭何子應  其一','王十朋','宋','宋诗','song-poetry','','[]','籍甚何夫子，文章擅美名。',48,'全唐诗/poet.song.119000.json','["籍甚何夫子，文章擅美名。", "金華傳語寶，鄱水主詩盟。", "心印橫渠學，相門無盡甥。", "人間一夢覺，卿月墮臺城。"]'),
('8edc7284-0c84-4492-90fb-452a0fab682c','哭何子應  其二','王十朋','宋','宋诗','song-poetry','','[]','骯髒宜三黜，飄零到九疑。',48,'全唐诗/poet.song.119000.json','["骯髒宜三黜，飄零到九疑。", "忠膺黄屋眷，音遇紫巖知。", "共理符頻綰，明刑節屢持。", "青天萬里蜀，無復話歸期。"]'),
('d74efc6c-e77a-4cef-a9e0-0866ebfcd49a','哭何子應  其三','王十朋','宋','宋诗','song-poetry','','[]','公作皇華使，予乘郡守轓。',48,'全唐诗/poet.song.119000.json','["公作皇華使，予乘郡守轓。", "江湖吳芮國，襟抱杜陵尊。", "翰墨頻揮染，詩文細討論。", "新編刊未就，楚些已招魂。"]'),
('7b40c99b-042e-4c07-b3a6-4f2aea8ddcdb','同官會飲鄱江樓送谷簾泉二尊戲成小詩','王十朋','宋','宋诗','song-poetry','','[]','聞說樓中會八仙，郡齋分送谷簾泉。',32,'全唐诗/poet.song.119000.json','["聞說樓中會八仙，郡齋分送谷簾泉。", "好將投向鄱江水，共作長鯨吸百川。"]'),
('e2fbb083-b780-41bb-b8b4-6d255475d33c','名郡之東門曰永平書一絕','王十朋','宋','宋诗','song-poetry','','[]','鄱水新門號永平，永平何止一鄱城。',32,'全唐诗/poet.song.119000.json','["鄱水新門號永平，永平何止一鄱城。", "願言廣此平天下，黎庶長無愁嘆聲。"]'),
('0a99910b-bd53-4b32-a2fd-246514473362','主簿程同年和永平門詩再賦四絕因以贈別  其一','王十朋','宋','宋诗','song-poetry','','[]','迂儒政事只平平，濫守鄱陽十里城。',32,'全唐诗/poet.song.119000.json','["迂儒政事只平平，濫守鄱陽十里城。", "頼有同年更同事，公餘時作苦吟聲。"]'),
('9b02b4e6-5803-489c-a5c8-229ee2dbac9f','主簿程同年和永平門詩再賦四絕因以贈別  其二','王十朋','宋','宋诗','song-poetry','','[]','高唱猶嫌二謝平，偏師能破五言城。',32,'全唐诗/poet.song.119000.json','["高唱猶嫌二謝平，偏師能破五言城。", "鄱人口誦新門記，已作雷門振大聲。"]'),
('b4561b15-54f6-4087-9146-7b89a9795b20','主簿程同年和永平門詩再賦四絕因以贈別  其三','王十朋','宋','宋诗','song-poetry','','[]','才知端如杜下平，異時何止任專城。',32,'全唐诗/poet.song.119000.json','["才知端如杜下平，異時何止任專城。", "三年俛首栖榛棘，行作沖霄鸞鳳聲。"]'),
('6490d2d6-97b4-40f6-83ba-441bed06a929','主簿程同年和永平門詩再賦四絕因以贈別  其四','王十朋','宋','宋诗','song-poetry','','[]','春盡湖如鏡面平，扁舟送別古鄱城。',32,'全唐诗/poet.song.119000.json','["春盡湖如鏡面平，扁舟送別古鄱城。", "相將我亦爲行客，征雁來時好寄聲。"]');
